#[derive(Clone, Debug, Deserialize, Serialize)]
struct EventView {
    seq: u64,
    #[serde(rename = "type")]
    type_name: String,
    success: bool,
    reason: u16,
    actor_id: Option<u64>,
    actor_name: Option<String>,
    target_actor_id: Option<u64>,
    target_actor_name: Option<String>,
    location_id: Option<u64>,
    location_name: Option<String>,
    destination_location_id: Option<u64>,
    destination_location_name: Option<String>,
    content_id: Option<u64>,
    content: Option<String>,
    item_id: Option<u64>,
    item_name: Option<String>,
    target_item_id: Option<u64>,
    target_item_name: Option<String>,
    raw_roll: Option<i16>,
    modifier: Option<i16>,
    total: Option<i16>,
    dc: Option<i16>,
    damage: Option<i16>,
    current_hp: Option<i16>,
    clock_id: Option<String>,
    clock_scope: Option<String>,
    clock_scope_id: Option<u64>,
    clock_kind: Option<String>,
    clock_label: Option<String>,
    clock_filled: Option<u8>,
    clock_segments: Option<u8>,
    clock_delta: Option<i16>,
    tag_id: Option<String>,
    tag_scope: Option<String>,
    tag_scope_id: Option<u64>,
    tag_kind: Option<String>,
    tag_label: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    caused_by_event_seq: Option<u64>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    source_world_tick: Option<u64>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    observed_through_seq: Option<u64>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    source_location_id: Option<u64>,
}

impl Default for EventView {
    fn default() -> Self {
        Self {
            seq: 0,
            type_name: String::new(),
            success: false,
            reason: 0,
            actor_id: None,
            actor_name: None,
            target_actor_id: None,
            target_actor_name: None,
            location_id: None,
            location_name: None,
            destination_location_id: None,
            destination_location_name: None,
            content_id: None,
            content: None,
            item_id: None,
            item_name: None,
            target_item_id: None,
            target_item_name: None,
            raw_roll: None,
            modifier: None,
            total: None,
            dc: None,
            damage: None,
            current_hp: None,
            clock_id: None,
            clock_scope: None,
            clock_scope_id: None,
            clock_kind: None,
            clock_label: None,
            clock_filled: None,
            clock_segments: None,
            clock_delta: None,
            tag_id: None,
            tag_scope: None,
            tag_scope_id: None,
            tag_kind: None,
            tag_label: None,
            caused_by_event_seq: None,
            source_world_tick: None,
            observed_through_seq: None,
            source_location_id: None,
        }
    }
}

impl EventView {
    fn apply_async_causality(&mut self, record: &JournalRecord) {
        self.caused_by_event_seq = record.caused_by_event_seq;
        self.source_world_tick = record.source_world_tick;
        self.observed_through_seq = record.observed_through_seq;
        self.source_location_id = record.source_location_id;
    }
}

