fn avatar_pack_card_rarity(card_id: &str) -> &str {
    ruby_high_card_spec(card_id)
        .map(|card| card.rarity.as_str())
        .or_else(|| seed_card_rarity_for_card_id(card_id))
        .unwrap_or("common")
}

fn seed_card_rarity_for_card_id(card_id: &str) -> Option<&'static str> {
    seed_content()
        .cards
        .iter()
        .find(|card| card.card_id == card_id)
        .map(|card| card.rarity.as_str())
}

fn avatar_pack_card_weight(card_id: &str) -> u64 {
    match avatar_pack_card_rarity(card_id)
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "ultra-rare" | "ultra_rare" | "ultrarare" | "mythic" | "legendary" => 4,
        "super-rare" | "super_rare" | "superrare" => 10,
        "rare" => 25,
        "uncommon" => 40,
        _ => 60,
    }
}

fn deterministic_pack_cards(reveal_seed: &str, already_owned: &BTreeSet<String>) -> Vec<String> {
    let catalog = avatar_pack_catalog();
    let count = 3.min(catalog.len());
    let mut cards = Vec::with_capacity(count);
    let mut nonce = 0_u64;
    while cards.len() < count {
        let mut candidates = catalog
            .iter()
            .copied()
            .filter(|card_id| !cards.iter().any(|chosen| chosen == card_id))
            .filter(|card_id| !already_owned.contains(*card_id))
            .collect::<Vec<_>>();
        if candidates.is_empty() {
            candidates = catalog
                .iter()
                .copied()
                .filter(|card_id| !cards.iter().any(|chosen| chosen == card_id))
                .collect();
        }
        if candidates.is_empty() {
            break;
        }
        let total_weight = candidates
            .iter()
            .map(|card_id| avatar_pack_card_weight(card_id))
            .sum::<u64>()
            .max(1);
        let nonce_text = nonce.to_string();
        let mut roll =
            stable_hash_u64(&["weighted-avatar-pack", reveal_seed, &nonce_text]) % total_weight;
        let mut selected = candidates[0];
        for card_id in candidates {
            let weight = avatar_pack_card_weight(card_id);
            if roll < weight {
                selected = card_id;
                break;
            }
            roll = roll.saturating_sub(weight);
        }
        cards.push(selected.to_string());
        nonce = nonce.saturating_add(1);
    }
    cards
}

fn random_hex(byte_count: usize) -> String {
    let mut bytes = vec![0_u8; byte_count];
    OsRng.fill_bytes(&mut bytes);
    let mut out = String::with_capacity(byte_count * 2);
    for byte in bytes {
        out.push_str(&format!("{byte:02x}"));
    }
    out
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "cosyworld_orchestrator=info,tower_http=info".into()),
        )
        .init();

    let state = AppState::bootstrap().await?;
    start_actor_job_worker(state.clone());
    start_ownership_refresh_scheduler(state.clone());
    start_moderation_retention_scheduler(state.clone());
    let app = routes::app_router(state);

    let addr: SocketAddr = std::env::var("COSYWORLD_V2_ADDR")
        .unwrap_or_else(|_| "127.0.0.1:3102".to_string())
        .parse()?;
    let listener = TcpListener::bind(addr).await?;
    info!("CosyWorld v2 orchestrator listening on http://{addr}");

    let server = axum::serve(
        listener,
        app.into_make_service_with_connect_info::<SocketAddr>(),
    );
    if env_flag("COSYWORLD_DISABLE_CTRL_C_SHUTDOWN") {
        server.await?;
    } else {
        server
            .with_graceful_shutdown(async {
                let _ = signal::ctrl_c().await;
            })
            .await?;
    }

    Ok(())
}

impl AppState {
    async fn bootstrap() -> io::Result<Self> {
        let (tx, _) = broadcast::channel(512);
        let deployment = DeploymentConfig::from_env()?;
        let snapshot_path = snapshot_path_from_env().map(Arc::new);
        let resident_continuity_path =
            resident_continuity_path_from_env(snapshot_path.as_deref()).map(Arc::new);
        let event_store_path = event_store_path_from_env().map(Arc::new);
        let mut runtime = match event_store_path.as_deref() {
            Some(path) => match init_event_store(path)
                .and_then(|_| action_journal_has_records(path))
                .and_then(|has_records| {
                    if has_records {
                        RuntimeWorld::from_action_journal(path)
                    } else {
                        Err(snapshot_error("action journal is empty"))
                    }
                }) {
                Ok(runtime) => {
                    info!(
                        "replayed CosyWorld v2 action journal from {}",
                        path.display()
                    );
                    runtime
                }
                Err(error) => {
                    warn!(
                        "action journal unavailable at {}; falling back to snapshot/seed: {}",
                        path.display(),
                        error
                    );
                    load_snapshot_or_seed(snapshot_path.as_deref())
                }
            },
            None => load_snapshot_or_seed(snapshot_path.as_deref()),
        };
        if let Some(path) = event_store_path.as_deref() {
            if let Err(error) = advance_runtime_next_event_seq_from_store(&mut runtime, path) {
                warn!(
                    "failed to advance CosyWorld event sequence from {}: {}",
                    path.display(),
                    error
                );
            }
        }

        let ownership_feed = OwnershipFeedConfig::from_env();
        let trust_client_card_ids = std::env::var("COSYWORLD_DEV_TRUST_CLIENT_CARD_IDS")
            .map(|value| matches!(value.as_str(), "1" | "true" | "yes" | "on"))
            .unwrap_or(false);
        let dev_reset_enabled = std::env::var("COSYWORLD_ENABLE_DEV_RESET")
            .map(|value| matches!(value.as_str(), "1" | "true" | "yes" | "on"))
            .unwrap_or(false);
        let allow_unsigned_wallet_claims = std::env::var("COSYWORLD_DEV_ALLOW_UNSIGNED_WALLET")
            .map(|value| matches!(value.as_str(), "1" | "true" | "yes" | "on"))
            .unwrap_or(false);
        let avatar_chat_delay = env_duration_millis("COSYWORLD_DEV_AVATAR_CHAT_DELAY_MS");
        let moderation_token = std::env::var("COSYWORLD_MODERATION_TOKEN")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .map(Arc::new);
        let moderation_report_retention = ModerationReportRetention::from_env()?;
        let ai_config = Arc::new(AiConfig::from_env());
        let generation_controls =
            Arc::new(GenerationControls::from_env().map_err(deployment_config_error)?);
        let avatar_art_config = Arc::new(ReplicateAvatarArtConfig::from_env());
        let generated_asset_dir = generated_asset_dir_from_env();
        fs::create_dir_all(generated_avatar_dir(&generated_asset_dir))?;
        #[cfg(test)]
        let ambient = AmbientConfig::from_env();
        let box_burn_verifier = BoxBurnVerifierConfig::from_env()?;
        deployment.validate_runtime_options(
            &ownership_feed,
            trust_client_card_ids,
            dev_reset_enabled,
            allow_unsigned_wallet_claims,
            avatar_chat_delay,
            event_store_path.is_some(),
            moderation_token.is_some(),
            box_burn_verifier.is_some(),
        )?;
        let (mut ownership_index, ownership_feed_health) =
            ownership_feed.load_best_effort_with_health().await;
        if let Some(path) = event_store_path.as_deref() {
            let external_snapshot_loaded = ownership_feed.remote_url.is_none()
                || (ownership_feed_health.last_success_at_unix.is_some()
                    && ownership_feed_health.consecutive_failures == 0);
            if external_snapshot_loaded
                && (ownership_feed.inline_feed.is_some()
                    || ownership_feed.path_feed.is_some()
                    || ownership_feed.remote_url.is_some())
            {
                match record_economy_reconciliation(path, &ownership_index, "startup") {
                    Ok(run) if run.anomaly_count > 0 => warn!(
                        "economy reconciliation found {} anomal{} at startup",
                        run.anomaly_count,
                        if run.anomaly_count == 1 { "y" } else { "ies" }
                    ),
                    Ok(_) => {}
                    Err(error) if deployment.profile.is_production() => {
                        return Err(io::Error::other(format!(
                            "production profile failed to record economy reconciliation in {}: {}",
                            path.display(),
                            error
                        )));
                    }
                    Err(error) => warn!(
                        "failed to record economy reconciliation in {}: {}",
                        path.display(),
                        error
                    ),
                }
            }
            match load_receipt_ownership_index(path) {
                Ok(receipt_index) => ownership_index.merge(receipt_index),
                Err(error) if deployment.profile.is_production() => {
                    return Err(io::Error::other(format!(
                        "production profile failed to load CosyWorld v2 NFT receipts from {}: {}",
                        path.display(),
                        error
                    )));
                }
                Err(error) => warn!(
                    "failed to load CosyWorld v2 NFT receipt ownership from {}: {}",
                    path.display(),
                    error
                ),
            }
        }
        let placement_rotation = placement_rotation_index_for_runtime(&runtime);
        runtime.apply_wallet_overlap_placements(&ownership_index, placement_rotation);
        if let Some(path) = resident_continuity_path.as_deref() {
            match runtime.load_resident_continuity_snapshot(path) {
                Ok(count) => info!(
                    "loaded {} resident continuit{} from {}",
                    count,
                    if count == 1 { "y" } else { "ies" },
                    path.display()
                ),
                Err(error) if error.kind() == io::ErrorKind::NotFound => info!(
                    "resident continuity artifact will be created at {}",
                    path.display()
                ),
                Err(error) => warn!(
                    "failed to load resident continuity artifact {}: {}",
                    path.display(),
                    error
                ),
            }
        }
        let ownership_index = Arc::new(RwLock::new(ownership_index));

        if let Some(path) = event_store_path.as_deref() {
            match init_event_store(path)
                .and_then(|_| event_store_is_empty(path))
                .and_then(|is_empty| {
                    if is_empty {
                        append_event_store(path, &runtime.event_log)
                    } else {
                        Ok(())
                    }
                }) {
                Ok(()) => info!("CosyWorld v2 event store ready at {}", path.display()),
                Err(error) if deployment.profile.is_production() => {
                    return Err(io::Error::other(format!(
                        "production profile failed to initialize CosyWorld event store at {}: {}",
                        path.display(),
                        error
                    )));
                }
                Err(error) => warn!(
                    "CosyWorld v2 event store disabled for this run; failed to initialize {}: {}",
                    path.display(),
                    error
                ),
            }
            if let Err(error) =
                purge_expired_moderation_reports_for_retention(path, moderation_report_retention)
            {
                warn!(
                    "failed to purge expired CosyWorld moderation reports from {}: {}",
                    path.display(),
                    error
                );
            }
        }

        let actor_sessions = event_store_path
            .as_deref()
            .map(|path| match load_actor_sessions(path) {
                Ok(sessions) => sessions,
                Err(error) => {
                    warn!(
                        "failed to load CosyWorld actor sessions from {}: {}",
                        path.display(),
                        error
                    );
                    ActorSessions::default()
                }
            })
            .unwrap_or_default();
        let wallet_actor_links = event_store_path
            .as_deref()
            .map(|path| match load_wallet_actor_links(path) {
                Ok(links) => links,
                Err(error) => {
                    warn!(
                        "failed to load CosyWorld wallet avatar links from {}: {}",
                        path.display(),
                        error
                    );
                    BTreeMap::new()
                }
            })
            .unwrap_or_default();
        let actor_suspensions = event_store_path
            .as_deref()
            .map(|path| match load_actor_suspensions(path) {
                Ok(suspensions) => suspensions,
                Err(error) => {
                    warn!(
                        "failed to load CosyWorld actor suspensions from {}: {}",
                        path.display(),
                        error
                    );
                    BTreeMap::new()
                }
            })
            .unwrap_or_default();
        let account_auth = Arc::new(AccountAuth::from_env(
            event_store_path.clone(),
            deployment.profile.is_production(),
        )?);

        Ok(Self {
            inner: Arc::new(Mutex::new(runtime)),
            tx,
            deployment,
            snapshot_path,
            resident_continuity_path,
            event_store_path,
            account_auth,
            ownership_index,
            trust_client_card_ids,
            dev_reset_enabled,
            ai_config,
            generation_controls,
            avatar_art_config,
            generated_asset_dir: Arc::new(generated_asset_dir),
            #[cfg(test)]
            ambient,
            box_burn_verifier: Arc::new(box_burn_verifier),
            ownership_feed: Arc::new(ownership_feed),
            ownership_feed_health: Arc::new(StdMutex::new(ownership_feed_health)),
            last_world_event_at: Arc::new(StdMutex::new(Instant::now())),
            wallet_sessions: Arc::new(StdMutex::new(WalletSessions::default())),
            qr_wallet_logins: Arc::new(StdMutex::new(QrWalletLogins::default())),
            wallet_actor_links: Arc::new(StdMutex::new(wallet_actor_links)),
            actor_sessions: Arc::new(StdMutex::new(actor_sessions)),
            actor_suspensions: Arc::new(StdMutex::new(actor_suspensions)),
            rate_limiter: Arc::new(StdMutex::new(RateLimiter::default())),
            actor_chat_locks: Arc::new(StdMutex::new(BTreeSet::new())),
            room_turns: Arc::new(StdMutex::new(RoomTurns::default())),
            room_memory_cache: Arc::new(StdMutex::new(BTreeMap::new())),
            room_memory_jobs: Arc::new(StdMutex::new(BTreeSet::new())),
            avatar_art_jobs: Arc::new(StdMutex::new(BTreeSet::new())),
            actor_job_notify: Arc::new(Notify::new()),
            avatar_chat_delay,
            moderation_token,
            moderation_report_retention,
            allow_unsigned_wallet_claims,
        })
    }

    async fn ownership_snapshot(&self) -> OwnershipIndex {
        self.ownership_index.read().await.clone()
    }

    fn mark_activity(&self) {
        if let Ok(mut last) = self.last_world_event_at.lock() {
            *last = Instant::now();
        }
    }

    #[cfg(test)]
    fn quiet_for(&self) -> Duration {
        self.last_world_event_at
            .lock()
            .map(|last| last.elapsed())
            .unwrap_or(Duration::ZERO)
    }

    fn allow_rate_limit(&self, key: impl Into<String>, limit: RateLimit) -> bool {
        self.rate_limiter
            .lock()
            .map(|mut limiter| limiter.allow(key.into(), limit, Instant::now()))
            .unwrap_or(false)
    }
}

impl ReplicateAvatarArtConfig {
    fn from_env() -> Option<Self> {
        let api_token = std::env::var("COSYWORLD_REPLICATE_API_TOKEN")
            .ok()
            .or_else(|| std::env::var("REPLICATE_API_TOKEN").ok())
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())?;
        let model = std::env::var("COSYWORLD_REPLICATE_AVATAR_MODEL")
            .ok()
            .or_else(|| std::env::var("REPLICATE_AVATAR_MODEL").ok())
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())?;
        let version = std::env::var("COSYWORLD_REPLICATE_AVATAR_VERSION")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty());
        let lora_url = std::env::var("COSYWORLD_REPLICATE_AVATAR_LORA")
            .ok()
            .or_else(|| std::env::var("COSYWORLD_MIRQUO_LORA_URL").ok())
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty());
        let lora_input_key = std::env::var("COSYWORLD_REPLICATE_AVATAR_LORA_INPUT")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "extra_lora".to_string());
        let lora_scale_input_key = std::env::var("COSYWORLD_REPLICATE_AVATAR_LORA_SCALE_INPUT")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "extra_lora_scale".to_string());
        let lora_scale = std::env::var("COSYWORLD_REPLICATE_AVATAR_LORA_SCALE")
            .ok()
            .and_then(|value| value.trim().parse::<f64>().ok())
            .unwrap_or(0.85)
            .clamp(0.0, 2.0);
        let prompt_prefix = std::env::var("COSYWORLD_REPLICATE_AVATAR_PROMPT_PREFIX")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "mirquo style, cozy storybook trading-card portrait".to_string());
        let output_format = std::env::var("COSYWORLD_REPLICATE_AVATAR_OUTPUT_FORMAT")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "png".to_string());
        Some(Self {
            api_token,
            model,
            version,
            lora_url,
            lora_input_key,
            lora_scale_input_key,
            lora_scale,
            prompt_prefix,
            output_format,
        })
    }
}

impl BoxBurnVerifierConfig {
    fn from_env() -> io::Result<Option<Self>> {
        let rpc_url = std::env::var("COSYWORLD_BOX_BURN_SOLANA_RPC_URL")
            .ok()
            .or_else(|| std::env::var("COSYWORLD_SOLANA_RPC_URL").ok())
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty());
        let collection_address = std::env::var("COSYWORLD_BOX_CORE_COLLECTION_ADDRESS")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty());

        match (rpc_url, collection_address) {
            (None, None) => Ok(None),
            (Some(rpc_url), Some(collection_address)) => {
                if !rpc_url.starts_with("http://") && !rpc_url.starts_with("https://") {
                    return Err(deployment_config_error(
                        "COSYWORLD_BOX_BURN_SOLANA_RPC_URL must be an HTTP(S) URL",
                    ));
                }
                let collection_address = clean_solana_address(
                    &collection_address,
                    "COSYWORLD_BOX_CORE_COLLECTION_ADDRESS",
                )
                .map_err(deployment_config_error)?;
                Ok(Some(Self {
                    rpc_url,
                    collection_address,
                }))
            }
            (Some(_), None) => Err(deployment_config_error(
                "COSYWORLD_BOX_BURN_SOLANA_RPC_URL requires COSYWORLD_BOX_CORE_COLLECTION_ADDRESS",
            )),
            (None, Some(_)) => Err(deployment_config_error(
                "COSYWORLD_BOX_CORE_COLLECTION_ADDRESS requires COSYWORLD_BOX_BURN_SOLANA_RPC_URL",
            )),
        }
    }

    async fn prepare_box_burn(
        &self,
        owner_wallet_address: &str,
        box_asset_address: &str,
    ) -> Result<PreparedBoxBurnTransaction, String> {
        let owner_wallet_address =
            clean_solana_address(owner_wallet_address, "Owner wallet address")?;
        let box_asset_address = clean_solana_address(box_asset_address, "Box asset address")?;
        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(10))
            .build()
            .map_err(|error| error.to_string())?;
        let body = serde_json::json!({
            "jsonrpc": "2.0",
            "id": "cosyworld-box-burn-prepare",
            "method": "getLatestBlockhash",
            "params": [{ "commitment": "confirmed" }]
        });
        let response = client
            .post(&self.rpc_url)
            .json(&body)
            .send()
            .await
            .map_err(|error| error.to_string())?;
        if !response.status().is_success() {
            return Err(format!(
                "Solana RPC failed with status {}",
                response.status().as_u16()
            ));
        }
        let payload: serde_json::Value =
            response.json().await.map_err(|error| error.to_string())?;
        if let Some(error) = payload.get("error") {
            return Err(error
                .get("message")
                .and_then(|value| value.as_str())
                .unwrap_or("Solana RPC returned an error")
                .to_string());
        }
        let blockhash = payload
            .pointer("/result/value/blockhash")
            .and_then(|value| value.as_str())
            .ok_or_else(|| "Solana RPC did not return a recent blockhash".to_string())?;
        let last_valid_block_height = payload
            .pointer("/result/value/lastValidBlockHeight")
            .and_then(|value| value.as_u64())
            .ok_or_else(|| "Solana RPC did not return a last valid block height".to_string())?;
        compile_core_burn_transaction(
            &owner_wallet_address,
            &box_asset_address,
            &self.collection_address,
            blockhash,
            last_valid_block_height,
        )
    }

    async fn verify_box_burn(
        &self,
        owner_wallet_address: &str,
        box_asset_address: &str,
        burn_signature: &str,
    ) -> Result<BoxBurnVerification, String> {
        let owner_wallet_address =
            clean_solana_address(owner_wallet_address, "Owner wallet address")?;
        let box_asset_address = clean_solana_address(box_asset_address, "Box asset address")?;
        let burn_signature = clean_solana_signature(burn_signature, "Solana burn signature")?;

        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(10))
            .build()
            .map_err(|error| error.to_string())?;
        let mut transaction = serde_json::Value::Null;
        for attempt in 0..4 {
            if attempt > 0 {
                tokio::time::sleep(Duration::from_millis(1000 + attempt * 500)).await;
            }
            let body = serde_json::json!({
                "jsonrpc": "2.0",
                "id": "cosyworld-box-burn",
                "method": "getTransaction",
                "params": [
                    burn_signature,
                    {
                        "encoding": "jsonParsed",
                        "maxSupportedTransactionVersion": 0,
                        "commitment": "confirmed"
                    }
                ]
            });
            let response = client
                .post(&self.rpc_url)
                .json(&body)
                .send()
                .await
                .map_err(|error| error.to_string())?;
            if !response.status().is_success() {
                return Err(format!(
                    "Solana RPC failed with status {}",
                    response.status().as_u16()
                ));
            }
            let payload: serde_json::Value =
                response.json().await.map_err(|error| error.to_string())?;
            if let Some(error) = payload.get("error") {
                return Err(error
                    .get("message")
                    .and_then(|value| value.as_str())
                    .unwrap_or("Solana RPC returned an error")
                    .to_string());
            }
            transaction = payload
                .get("result")
                .cloned()
                .unwrap_or(serde_json::Value::Null);
            if !transaction.is_null() {
                break;
            }
        }

        if transaction.is_null() {
            return Err("Solana burn transaction was not found yet".to_string());
        }
        if !transaction
            .pointer("/meta/err")
            .is_none_or(|value| value.is_null())
        {
            return Err("Solana burn transaction failed on-chain".to_string());
        }
        let signatures = transaction
            .pointer("/transaction/signatures")
            .and_then(|value| value.as_array())
            .map(|values| {
                values
                    .iter()
                    .filter_map(|value| value.as_str())
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        if !signatures.contains(&burn_signature.as_str()) {
            return Err("Solana RPC returned a different burn transaction".to_string());
        }
        if !transaction_burns_core_asset_from_owner(
            &transaction,
            &box_asset_address,
            &owner_wallet_address,
            &self.collection_address,
        ) {
            return Err("Solana transaction does not burn this CosyWorld Box".to_string());
        }

        Ok(BoxBurnVerification {
            verification_status: "solana_core_burn_verified",
        })
    }
}

