    fn project_preparation_spent_for_actor(&self, actor_id: u64) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        let Some(clock_id) = self.active_progress_clock_id_for_location(actor.location_id) else {
            return false;
        };
        self.project_preparation_spent_for_clock(actor_id, actor.location_id, &clock_id)
    }

    fn room_features(&self, location_id: u64) -> Vec<&'static SeedRoomFeatureContent> {
        seed_content()
            .room_features
            .iter()
            .filter(|feature| feature.location_id == location_id)
            .collect()
    }

    #[allow(dead_code)]
    fn room_feature_views(&self, location_id: u64, actor_id: Option<u64>) -> Vec<RoomFeatureView> {
        self.room_features(location_id)
            .into_iter()
            .map(|feature| {
                let hidden_exit_pending = self
                    .hidden_exit_candidate_for_search(location_id, &feature.key)
                    .is_some();
                let search_reveal_pending = !self
                    .search_reveal_candidates_for_feature(location_id, &feature.key)
                    .is_empty();
                let explicitly_searched = self
                    .room_feature_search_claimed(location_id, &feature.key)
                    || actor_id
                        .map(|id| self.feature_search_claimed(id, location_id, &feature.key))
                        .unwrap_or(false);
                let searched = explicitly_searched
                    || (!hidden_exit_pending
                        && !search_reveal_pending
                        && !self.room_floor_empty(location_id));
                let uses = feature
                    .uses
                    .iter()
                    .map(|use_case| RoomFeatureUseView {
                        item_id: use_case.item_id,
                        feature_key: feature.key.clone(),
                        text: use_case.text.clone(),
                        used: actor_id
                            .map(|id| {
                                self.feature_use_claimed(
                                    id,
                                    location_id,
                                    &feature.key,
                                    use_case.item_id,
                                )
                            })
                            .unwrap_or(false),
                        effect: self.room_feature_use_effect(
                            actor_id,
                            location_id,
                            &feature.key,
                            use_case.item_id,
                        ),
                    })
                    .collect();
                RoomFeatureView {
                    key: feature.key.clone(),
                    name: feature.name.clone(),
                    aliases: feature.aliases.clone(),
                    look: feature.look.clone(),
                    search: feature.search.clone(),
                    searched,
                    uses,
                }
            })
            .collect()
    }

    #[allow(dead_code)]
    fn room_feature_use_effect(
        &self,
        actor_id: Option<u64>,
        location_id: u64,
        feature_key: &str,
        item_id: u64,
    ) -> Option<String> {
        let mut parts = Vec::new();
        if let Some(progress) =
            self.room_feature_project_progress_effect(actor_id, location_id, item_id)
        {
            parts.push(progress);
        }
        if let Some(target) = FEATURE_BOND_TARGETS.iter().find(|target| {
            target.location_id == location_id
                && target.feature_key == feature_key
                && target.item_id == item_id
        }) {
            let target_name = self
                .actor_name(target.target_actor_id)
                .unwrap_or_else(|| format!("Resident {}", target.target_actor_id));
            parts.push(format!("friendship with {target_name} grows"));
        }
        (!parts.is_empty()).then(|| parts.join(", "))
    }

    #[allow(dead_code)]
    fn room_feature_project_progress_effect(
        &self,
        actor_id: Option<u64>,
        location_id: u64,
        item_id: u64,
    ) -> Option<String> {
        let clock_id = self.active_progress_clock_id_for_location(location_id)?;
        let target_id = item_id.to_string();
        let amount: u8 = lifecycle_hooks_for("on_use", "item", &target_id)
            .into_iter()
            .filter(|hook| {
                actor_id
                    .and_then(|id| lifecycle_hook_claim_key(hook, id, "item", &target_id, 0))
                    .map(|claim_key| !self.rpg_claims.contains(&claim_key))
                    .unwrap_or(true)
            })
            .flat_map(|hook| hook.effects.iter())
            .filter_map(|effect| match effect {
                EffectDescriptor::AdvanceClock {
                    clock_id: effect_clock_id,
                    amount,
                    ..
                } if effect_clock_id == &clock_id => Some(*amount),
                _ => None,
            })
            .sum();
        (amount > 0).then(|| format!("+{amount} progress"))
    }

    fn feature_use_claimed(
        &self,
        actor_id: u64,
        location_id: u64,
        feature_key: &str,
        item_id: u64,
    ) -> bool {
        self.tags
            .get(&feature_use_tag_id(
                actor_id,
                location_id,
                feature_key,
                item_id,
            ))
            .map(|tag| tag.active)
            .unwrap_or(false)
    }

    fn default_player_feature_use_candidate(
        &self,
        actor_id: u64,
    ) -> Option<PlayerFeatureUseCandidate> {
        let actor = self.actor_by_id(actor_id)?;
        if actor.kind != CW_ACTOR_HUMAN || actor.status != CW_ACTOR_ACTIVE {
            return None;
        }
        let held_item_ids: BTreeSet<u64> = self
            .actor_held_items(actor_id)
            .into_iter()
            .map(|item| item.id)
            .collect();
        let mut candidates = Vec::new();
        for feature in self.room_feature_views(actor.location_id, Some(actor_id)) {
            for use_case in feature
                .uses
                .into_iter()
                .filter(|use_case| !use_case.used)
                .filter(|use_case| held_item_ids.contains(&use_case.item_id))
            {
                let Some(effect) = use_case.effect.filter(|effect| !effect.trim().is_empty())
                else {
                    continue;
                };
                let item_name = self
                    .item_name(use_case.item_id)
                    .unwrap_or_else(|| format!("Item {}", use_case.item_id));
                candidates.push(PlayerFeatureUseCandidate {
                    location_id: actor.location_id,
                    feature_name: feature.name.clone(),
                    item_id: use_case.item_id,
                    item_name,
                    effect,
                });
            }
        }
        candidates.sort_by(|left, right| {
            left.feature_name
                .cmp(&right.feature_name)
                .then_with(|| left.item_name.cmp(&right.item_name))
                .then_with(|| left.item_id.cmp(&right.item_id))
        });
        candidates.into_iter().next()
    }

