    fn searched_room_feature_count(&self, actor_id: u64, location_id: u64) -> usize {
        let feature_searches = self
            .room_features(location_id)
            .into_iter()
            .filter(|feature| self.feature_search_claimed(actor_id, location_id, &feature.key))
            .count();
        if self.location_search_claimed(actor_id, location_id) {
            feature_searches.max(1)
        } else {
            feature_searches
        }
    }

    fn project_location_evidence_count(&self, actor_id: u64, job: &JobState) -> usize {
        job.location_ids
            .iter()
            .filter(|location_id| {
                self.searched_room_feature_count(actor_id, **location_id) > 0
                    || self.listen_attempt_claimed_at(actor_id, **location_id)
            })
            .count()
    }

    fn prepared_project_progress_amount(&self, actor_id: u64, location_id: u64) -> u8 {
        let Some(job) = self.active_job_for_location(location_id) else {
            return 2;
        };
        if job.location_ids.len() > 1 {
            let needed = job.location_ids.len();
            let found = self.project_location_evidence_count(actor_id, job);
            if found >= needed {
                3
            } else {
                2
            }
        } else if self.searched_room_feature_count(actor_id, location_id) > 0 {
            3
        } else {
            2
        }
    }

    #[cfg(test)]
    fn project_progress_amount(&self, actor_id: u64, location_id: u64) -> u8 {
        if !self.prepared_tag_active(actor_id, location_id) {
            return 1;
        }
        self.prepared_project_progress_amount(actor_id, location_id)
    }

    fn work_project_progress_amount(&self, actor_id: u64, location_id: u64) -> u8 {
        if !self.prepared_tag_active(actor_id, location_id) {
            return 2;
        }
        self.prepared_project_progress_amount(actor_id, location_id)
    }

    fn work_finishes_active_progress(&self, actor_id: u64) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        let Some(clock_id) = self.active_progress_clock_id_for_location(actor.location_id) else {
            return false;
        };
        let Some(clock) = self.clocks.get(&clock_id) else {
            return false;
        };
        let remaining = clock.segments.saturating_sub(clock.filled);
        remaining > 0 && self.work_project_progress_amount(actor_id, actor.location_id) >= remaining
    }

    fn project_headway_text(&self, clock_id: &str, amount: u8) -> String {
        if self
            .clocks
            .get(clock_id)
            .map(|clock| clock.segments.saturating_sub(clock.filled))
            .filter(|remaining| *remaining > 0 && amount >= *remaining)
            .is_some()
        {
            return "finishes the shared work".to_string();
        }
        match amount {
            0 | 1 => "makes a little headway".to_string(),
            2 => "makes good headway".to_string(),
            _ => "brings the shared work close to done".to_string(),
        }
    }

    fn help_project_progress_amount(&self, actor_id: u64, location_id: u64) -> u8 {
        if !self.prepared_tag_active(actor_id, location_id) {
            return 1;
        }
        self.prepared_project_progress_amount(actor_id, location_id)
            .saturating_sub(1)
            .max(1)
    }

    fn helped_room_tag_active(&self, location_id: u64) -> bool {
        self.tags
            .get(&helped_room_tag_id(location_id))
            .map(|tag| tag.active)
            .unwrap_or(false)
    }

    fn repeated_unprepared_help_tires(&self, actor_id: u64, location_id: u64) -> bool {
        self.helped_room_tag_active(location_id) && !self.prepared_tag_active(actor_id, location_id)
    }

    fn clock_views(&self, location_id: u64) -> Vec<ClockView> {
        let mut clock_ids = Vec::new();
        let mut push_clock_id = |clock_id: &str| {
            if !clock_ids.iter().any(|existing| existing == clock_id) {
                clock_ids.push(clock_id.to_string());
            }
        };
        for job in self
            .jobs
            .values()
            .filter(|job| job.location_ids.contains(&location_id))
            .filter(|job| self.job_status(job) == "active")
        {
            push_clock_id(&job.progress_clock_id);
            push_clock_id(&job.danger_clock_id);
        }
        for clock in self.clocks.values().filter(|clock| {
            clock.visible_to_players && clock.scope == "room" && clock.scope_id == location_id
        }) {
            push_clock_id(&clock.id);
        }
        clock_ids
            .into_iter()
            .filter_map(|clock_id| self.clocks.get(&clock_id))
            .filter(|clock| clock.visible_to_players)
            .map(|clock| ClockView {
                id: clock.id.clone(),
                scope: clock.scope.clone(),
                scope_id: clock.scope_id,
                kind: clock.kind.clone(),
                zone: clock_zone(clock).to_string(),
                label: clock.label.clone(),
                segments: clock.segments,
                filled: clock.filled,
                status: clock_status(clock),
            })
            .collect()
    }

    fn tag_views(&self, actor_id: Option<u64>, location_id: u64) -> Vec<TagView> {
        self.tags
            .values()
            .filter(|tag| tag.active)
            .filter(|tag| {
                (tag.scope == "room" && tag.scope_id == location_id)
                    || actor_id
                        .map(|id| tag.scope == "actor" && tag.scope_id == id)
                        .unwrap_or(false)
            })
            .map(|tag| TagView {
                id: tag.id.clone(),
                scope: tag.scope.clone(),
                scope_id: tag.scope_id,
                label: tag.label.clone(),
                kind: tag.kind.clone(),
                expires: tag.expires.clone(),
            })
            .collect()
    }

    fn job_views(&self, location_id: u64) -> Vec<JobView> {
        self.jobs
            .values()
            .filter(|job| job.location_ids.contains(&location_id))
            .map(|job| JobView {
                id: job.id.clone(),
                premise: job.premise.clone(),
                stakes: job.stakes.clone(),
                status: self.job_status(job),
                progress_clock_id: job.progress_clock_id.clone(),
                danger_clock_id: job.danger_clock_id.clone(),
                reward: job.reward.label().to_string(),
                consequence: job.consequence.clone(),
            })
            .collect()
    }

    fn front_views(&self, location_id: u64) -> Vec<FrontView> {
        seed_content()
            .fronts
            .iter()
            .filter(|front| front.location_ids.contains(&location_id))
            .map(|front| FrontView {
                id: front.id.clone(),
                premise: front.premise.clone(),
                zone: front.zone.clone(),
                status: front.status.clone(),
                location_ids: front.location_ids.clone(),
                participant_ids: front.participant_ids.clone(),
                participant_names: front
                    .participant_ids
                    .iter()
                    .map(|actor_id| {
                        self.actor_name(*actor_id)
                            .unwrap_or_else(|| format!("Actor {actor_id}"))
                    })
                    .collect(),
                stakes_questions: front.stakes_questions.clone(),
                portent_clock_id: front.portent_clock_id.clone(),
                job_ids: front.job_ids.clone(),
                impending_outcome: front.impending_outcome.clone(),
            })
            .collect()
    }

    fn room_sheet_view(&self, location_id: u64) -> Option<RoomSheetView> {
        self.room_sheets
            .get(&location_id)
            .map(|sheet| RoomSheetView {
                id: sheet.id.clone(),
                location_id: sheet.location_id,
                name: sheet.name.clone(),
                safety: sheet.safety.clone(),
                zone: room_sheet_zone(sheet).to_string(),
                aspects: sheet.aspects.clone(),
                boons: sheet.boons.clone(),
                hooks: sheet.hooks.clone(),
                resources: sheet.resources.clone(),
                projects: sheet.projects.clone(),
            })
            .or_else(|| {
                let pathway = self.generated_pathway_for_location(location_id)?;
                let familiar = pathway.familiar;
                let meta = self.location_meta_for(location_id);
                Some(RoomSheetView {
                    id: format!("generated-pathway-room:{location_id}"),
                    location_id,
                    name: self
                        .location_name(location_id)
                        .unwrap_or_else(|| "Newly Found Path".to_string()),
                    safety: if familiar { "safe" } else { "risky" }.to_string(),
                    zone: if familiar {
                        ZONE_SANCTUARY
                    } else {
                        ZONE_FRONTIER
                    }
                    .to_string(),
                    aspects: if meta.terrain.is_empty() {
                        vec!["unfinished ground".to_string()]
                    } else {
                        meta.terrain.clone()
                    },
                    boons: vec![if familiar {
                        "Travelers know how to find their footing here.".to_string()
                    } else {
                        "Every careful hand helps the route take shape.".to_string()
                    }],
                    hooks: vec![if familiar {
                        "The settled way remembers who helped make it familiar.".to_string()
                    } else {
                        "Work together until the wild way becomes familiar.".to_string()
                    }],
                    resources: BTreeMap::new(),
                    projects: vec![generated_pathway_job_id(&pathway.id)],
                })
            })
    }

    fn inspector_view(
        &self,
        location_id: u64,
        primary_action: &PrimaryAction,
        action_offers: &[RankedActionOffer],
    ) -> InspectorView {
        let room_sheet = self.room_sheets.get(&location_id);
        let zone = room_sheet
            .map(|sheet| room_sheet_zone(sheet).to_string())
            .unwrap_or_else(|| default_zone_for_scope("room", location_id).to_string());
        let features = Vec::new();
        let listen_offer = action_offers.iter().find(|offer| offer.kind == "check");
        let listen_reason = listen_offer
            .map(|offer| {
                let effect = offer
                    .effect
                    .clone()
                    .unwrap_or_else(|| "lets the room share one useful clue".to_string());
                format!("Listen is suggested from the check offer; {effect}")
            })
            .or_else(|| {
                self.active_progress_clock_id_for_location(location_id)
                    .map(|clock_id| {
                        format!(
                            "Listen can feed {clock_id}, but it is not currently the top offer."
                        )
                    })
            });
        let suggested_action = action_offers
            .iter()
            .find(|offer| offer.kind == primary_action.kind)
            .or_else(|| action_offers.first())
            .map(|offer| ActionInspectorView {
                offer_id: offer.id.clone(),
                kind: offer.kind.clone(),
                category: offer.category.clone(),
                label: offer.label.clone(),
                command: offer.command.clone(),
                rank: offer.rank,
                disabled: offer.disabled,
                disabled_reason: offer.disabled_reason.clone(),
                zone: offer.zone.clone(),
                source: offer.source.clone(),
                target: offer.target.clone(),
                claim_key: offer.claim_key.clone(),
                reason: offer.reason.clone(),
                effect: offer.effect.clone(),
                risk: offer.risk.clone(),
                cost_orbs: offer.cost.as_ref().map(|cost| cost.orbs),
            });

        InspectorView {
            location_id,
            room: RoomInspectorView {
                name: self
                    .location_name(location_id)
                    .unwrap_or_else(|| format!("Location {location_id}")),
                zone,
                safety: room_sheet.map(|sheet| sheet.safety.clone()),
                aspects: room_sheet
                    .map(|sheet| sheet.aspects.clone())
                    .unwrap_or_default(),
                boons: room_sheet
                    .map(|sheet| sheet.boons.clone())
                    .unwrap_or_default(),
                hooks: room_sheet
                    .map(|sheet| sheet.hooks.clone())
                    .unwrap_or_default(),
                resources: room_sheet
                    .map(|sheet| sheet.resources.clone())
                    .unwrap_or_default(),
                projects: room_sheet
                    .map(|sheet| sheet.projects.clone())
                    .unwrap_or_default(),
                features,
                listen_reason,
            },
            suggested_action,
            jobs: self.job_inspector_views(location_id),
            fronts: self.front_views(location_id),
            clocks: self.clock_inspector_views(location_id),
            lifecycle_hooks: self.lifecycle_hook_inspector_views(location_id),
        }
    }

    fn job_inspector_views(&self, location_id: u64) -> Vec<JobInspectorView> {
        self.jobs
            .values()
            .filter(|job| job.location_ids.contains(&location_id))
            .map(|job| {
                let progress = self.clocks.get(&job.progress_clock_id);
                let danger = self.clocks.get(&job.danger_clock_id);
                let mut needs = Vec::new();
                if let Some(clock) = progress {
                    let remaining = clock.segments.saturating_sub(clock.filled);
                    if remaining > 0 {
                        needs.push(format!("{remaining} progress segments"));
                    }
                }
                if needs.is_empty() {
                    needs.push("progress clock filled".to_string());
                }
                let mut blockers = Vec::new();
                if danger
                    .map(|clock| clock.filled >= clock.segments)
                    .unwrap_or(false)
                {
                    blockers.push("danger clock filled".to_string());
                }
                let participants = job
                    .participant_ids
                    .iter()
                    .map(|actor_id| {
                        self.actor_name(*actor_id)
                            .unwrap_or_else(|| format!("Actor {actor_id}"))
                    })
                    .collect();
                JobInspectorView {
                    id: job.id.clone(),
                    status: self.job_status(job),
                    premise: job.premise.clone(),
                    needs,
                    blockers,
                    participants,
                    progress_clock_id: job.progress_clock_id.clone(),
                    danger_clock_id: job.danger_clock_id.clone(),
                    reward: job.reward.label().to_string(),
                    consequence: job.consequence.clone(),
                }
            })
            .collect()
    }

    fn clock_inspector_views(&self, location_id: u64) -> Vec<ClockInspectorView> {
        self.clocks
            .values()
            .filter(|clock| clock.scope == "room" && clock.scope_id == location_id)
            .map(|clock| {
                let last_event = self.event_log.iter().rev().find(|event| {
                    event.type_name == "clock.updated"
                        && event.clock_id.as_deref() == Some(clock.id.as_str())
                });
                ClockInspectorView {
                    id: clock.id.clone(),
                    kind: clock.kind.clone(),
                    label: clock.label.clone(),
                    zone: clock_zone(clock).to_string(),
                    filled: clock.filled,
                    segments: clock.segments,
                    status: clock_status(clock),
                    visible_to_players: clock.visible_to_players,
                    updated_event_seq: clock.updated_event_seq,
                    last_delta: last_event.and_then(|event| event.clock_delta),
                    last_reason: last_event.and_then(|event| event.content.clone()),
                    on_fill: clock.on_fill.clone(),
                    on_fill_effect: summarize_effects(&clock.on_fill),
                }
            })
            .collect()
    }

    fn lifecycle_hook_inspector_views(&self, location_id: u64) -> Vec<LifecycleHookInspectorView> {
        let room_actor_ids: BTreeSet<String> = self.world.actors[..self.world.actor_count]
            .iter()
            .filter(|actor| actor.location_id == location_id)
            .map(|actor| actor.id.to_string())
            .collect();
        let room_item_ids: BTreeSet<String> = self.world.items[..self.world.item_count]
            .iter()
            .filter(|item| item.location_id == location_id)
            .map(|item| item.id.to_string())
            .collect();
        let room_clock_ids: BTreeSet<String> = self
            .clocks
            .values()
            .filter(|clock| clock.scope == "room" && clock.scope_id == location_id)
            .map(|clock| clock.id.clone())
            .collect();
        seed_content()
            .lifecycle_hooks
            .iter()
            .filter(|hook| match hook.target_kind.as_str() {
                "room" => hook.target_id == location_id.to_string(),
                "actor" => room_actor_ids.contains(&hook.target_id),
                "item" => room_item_ids.contains(&hook.target_id),
                "clock" => room_clock_ids.contains(&hook.target_id),
                _ => false,
            })
            .map(|hook| LifecycleHookInspectorView {
                hook: hook.hook.clone(),
                target_kind: hook.target_kind.clone(),
                target_id: hook.target_id.clone(),
                claim_scope: hook.claim_scope.clone(),
                effects: hook.effects.clone(),
                effect: summarize_effects(&hook.effects),
            })
            .collect()
    }

    fn calling_view(&self, actor_id: u64) -> Option<CallingView> {
        self.callings.get(&actor_id).map(|calling| CallingView {
            actor_id: calling.actor_id,
            statement: calling.statement.clone(),
        })
    }

    fn skill_views(&self, actor_id: u64) -> Vec<SkillView> {
        let mut skills: Vec<_> = self
            .skills
            .values()
            .filter(|skill| skill.actor_id == actor_id && skill.rank > 0)
            .map(|skill| SkillView {
                skill_id: skill.skill_id.clone(),
                label: skill.label.clone(),
                rank: skill.rank,
                tier: skill_rank_label(skill.rank).to_string(),
                bonus: skill_bonus_for_rank(skill.rank),
            })
            .collect();
        skills.sort_by(|a, b| a.label.cmp(&b.label));
        skills
    }

    fn visit_ledger_view(&self, actor_id: u64) -> VisitLedgerView {
        let mut marks: Vec<_> = self
            .ledger_marks
            .values()
            .filter(|mark| mark.actor_id == actor_id && !mark.banked)
            .map(|mark| VisitLedgerMarkView {
                id: mark.id.clone(),
                category: mark.category.clone(),
                label: mark.label.clone(),
                source_event_seq: mark.source_event_seq,
            })
            .collect();
        marks.sort_by_key(|mark| mark.source_event_seq);
        let banked_count = self
            .ledger_marks
            .values()
            .filter(|mark| mark.actor_id == actor_id && mark.banked)
            .count();
        let spent_count = self.advancement_spent_count(actor_id);
        let learned_truth_count = self
            .ledger_marks
            .values()
            .filter(|mark| mark.actor_id == actor_id && mark.category == "learned_truth")
            .count();
        VisitLedgerView {
            unbanked_count: marks.len(),
            banked_count,
            spent_count,
            advancement_points: banked_count.saturating_sub(spent_count),
            learned_truth_count,
            unbanked_marks: marks,
        }
    }

    fn advancement_spent_count(&self, actor_id: u64) -> usize {
        self.advancement_spends
            .values()
            .filter(|spend| spend.actor_id == actor_id)
            .map(|spend| usize::from(spend.cost))
            .sum()
    }

    fn advancement_points_available(&self, actor_id: u64) -> usize {
        let banked = self
            .ledger_marks
            .values()
            .filter(|mark| mark.actor_id == actor_id && mark.banked)
            .count();
        banked.saturating_sub(self.advancement_spent_count(actor_id))
    }

    fn unbanked_visit_ledger_count(&self, actor_id: u64) -> usize {
        self.ledger_marks
            .values()
            .filter(|mark| mark.actor_id == actor_id && !mark.banked)
            .count()
    }

    fn default_trainable_skill(&self, actor_id: u64) -> Option<&'static str> {
        if self.trained_since_rest_tag_active(actor_id)
            || self.advancement_points_available(actor_id) < usize::from(SKILL_STEP_COST)
        {
            return None;
        }

        let mut preferences = Vec::new();
        let mut banked_marks: Vec<_> = self
            .ledger_marks
            .values()
            .filter(|mark| mark.actor_id == actor_id && mark.banked)
            .collect();
        banked_marks.sort_by_key(|mark| mark.source_event_seq);
        for mark in banked_marks.iter().rev() {
            let Some(skill_id) = default_skill_for_ledger_category(&mark.category) else {
                continue;
            };
            if !preferences.contains(&skill_id) {
                preferences.push(skill_id);
            }
        }
        for skill_id in [
            "listening",
            "kindness",
            "lorecraft",
            "steadiness",
            "nimble_hands",
            "lifting",
        ] {
            if !preferences.contains(&skill_id) {
                preferences.push(skill_id);
            }
        }

        preferences.into_iter().find(|skill_id| {
            self.skills
                .get(&skill_state_id(actor_id, skill_id))
                .map(|skill| skill.rank)
                .unwrap_or(0)
                < MAX_SKILL_RANK
        })
    }

    fn default_bondable_resident(&self, actor_id: u64) -> Option<CwActor> {
        let actor = self.actor_by_id(actor_id)?;
        if self.advancement_points_available(actor_id) < usize::from(BOND_SLOT_COST) {
            return None;
        }
        self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .find(|target| {
                target.id != actor_id
                    && target.kind == CW_ACTOR_NPC
                    && target.status == CW_ACTOR_ACTIVE
                    && target.location_id == actor.location_id
                    && self.actor_visible_in_projection(*target, Some(actor_id), None)
                    && self.active_bond(actor_id, target.id).is_none()
            })
    }

    fn default_bond_command(&self, actor_id: u64) -> Option<String> {
        let target = self.default_bondable_resident(actor_id)?;
        let target_name = self.actor_name(target.id)?;
        let statement = default_bond_statement(&target_name);
        Some(format!("bond {target_name}: {statement}"))
    }

    fn default_resolvable_bond(&self, actor_id: u64) -> Option<BondState> {
        let actor = self.actor_by_id(actor_id)?;
        self.bonds
            .values()
            .filter(|bond| {
                bond.actor_id == actor_id
                    && bond.status != "resolved"
                    && bond.strength >= BOND_SETTLE_MIN_STRENGTH
                    && self
                        .actor_by_id(bond.target_actor_id)
                        .is_some_and(|target| {
                            target.kind == CW_ACTOR_NPC
                                && target.status == CW_ACTOR_ACTIVE
                                && target.location_id == actor.location_id
                        })
            })
            .max_by(|left, right| {
                left.strength
                    .cmp(&right.strength)
                    .then_with(|| left.updated_event_seq.cmp(&right.updated_event_seq))
                    .then_with(|| right.id.cmp(&left.id))
            })
            .cloned()
    }

    fn bond_views(&self, actor_id: u64) -> Vec<BondView> {
        let mut bonds: Vec<_> = self
            .bonds
            .values()
            .filter(|bond| bond.actor_id == actor_id && bond.status != "resolved")
            .map(|bond| BondView {
                id: bond.id.clone(),
                actor_id: bond.actor_id,
                target_actor_id: bond.target_actor_id,
                target_actor_name: self.actor_name(bond.target_actor_id),
                statement: bond.statement.clone(),
                strength: bond.strength,
                status: bond.status.clone(),
            })
            .collect();
        bonds.sort_by(|a, b| {
            a.target_actor_name
                .cmp(&b.target_actor_name)
                .then_with(|| a.id.cmp(&b.id))
        });
        bonds
    }

    fn chat_bond_claimed_target_ids(&self, actor_id: u64, location_id: u64) -> Vec<u64> {
        let mut target_ids: Vec<_> = self.world.actors[..self.world.actor_count]
            .iter()
            .filter(|target| {
                target.id != actor_id
                    && target.kind == CW_ACTOR_NPC
                    && target.status == CW_ACTOR_ACTIVE
                    && target.location_id == location_id
                    && self
                        .rpg_claims
                        .contains(&chat_bond_claim_key(actor_id, target.id))
            })
            .map(|target| target.id)
            .collect();
        target_ids.sort_unstable();
        target_ids
    }

    fn job_status(&self, job: &JobState) -> String {
        let explicit = job.status.trim();
        if matches!(explicit, "completed" | "failed") {
            return explicit.to_string();
        }
        let progress_filled = self
            .clocks
            .get(&job.progress_clock_id)
            .map(|clock| clock.filled >= clock.segments)
            .unwrap_or(false);
        if progress_filled {
            return "completed".to_string();
        }
        let danger_filled = self
            .clocks
            .get(&job.danger_clock_id)
            .map(|clock| clock.filled >= clock.segments)
            .unwrap_or(false);
        if danger_filled {
            return "failed".to_string();
        }
        if explicit.is_empty() {
            "active".to_string()
        } else {
            explicit.to_string()
        }
    }

    fn listen_attempt_claimed_at(&self, actor_id: u64, location_id: u64) -> bool {
        self.listen_attempt_claims
            .contains(&listen_attempt_claim_key(actor_id, location_id))
    }

    fn record_listen_attempt(&mut self, action: &CwAction, events: &[EventView]) {
        if !action_is_listen_check(action) {
            return;
        }
        let location_id = events
            .iter()
            .find(|event| {
                event.type_name == "ability_check.rolled" && event.actor_id == Some(action.actor_id)
            })
            .and_then(|event| event.location_id)
            .or_else(|| {
                self.actor_by_id(action.actor_id)
                    .map(|actor| actor.location_id)
            });
        if let Some(location_id) = location_id {
            self.listen_attempt_claims
                .insert(listen_attempt_claim_key(action.actor_id, location_id));
        }
    }

    fn backfill_listen_attempt_claims_from_events(&mut self) {
        for event in &self.event_log {
            if event.type_name != "ability_check.rolled" || event.dc != Some(LISTEN_DC as i16) {
                continue;
            }
            let (Some(actor_id), Some(location_id)) = (event.actor_id, event.location_id) else {
                continue;
            };
            self.listen_attempt_claims
                .insert(listen_attempt_claim_key(actor_id, location_id));
        }
    }

    #[cfg(test)]
    fn world_response(&self, actor_id: Option<u64>, access: &AccessContext) -> WorldResponse {
        self.world_response_with_presence(actor_id, access, None)
    }

    fn world_response_with_presence(
        &self,
        actor_id: Option<u64>,
        access: &AccessContext,
        active_human_actor_ids: Option<&BTreeSet<u64>>,
    ) -> WorldResponse {
        let client_actor_id = actor_id.filter(|id| self.client_actor_can_submit(*id));
        let current_location_id = client_actor_id
            .and_then(|id| self.actor_by_id(id))
            .map(|actor| actor.location_id);
        let visible_location_ids: BTreeSet<u64> = self.world.locations[..self.world.location_count]
            .iter()
            .filter_map(|location| {
                let is_current = current_location_id == Some(location.id);
                let default_start =
                    current_location_id.is_none() && location.id == COSY_COTTAGE_LOCATION_ID;
                let discovered = self.location_discovered_by_search(location.id);
                let generated = self.generated_location_is_revealed(location.id);
                (is_current || default_start || discovered || generated).then_some(location.id)
            })
            .collect();

        let mut location_cards = BTreeMap::new();
        for location in self.world.locations[..self.world.location_count]
            .iter()
            .filter(|location| visible_location_ids.contains(&location.id))
        {
            let name = self
                .location_name(location.id)
                .unwrap_or_else(|| format!("Location {}", location.id));
            let meta = self.location_meta_for(location.id);
            location_cards.insert(
                location.id,
                apply_location_access(
                    card_for_location(location.id, &name, Some(&meta)),
                    location.id,
                    access,
                ),
            );
        }
        let access_view = access_view(access, &location_cards);

        let locations = self.world.locations[..self.world.location_count]
            .iter()
            .filter(|location| visible_location_ids.contains(&location.id))
            .map(|location| {
                let name = self
                    .location_name(location.id)
                    .unwrap_or_else(|| format!("Location {}", location.id));
                let meta = self.location_meta_for(location.id);
                let access_rule = location_access_rule(location.id);
                let accessible = location_access_allowed(location.id, access);
                let actors_in_location: Vec<CwActor> = self.world.actors[..self.world.actor_count]
                    .iter()
                    .copied()
                    .filter(|actor| actor.location_id == location.id)
                    .collect();
                let visible_actors_in_location: Vec<CwActor> = actors_in_location
                    .iter()
                    .copied()
                    .filter(|actor| {
                        self.actor_visible_in_projection(
                            *actor,
                            client_actor_id,
                            active_human_actor_ids,
                        )
                    })
                    .collect();
                let items_in_location: Vec<CwItem> = self.world.items[..self.world.item_count]
                    .iter()
                    .copied()
                    .filter(|item| {
                        item.location_id == location.id
                            && !self.forgotten_search_item_at_location(*item, location.id)
                    })
                    .collect();
                let human_count = visible_actors_in_location
                    .iter()
                    .filter(|actor| actor.kind == CW_ACTOR_HUMAN)
                    .count();
                let resident_count = visible_actors_in_location
                    .iter()
                    .filter(|actor| actor.kind == CW_ACTOR_NPC)
                    .count();
                let actors = accessible
                    .then(|| {
                        visible_actors_in_location
                            .iter()
                            .copied()
                            .map(|actor| self.actor_view(actor))
                            .collect()
                    })
                    .unwrap_or_default();
                let items = accessible
                    .then(|| {
                        items_in_location
                            .iter()
                            .copied()
                            .map(|item| self.item_view(item))
                            .collect()
                    })
                    .unwrap_or_default();
                let exits = accessible
                    .then(|| self.exit_views(location.id, access))
                    .unwrap_or_default();
                let card = location_cards
                    .get(&location.id)
                    .cloned()
                    .unwrap_or_else(|| {
                        apply_location_access(
                            card_for_location(location.id, &name, Some(&meta)),
                            location.id,
                            access,
                        )
                    });

                WorldLocationView {
                    id: location.id,
                    pack_id: seed_pack_id_for_location(location.id),
                    name,
                    title: meta.title,
                    description: meta.description,
                    persona: meta.persona,
                    memory: meta.memory,
                    factions: faction_refs_for_location(location.id),
                    public: access_rule.required_grant_id.is_none()
                        && access_rule.required_card_id.is_none(),
                    accessible,
                    required_grant_id: access_rule.required_grant_id.map(ToString::to_string),
                    required_card_id: access_rule.required_card_id.map(ToString::to_string),
                    access_reason: if accessible {
                        None
                    } else {
                        access_rule.reason.map(ToString::to_string)
                    },
                    card,
                    actor_count: visible_actors_in_location.len(),
                    human_count,
                    resident_count,
                    item_count: items_in_location.len(),
                    actors,
                    items,
                    exits,
                }
            })
            .collect();

        WorldResponse {
            shared_world: true,
            current_actor_id: client_actor_id,
            current_location_id,
            access: access_view,
            factions: faction_views(),
            locations,
        }
    }

    fn visible_event_locations(
        &self,
        client_actor_id: Option<u64>,
        access: &AccessContext,
    ) -> BTreeSet<u64> {
        let mut locations = BTreeSet::from([1]);
        if let Some(actor) = client_actor_id.and_then(|id| self.actor_by_id(id)) {
            locations.insert(actor.location_id);
        }
        for location in &self.world.locations[..self.world.location_count] {
            if location_access_allowed(location.id, access) {
                locations.insert(location.id);
            }
        }
        locations
    }

    fn visible_events<'a>(
        &self,
        events: impl IntoIterator<Item = &'a EventView>,
        client_actor_id: Option<u64>,
        access: &AccessContext,
    ) -> Vec<EventView> {
        let visible_locations = self.visible_event_locations(client_actor_id, access);
        events
            .into_iter()
            .filter(|event| event_visible_to_locations(event, &visible_locations))
            .cloned()
            .collect()
    }

    fn card_registry_for(
        &self,
        location: &LocationView,
        actors: &[ActorView],
        items: &[ItemView],
        exits: &[ExitView],
        access: &AccessContext,
    ) -> CardRegistryView {
        let mut locations = BTreeMap::new();
        locations.insert(
            location.id,
            apply_location_access(
                card_for_location(
                    location.id,
                    location.name.as_str(),
                    Some(&self.location_meta_for(location.id)),
                ),
                location.id,
                access,
            ),
        );
        for exit in exits {
            locations.insert(
                exit.destination_location_id,
                apply_location_access(
                    card_for_location(
                        exit.destination_location_id,
                        exit.destination_location_name.as_str(),
                        Some(&self.location_meta_for(exit.destination_location_id)),
                    ),
                    exit.destination_location_id,
                    access,
                ),
            );
        }

        CardRegistryView {
            actors: actors
                .iter()
                .map(|actor| {
                    (
                        actor.id,
                        card_for_actor(
                            actor.id,
                            actor.name.as_str(),
                            actor.title.as_str(),
                            actor.description.as_str(),
                            actor.stats.level,
                        ),
                    )
                })
                .collect(),
            items: items
                .iter()
                .map(|item| {
                    (
                        item.id,
                        card_for_item(item.id, item.name.as_str(), item.description.as_str()),
                    )
                })
                .collect(),
            locations,
        }
    }

    fn card_transaction_views(
        &self,
        location_id: u64,
        actors: &[ActorView],
        items: &[ItemView],
        exits: &[ExitView],
        cards: &CardRegistryView,
    ) -> Vec<CardTransactionView> {
        let mut transactions = Vec::new();
        let Some(location_card) = cards.locations.get(&location_id) else {
            return transactions;
        };
        let location_ref = card_ref_view("location", location_id, location_card);

        for exit in exits.iter().filter(|exit| exit.accessible && !exit.locked) {
            if let Some(destination_card) = cards.locations.get(&exit.destination_location_id) {
                transactions.push(card_transaction_view(
                    location_ref.clone(),
                    "connected_to",
                    card_ref_view("location", exit.destination_location_id, destination_card),
                    Some(location_id),
                ));
            }
        }

        for actor in actors
            .iter()
            .filter(|actor| actor.location_id == location_id)
        {
            if let Some(actor_card) = cards.actors.get(&actor.id) {
                transactions.push(card_transaction_view(
                    card_ref_view("actor", actor.id, actor_card),
                    "in",
                    location_ref.clone(),
                    Some(location_id),
                ));
            }
        }

        for item in items {
            if item.location_id == Some(location_id) {
                if let Some(item_card) = cards.items.get(&item.id) {
                    transactions.push(card_transaction_view(
                        card_ref_view("item", item.id, item_card),
                        "in",
                        location_ref.clone(),
                        Some(location_id),
                    ));
                }
            }
            let Some(holder_actor_id) = item.holder_actor_id else {
                continue;
            };
            if let (Some(actor_card), Some(item_card)) = (
                cards.actors.get(&holder_actor_id),
                cards.items.get(&item.id),
            ) {
                transactions.push(card_transaction_view(
                    card_ref_view("actor", holder_actor_id, actor_card),
                    "holds",
                    card_ref_view("item", item.id, item_card),
                    Some(location_id),
                ));
            }
        }

        transactions
    }

    fn branch_is_active(&self, branch: &DialogueBranch) -> bool {
        self.world.tick <= branch.expires_at_tick
    }

    fn primary_action(&self, actor_id: Option<u64>, access: &AccessContext) -> PrimaryAction {
        let Some(actor_id) = actor_id else {
            return PrimaryAction {
                kind: "create_avatar".to_string(),
                label: "Create Avatar".to_string(),
                command: "create avatar".to_string(),
                disabled: false,
                options: Vec::new(),
            };
        };

        if self.actor_by_id(actor_id).is_none() {
            return PrimaryAction {
                kind: "create_avatar".to_string(),
                label: "Create Avatar".to_string(),
                command: "create avatar".to_string(),
                disabled: false,
                options: Vec::new(),
            };
        }

        if let Some(encounter) = self.active_combat_encounter_for_actor(actor_id) {
            if self.combat_current_actor_id(encounter.id) != Some(actor_id) {
                return PrimaryAction {
                    kind: "wait".to_string(),
                    label: "Wait".to_string(),
                    command: "wait".to_string(),
                    disabled: true,
                    options: Vec::new(),
                };
            }
            let mut options = vec![
                ActionOption {
                    kind: "attack".to_string(),
                    label: "Attack".to_string(),
                    command: "attack".to_string(),
                },
                ActionOption {
                    kind: "defend".to_string(),
                    label: "Dodge".to_string(),
                    command: "defend".to_string(),
                },
            ];
            if self.has_accessible_exit(actor_id, access) {
                options.push(ActionOption {
                    kind: "flee".to_string(),
                    label: "Escape".to_string(),
                    command: "flee".to_string(),
                });
            }
            return PrimaryAction {
                kind: "attack".to_string(),
                label: "Attack".to_string(),
                command: "attack".to_string(),
                disabled: false,
                options,
            };
        }

        let mut offers = CwActionOffers::default();
        let status = unsafe { cw_get_action_offers(&self.world, actor_id, &mut offers) };
        if status != CW_OK || offers.option_flags == 0 {
            return PrimaryAction {
                kind: "wait".to_string(),
                label: "Wait".to_string(),
                command: "wait".to_string(),
                disabled: true,
                options: Vec::new(),
            };
        }

        let has_chat_target = self.has_active_chat_target(actor_id);
        let has_combat_target = self.has_active_combat_target(actor_id);
        let has_resident_gift = self.has_resident_gift(actor_id);
        let can_trade_item = self.default_item_trade(actor_id).is_some();
        let can_prepare = self.prepare_available(actor_id);
        let can_work = self.work_available(actor_id);
        let can_help = self.help_available(actor_id);
        let can_rest = self.rest_available(actor_id);
        let has_unbanked_ledger = self.unbanked_visit_ledger_count(actor_id) > 0;
        let can_train_skill = self.default_trainable_skill(actor_id).is_some();
        let can_create_bond = self.default_bondable_resident(actor_id).is_some();
        let can_resolve_bond = self.default_resolvable_bond(actor_id).is_some();
        let default_feature_use = self.default_player_feature_use_candidate(actor_id);
        let default_search_target = self.default_search_target(actor_id);
        let default_craft_recipe = self.default_craft_recipe(actor_id);

        let mut options = Vec::new();
        if offers.option_flags & CW_OFFER_CHAT != 0 && has_chat_target {
            options.push(ActionOption {
                kind: "chat".to_string(),
                label: "Chat".to_string(),
                command: "chat".to_string(),
            });
        }
        if offers.option_flags & CW_OFFER_CHECK != 0 {
            if has_unbanked_ledger {
                options.push(ActionOption {
                    kind: "bank_ledger".to_string(),
                    label: "Grow".to_string(),
                    command: "bank ledger".to_string(),
                });
            } else if self.listen_offerable(actor_id) {
                options.push(ActionOption {
                    kind: "check".to_string(),
                    label: "Check".to_string(),
                    command: "listen".to_string(),
                });
            }
        }
        if offers.option_flags & CW_OFFER_MOVE != 0 && self.has_accessible_exit(actor_id, access) {
            options.push(ActionOption {
                kind: "move".to_string(),
                label: "Move".to_string(),
                command: "go".to_string(),
            });
        }
        if offers.option_flags & CW_OFFER_FLEE != 0
            && has_combat_target
            && self.has_accessible_exit(actor_id, access)
        {
            options.push(ActionOption {
                kind: "flee".to_string(),
                label: "Flee".to_string(),
                command: "flee".to_string(),
            });
        }
        if offers.option_flags & CW_OFFER_PICK_UP != 0 {
            options.push(ActionOption {
                kind: "pick_up".to_string(),
                label: "Pick Up".to_string(),
                command: "take".to_string(),
            });
        }
        if offers.option_flags & CW_OFFER_USE_ITEM != 0 && self.has_useful_usable_item(actor_id) {
            options.push(ActionOption {
                kind: "use_item".to_string(),
                label: "Use".to_string(),
                command: "use".to_string(),
            });
        }
        if let Some(candidate) = &default_feature_use {
            options.push(ActionOption {
                kind: "use_feature".to_string(),
                label: "Use".to_string(),
                command: format!("use {} on {}", candidate.item_name, candidate.feature_name),
            });
        }
        if let Some(target) = &default_search_target {
            options.push(ActionOption {
                kind: "search".to_string(),
                label: "Search".to_string(),
                command: format!("search {}", target.name),
            });
        }
        if offers.option_flags & CW_OFFER_CRAFT != 0 {
            if let Some(recipe) = default_craft_recipe {
                options.push(ActionOption {
                    kind: "craft".to_string(),
                    label: "Craft".to_string(),
                    command: format!("craft {}", recipe.name),
                });
            }
        }
        if offers.option_flags & CW_OFFER_GIVE_ITEM != 0 && has_resident_gift {
            options.push(ActionOption {
                kind: "give_item".to_string(),
                label: "Give Item".to_string(),
                command: "give".to_string(),
            });
        }
        if offers.option_flags & CW_OFFER_TRADE_ITEM != 0 && can_trade_item {
            options.push(ActionOption {
                kind: "trade_item".to_string(),
                label: "Trade".to_string(),
                command: "trade".to_string(),
            });
        }
        if offers.option_flags & CW_OFFER_DEFEND != 0 && has_combat_target {
            options.push(ActionOption {
                kind: "defend".to_string(),
                label: "Defend".to_string(),
                command: "defend".to_string(),
            });
        }
        if offers.option_flags & CW_OFFER_ATTACK != 0 && has_combat_target {
            options.push(ActionOption {
                kind: "attack".to_string(),
                label: "Attack".to_string(),
                command: "attack".to_string(),
            });
        }
        if can_prepare {
            options.push(ActionOption {
                kind: "prepare".to_string(),
                label: "Prepare".to_string(),
                command: "prepare".to_string(),
            });
        }
        if can_work {
            options.push(ActionOption {
                kind: "work".to_string(),
                label: if self.work_finishes_active_progress(actor_id) {
                    "Finish"
                } else {
                    "Work"
                }
                .to_string(),
                command: "work".to_string(),
            });
        }
        if can_help {
            options.push(ActionOption {
                kind: "help".to_string(),
                label: "Help".to_string(),
                command: "assist".to_string(),
            });
        }
        if can_rest {
            options.push(ActionOption {
                kind: "rest".to_string(),
                label: "Rest".to_string(),
                command: "rest".to_string(),
            });
        }
        if can_train_skill {
            let command = self
                .default_trainable_skill(actor_id)
                .and_then(skill_command_name)
                .map(|skill| format!("skill {skill}"))
                .unwrap_or_else(|| "skill listening".to_string());
            options.push(ActionOption {
                kind: "train_skill".to_string(),
                label: "Practice".to_string(),
                command,
            });
        }
        if can_create_bond {
            let command = self
                .default_bond_command(actor_id)
                .unwrap_or_else(|| "bond".to_string());
            options.push(ActionOption {
                kind: "create_bond".to_string(),
                label: "Grow Closer".to_string(),
                command,
            });
        }
        if can_resolve_bond {
            options.push(ActionOption {
                kind: "resolve_bond".to_string(),
                label: "Remember".to_string(),
                command: "remember".to_string(),
            });
        }

        let selected_kind = options
            .iter()
            .min_by_key(|option| self.action_offer_rank_for_actor(&option.kind, actor_id))
            .map(|option| option.kind.as_str())
            .unwrap_or("act");

        PrimaryAction {
            kind: match selected_kind {
                "move" => "travel",
                "act" => "act",
                kind => kind,
            }
            .to_string(),
            label: match selected_kind {
                "chat" => "Chat",
                "move" => "Travel",
                "flee" => "Flee",
                "give_item" => "Give Item",
                "trade_item" => "Trade",
                "use_item" => "Use",
                "use_feature" => "Use",
                "rest" => "Rest",
                "attack" => "Attack",
                "defend" => "Defend",
                "pick_up" => "Take",
                "check" => "Listen",
                "prepare" => "Prepare",
                "work" if self.work_finishes_active_progress(actor_id) => "Finish",
                "work" => "Work",
                "help" => "Help",
                "bank_ledger" => "Grow",
                "train_skill" => "Practice",
                "create_bond" => "Grow Closer",
                "resolve_bond" => "Remember",
                _ => "Act",
            }
            .to_string(),
            command: match selected_kind {
                "chat" => "chat".to_string(),
                "move" => "go".to_string(),
                "flee" => "flee".to_string(),
                "give_item" => "give".to_string(),
                "trade_item" => "trade".to_string(),
                "use_item" => "use".to_string(),
                "use_feature" => default_feature_use
                    .as_ref()
                    .map(|candidate| {
                        format!("use {} on {}", candidate.item_name, candidate.feature_name)
                    })
                    .unwrap_or_else(|| "use".to_string()),
                "rest" => "rest".to_string(),
                "attack" => "attack".to_string(),
                "defend" => "defend".to_string(),
                "pick_up" => "take".to_string(),
                "check" => "listen".to_string(),
                "prepare" => "prepare".to_string(),
                "work" => "work".to_string(),
                "help" => "assist".to_string(),
                "bank_ledger" => "bank ledger".to_string(),
                "train_skill" => self
                    .default_trainable_skill(actor_id)
                    .and_then(skill_command_name)
                    .map(|skill| format!("skill {skill}"))
                    .unwrap_or_else(|| "skill listening".to_string()),
                "create_bond" => self
                    .default_bond_command(actor_id)
                    .unwrap_or_else(|| "bond".to_string()),
                "resolve_bond" => "remember".to_string(),
                _ => "look".to_string(),
            },
            disabled: false,
            options,
        }
    }

    fn ranked_action_offers(
        &self,
        actor_id: Option<u64>,
        access: &AccessContext,
        primary_action: &PrimaryAction,
    ) -> Vec<RankedActionOffer> {
        let Some(actor_id) = actor_id else {
            return vec![self.ranked_offer_from_parts(
                "create_avatar",
                "Create Avatar",
                "create avatar",
                0,
                false,
                None,
                None,
                None,
                None,
                Some("Creates a new avatar at the cottage threshold.".to_string()),
                None,
                "no_active_avatar",
            )];
        };
        let zone = self
            .actor_by_id(actor_id)
            .map(|actor| {
                self.room_sheets
                    .get(&actor.location_id)
                    .map(|sheet| room_sheet_zone(sheet).to_string())
                    .unwrap_or_else(|| {
                        default_zone_for_scope("room", actor.location_id).to_string()
                    })
            })
            .unwrap_or_else(default_zone);
        let options: Vec<ActionOption> = if primary_action.options.is_empty() {
            vec![ActionOption {
                kind: primary_action.kind.clone(),
                label: primary_action.label.clone(),
                command: primary_action.command.clone(),
            }]
        } else {
            primary_action
                .options
                .iter()
                .map(|option| ActionOption {
                    kind: option.kind.clone(),
                    label: option.label.clone(),
                    command: option.command.clone(),
                })
                .collect()
        };
        let mut offers: Vec<_> = options
            .into_iter()
            .map(|option| {
                let rank = self.action_offer_rank_for_actor(&option.kind, actor_id);
                let target = self.action_offer_target(&option.kind, actor_id, access);
                let cost = self.action_offer_cost(&option.kind, actor_id);
                let risk = self.action_offer_risk(&option.kind, actor_id);
                let effect = self.action_offer_effect(&option.kind, actor_id);
                let progress = self.action_offer_progress(&option.kind, actor_id);
                let claim_key = self.action_offer_claim_key(&option.kind, actor_id);
                RankedActionOffer {
                    id: format!(
                        "{}:{}",
                        option.kind,
                        normalize_command_text(&option.command)
                    ),
                    category: action_offer_category(&option.kind).to_string(),
                    kind: option.kind,
                    label: option.label,
                    command: option.command,
                    rank,
                    disabled: primary_action.disabled,
                    disabled_reason: primary_action
                        .disabled
                        .then(|| "primary action is currently unavailable".to_string()),
                    zone: zone.clone(),
                    source: "kernel_flags+rpg_projection".to_string(),
                    target,
                    cost,
                    risk,
                    effect,
                    progress,
                    claim_key,
                    reason: "ranked from current room affordances and RPG projection".to_string(),
                }
            })
            .collect();
        offers.sort_by_key(|offer| offer.rank);
        offers
    }

    fn action_offer_rank_for_actor(&self, kind: &str, actor_id: u64) -> u16 {
        if kind == "work" && self.work_finishes_active_progress(actor_id) {
            return if self
                .actor_by_id(actor_id)
                .is_some_and(|actor| self.prepared_tag_active(actor_id, actor.location_id))
            {
                33
            } else {
                36
            };
        }
        if self.project_preparation_spent_for_actor(actor_id) {
            match kind {
                "work" => return 36,
                "help" => return 37,
                _ => {}
            }
        }
        if kind == "bank_ledger" && self.unbanked_visit_ledger_count(actor_id) > 0 {
            return if self.rest_available(actor_id) {
                24
            } else {
                34
            };
        }
        if kind == "check"
            && self
                .actor_by_id(actor_id)
                .is_some_and(|actor| self.listen_attempt_claimed_at(actor_id, actor.location_id))
        {
            return 82;
        }
        if kind == "chat" {
            return 83;
        }
        if kind == "rest"
            && self
                .actor_by_id(actor_id)
                .is_some_and(|actor| !self.location_is_frontier(actor.location_id))
        {
            return 84;
        }
        if kind == "train_skill"
            && self.default_bondable_resident(actor_id).is_some()
            && self
                .default_trainable_skill(actor_id)
                .is_some_and(|skill_id| {
                    self.skills
                        .get(&skill_state_id(actor_id, skill_id))
                        .is_some_and(|skill| skill.rank > 0)
                })
        {
            return 78;
        }
        action_offer_rank(kind)
    }

    fn ranked_offer_from_parts(
        &self,
        kind: &str,
        label: &str,
        command: &str,
        rank: u16,
        disabled: bool,
        disabled_reason: Option<String>,
        target: Option<ActionTargetView>,
        cost: Option<ActionCostView>,
        risk: Option<String>,
        effect: Option<String>,
        claim_key: Option<String>,
        reason: &str,
    ) -> RankedActionOffer {
        RankedActionOffer {
            id: format!("{kind}:{}", normalize_command_text(command)),
            kind: kind.to_string(),
            category: action_offer_category(kind).to_string(),
            label: label.to_string(),
            command: normalize_command_text(command),
            rank,
            disabled,
            disabled_reason,
            zone: default_zone(),
            source: "server".to_string(),
            target,
            cost,
            risk,
            effect,
            progress: None,
            claim_key,
            reason: reason.to_string(),
        }
    }

    fn action_offer_target(
        &self,
        kind: &str,
        actor_id: u64,
        access: &AccessContext,
    ) -> Option<ActionTargetView> {
        let actor = self.actor_by_id(actor_id)?;
        match kind {
            "chat" => self
                .default_chat_target(actor_id)
                .map(|target| ActionTargetView {
                    kind: "actor".to_string(),
                    id: Some(target.id),
                    label: self.actor_name(target.id),
                }),
            "attack" | "defend" => self
                .combat_job_for_actor(actor_id, None)
                .and_then(|(_, target_id)| self.actor_by_id(target_id))
                .map(|target| ActionTargetView {
                    kind: "actor".to_string(),
                    id: Some(target.id),
                    label: self.actor_name(target.id),
                }),
            "help" => self
                .default_chat_target(actor_id)
                .map(|target| ActionTargetView {
                    kind: "actor".to_string(),
                    id: Some(target.id),
                    label: self.actor_name(target.id),
                }),
            "use_feature" => self
                .default_player_feature_use_candidate(actor_id)
                .map(|candidate| ActionTargetView {
                    kind: "feature".to_string(),
                    id: Some(candidate.location_id),
                    label: Some(candidate.feature_name),
                }),
            "give_item" => self
                .default_resident_gift_candidate(actor_id)
                .map(|candidate| ActionTargetView {
                    kind: "actor".to_string(),
                    id: Some(candidate.target.id),
                    label: Some(format!(
                        "{} to {}",
                        self.item_name(candidate.offered_item.id)
                            .unwrap_or_else(|| format!("Item {}", candidate.offered_item.id)),
                        self.actor_name(candidate.target.id)
                            .unwrap_or_else(|| format!("Resident {}", candidate.target.id))
                    )),
                }),
            "trade_item" => self
                .default_item_trade(actor_id)
                .map(|(_, target, target_item)| ActionTargetView {
                    kind: "item".to_string(),
                    id: Some(target_item.id),
                    label: Some(format!(
                        "{} from {}",
                        self.item_name(target_item.id)
                            .unwrap_or_else(|| format!("Item {}", target_item.id)),
                        self.actor_name(target.id)
                            .unwrap_or_else(|| format!("Resident {}", target.id))
                    )),
                }),
            "search" => self
                .default_search_target(actor_id)
                .map(|target| ActionTargetView {
                    kind: "feature".to_string(),
                    id: Some(target.location_id),
                    label: Some(target.name),
                }),
            "craft" => self
                .default_craft_recipe(actor_id)
                .map(|recipe| ActionTargetView {
                    kind: "recipe".to_string(),
                    id: Some(recipe.id),
                    label: Some(recipe.name.clone()),
                }),
            "move" | "flee" => self
                .exit_views(actor.location_id, access)
                .into_iter()
                .find(|exit| exit.accessible && !exit.locked)
                .map(|exit| ActionTargetView {
                    kind: "location".to_string(),
                    id: Some(exit.destination_location_id),
                    label: Some(exit.destination_location_name),
                }),
            "create_bond" => {
                self.default_bondable_resident(actor_id)
                    .map(|target| ActionTargetView {
                        kind: "actor".to_string(),
                        id: Some(target.id),
                        label: self.actor_name(target.id),
                    })
            }
            "resolve_bond" => self
                .default_resolvable_bond(actor_id)
                .map(|bond| ActionTargetView {
                    kind: "actor".to_string(),
                    id: Some(bond.target_actor_id),
                    label: self.actor_name(bond.target_actor_id),
                }),
            _ => None,
        }
    }

    fn action_offer_cost(&self, kind: &str, actor_id: u64) -> Option<ActionCostView> {
        match kind {
            "chat" => Some(ActionCostView {
                orbs: CHAT_ORB_COST,
                reason: "server-authored avatar chat".to_string(),
            }),
            "check" => {
                let orbs = self.listen_cost_orbs(actor_id);
                (orbs > 0).then(|| ActionCostView {
                    orbs,
                    reason: "repeat frontier listen".to_string(),
                })
            }
            _ => None,
        }
    }

    fn action_offer_risk(&self, kind: &str, actor_id: u64) -> Option<String> {
        let actor = self.actor_by_id(actor_id)?;
        match kind {
            "attack"
                if self
                    .active_danger_clock_id_for_location(actor.location_id)
                    .is_some() =>
            {
                Some(
                    "the scuffle grows more dangerous; someone may be hurt or fall quiet"
                        .to_string(),
                )
            }
            "attack" => Some("someone may be hurt or fall quiet".to_string()),
            "defend" => Some("you guard instead of striking".to_string()),
            "flee" => Some("you leave the danger and this room behind".to_string()),
            "check" if self.location_is_frontier(actor.location_id) => {
                Some("listening again out here may tire you".to_string())
            }
            "work" if !self.prepared_tag_active(actor_id, actor.location_id) => {
                Some("rushing in may tire you".to_string())
            }
            "help" if self.repeated_unprepared_help_tires(actor_id, actor.location_id) => {
                Some("helping again may tire you".to_string())
            }
            "rest" => self
                .active_danger_clock_id_for_location(actor.location_id)
                .filter(|clock_id| self.clock_is_frontier(clock_id))
                .filter(|_| !self.hearth_tonic_warmth_guards_rest(actor.location_id))
                .map(|_| "trouble may draw nearer while you rest".to_string()),
            _ => None,
        }
    }

    fn action_offer_progress(&self, kind: &str, actor_id: u64) -> Option<u8> {
        let actor = self.actor_by_id(actor_id)?;
        match kind {
            "check" => lifecycle_effects_for("on_listen", "room", &actor.location_id.to_string())
                .into_iter()
                .find_map(|effect| match effect {
                    EffectDescriptor::AdvanceClock { amount, .. } => Some(amount),
                    _ => None,
                }),
            "prepare" => Some(self.prepared_project_progress_amount(actor_id, actor.location_id)),
            "defend" if self.prepare_available(actor_id) => {
                Some(self.prepared_project_progress_amount(actor_id, actor.location_id))
            }
            "work"
                if self
                    .active_progress_clock_id_for_location(actor.location_id)
                    .is_some() =>
            {
                Some(self.work_project_progress_amount(actor_id, actor.location_id))
            }
            "help"
                if self
                    .active_progress_clock_id_for_location(actor.location_id)
                    .is_some() =>
            {
                Some(self.help_project_progress_amount(actor_id, actor.location_id))
            }
            _ => None,
        }
    }

    fn action_offer_effect(&self, kind: &str, actor_id: u64) -> Option<String> {
        let actor = self.actor_by_id(actor_id)?;
        match kind {
            "chat" => self
                .default_chat_target(actor_id)
                .and_then(|target| self.actor_name(target.id))
                .map(|name| format!("opens a small exchange with {name}")),
            "check" => {
                let unbanked = self.unbanked_visit_ledger_count(actor_id);
                if unbanked > 0 {
                    return Some("keeps what this visit taught you".to_string());
                }
                if self.listen_attempt_claimed_at(actor_id, actor.location_id) {
                    return Some(
                        "listens once more, though the room may have nothing new yet"
                            .to_string(),
                    );
                }
                let effects =
                    lifecycle_effects_for("on_listen", "room", &actor.location_id.to_string());
                if effects.is_empty() {
                    Some("lets the room share one useful clue".to_string())
                } else {
                    Some(
                        "lets the room share one useful clue; what you hear may help the shared work"
                            .to_string(),
                    )
                }
            }
            "prepare" => {
                let amount = self.prepared_project_progress_amount(actor_id, actor.location_id);
                let setup_effect = "makes the next try count";
                let multi_room_partial = self
                    .active_job_for_location(actor.location_id)
                    .is_some_and(|job| {
                        job.location_ids.len() > 1
                            && self.project_location_evidence_count(actor_id, job)
                                < job.location_ids.len()
                    });
                if amount > 2 {
                    Some(format!(
                        "brings together every clue you found; {setup_effect}"
                    ))
                } else if multi_room_partial {
                    Some(format!("uses the clues you found here; {setup_effect}"))
                } else {
                    Some(setup_effect.to_string())
                }
            }
            "defend" if self.prepare_available(actor_id) => {
                Some("guards carefully and makes the next try count".to_string())
            }
            "defend" => Some("raises a careful guard".to_string()),
            "work" => self
                .active_progress_clock_id_for_location(actor.location_id)
                .map(|clock_id| {
                    self.project_headway_text(
                        &clock_id,
                        self.work_project_progress_amount(actor_id, actor.location_id),
                    )
                }),
            "help" => self
                .active_progress_clock_id_for_location(actor.location_id)
                .map(|clock_id| {
                    let amount = self.help_project_progress_amount(actor_id, actor.location_id);
                    let progress_effect = self.project_headway_text(&clock_id, amount);
                    if let Some(target) = self.default_chat_target(actor_id) {
                        let target_name = self
                            .actor_name(target.id)
                            .unwrap_or_else(|| format!("Resident {}", target.id));
                        let claim_key = help_bond_claim_key(actor_id, target.id);
                        if !self.rpg_claims.contains(&claim_key) {
                            format!(
                                "helps {target_name}; {progress_effect}; first help brings you closer to {target_name}"
                            )
                        } else {
                            format!("helps a resident and {progress_effect}")
                        }
                    } else {
                        format!("helps a resident and {progress_effect}")
                    }
                }),
            "rest"
                if self
                    .active_danger_clock_id_for_location(actor.location_id)
                    .is_some_and(|clock_id| self.clock_is_frontier(&clock_id))
                    && self.hearth_tonic_warmth_guards_rest(actor.location_id) =>
            {
                Some(
                    "helps you feel fresh and uses the tonic's warmth; trouble stays back"
                        .to_string(),
                )
            }
            "rest" if self.trained_since_rest_tag_active(actor_id) => {
                Some("helps you feel fresh; practice settles into something lasting".to_string())
            }
            "rest" => Some("helps you feel fresh; trouble may draw nearer out here".to_string()),
            "move" => Some("takes you to a nearby room".to_string()),
            "flee" => Some("returns from the frontier with something worth remembering".to_string()),
            "search" => self.default_search_target(actor_id).map(|target| {
                let candidates =
                    self.search_reveal_candidates_for_feature(actor.location_id, &target.key);
                let Some(candidate) = candidates.first() else {
                    return format!("looks closely around {}", target.name);
                };
                match candidate {
                    SearchRevealCandidate::SeedExit { .. } => {
                        format!("looks closely around {}; uncovers a new path", target.name)
                    }
                    SearchRevealCandidate::HiddenExit { .. } => {
                        format!(
                            "looks closely around {}; uncovers a hidden entrance",
                            target.name
                        )
                    }
                    SearchRevealCandidate::Avatar { .. } => {
                        format!("looks closely around {}; finds someone hidden", target.name)
                    }
                    SearchRevealCandidate::Item { .. } => {
                        format!("looks closely around {}; finds a hidden item", target.name)
                    }
                }
            }),
            "craft" => self.default_craft_recipe(actor_id).map(|recipe| {
                let output = recipe
                    .output
                    .as_ref()
                    .map(|output| output.name.as_str())
                    .unwrap_or("a new keepsake");
                format!(
                    "creates {output} from present items without consuming the inputs"
                )
            }),
            "bank_ledger" => {
                let count = self.unbanked_visit_ledger_count(actor_id);
                (count > 0).then(|| "lets this visit become part of you".to_string())
            }
            "train_skill" => self.default_trainable_skill(actor_id).map(|skill_id| {
                let label = skill_label(skill_id).unwrap_or("Skill");
                format!("{label} grows a little stronger")
            }),
            "create_bond" => self.default_bondable_resident(actor_id).and_then(|target| {
                self.actor_name(target.id)
                    .map(|name| format!("a friendship with {name} begins"))
            }),
            "resolve_bond" => self.default_resolvable_bond(actor_id).and_then(|bond| {
                self.actor_name(bond.target_actor_id)
                    .map(|name| format!("keeps what mattered with {name}; leaves you something to remember"))
            }),
            "give_item" => self
                .default_resident_gift_candidate(actor_id)
                .map(|candidate| {
                    let item_name = self
                        .item_name(candidate.offered_item.id)
                        .unwrap_or_else(|| format!("Item {}", candidate.offered_item.id));
                    let target_name = self
                        .actor_name(candidate.target.id)
                        .unwrap_or_else(|| format!("Resident {}", candidate.target.id));
                    let reason = candidate.request.reason.trim_end_matches('.');
                    if let Some(return_item) = self.resident_player_gift_return_item(
                        candidate.target,
                        candidate.offered_item,
                    ) {
                        let return_name = self
                            .item_name(return_item.id)
                            .unwrap_or_else(|| format!("Item {}", return_item.id));
                        format!(
                            "{reason}; offers {item_name} to {target_name}; {target_name} hands you {return_name} to make room"
                        )
                    } else {
                        format!("{reason}; offers {item_name} to {target_name}")
                    }
                }),
            "trade_item" => self
                .default_item_trade_candidate(actor_id)
                .map(|candidate| {
                    let ResidentTradeCandidate {
                        offered_item,
                        target,
                        target_item,
                        preference,
                    } = candidate;
                    format!(
                        "{} swaps {} with {} for {}",
                        preference.reason,
                        self.item_name(offered_item.id)
                            .unwrap_or_else(|| format!("Item {}", offered_item.id)),
                        self.actor_name(target.id)
                            .unwrap_or_else(|| format!("Resident {}", target.id)),
                        self.item_name(target_item.id)
                            .unwrap_or_else(|| format!("Item {}", target_item.id))
                    )
                }),
            "use_item" => Some("uses a held item on a valid room or actor target".to_string()),
            "use_feature" => self
                .default_player_feature_use_candidate(actor_id)
                .map(|candidate| candidate.effect),
            "pick_up" => {
                if self.actor_inventory_full(actor_id) {
                    Some("takes the floor item and places your held item here".to_string())
                } else {
                    Some("takes the floor item into your hand".to_string())
                }
            }
            _ => None,
        }
    }

    fn action_offer_claim_key(&self, kind: &str, actor_id: u64) -> Option<String> {
        let actor = self.actor_by_id(actor_id)?;
        match kind {
            "chat" => None,
            "check" => Some(ability_check_success_claim_key(
                actor_id,
                actor.location_id,
                LISTEN_ABILITY,
                LISTEN_DC as i16,
            )),
            "rest" => Some(tired_tag_id(actor_id)),
            "help" => self.default_chat_target(actor_id).and_then(|target| {
                let claim_key = help_bond_claim_key(actor_id, target.id);
                (!self.rpg_claims.contains(&claim_key)).then_some(claim_key)
            }),
            "create_bond" => self
                .default_bondable_resident(actor_id)
                .map(|target| bond_id(actor_id, target.id)),
            "resolve_bond" => self
                .default_resolvable_bond(actor_id)
                .map(|bond| format!("bond_resolved:{}", bond.id)),
            _ => None,
        }
    }

    fn has_accessible_exit(&self, actor_id: u64, access: &AccessContext) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        self.exit_views(actor.location_id, access)
            .into_iter()
            .any(|exit| exit.accessible && !exit.locked)
    }

    fn active_chat_targets(&self, actor_id: u64) -> Vec<CwActor> {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return Vec::new();
        };
        self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|target| {
                target.id != actor_id
                    && target.kind == CW_ACTOR_NPC
                    && target.status == CW_ACTOR_ACTIVE
                    && target.location_id == actor.location_id
                    && self.actor_visible_in_projection(*target, Some(actor_id), None)
            })
            .collect()
    }

    fn default_chat_target(&self, actor_id: u64) -> Option<CwActor> {
        self.active_chat_targets(actor_id).into_iter().next()
    }

    fn has_active_chat_target(&self, actor_id: u64) -> bool {
        self.default_chat_target(actor_id).is_some()
    }

    fn has_active_combat_target(&self, actor_id: u64) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        self.combat_job_for_actor(actor_id, None)
            .is_some_and(|(job_id, target_id)| {
                let encounter_id = combat_encounter_id(&job_id);
                let actor_can_act = self
                    .active_combat_encounter(encounter_id)
                    .map(|_| {
                        !self.combat_actor_is_participant(encounter_id, actor_id)
                            || self.combat_current_actor_id(encounter_id) == Some(actor_id)
                    })
                    .unwrap_or(true);
                actor_can_act
                    && self.actor_by_id(target_id).is_some_and(|target| {
                        target.kind == CW_ACTOR_NPC
                            && target.status == CW_ACTOR_ACTIVE
                            && target.location_id == actor.location_id
                            && self.actor_visible_in_projection(target, Some(actor_id), None)
                    })
            })
    }

    fn location_has_unresolved_combat(&self, location_id: u64) -> bool {
        self.location_allows_combat(location_id)
            && self.jobs.values().any(|job| {
                job.location_ids.contains(&location_id) && self.job_status(job) == "active"
            })
    }

    fn location_allows_combat(&self, location_id: u64) -> bool {
        self.world.locations[..self.world.location_count]
            .iter()
            .any(|location| {
                location.id == location_id && (location.flags & CW_LOCATION_ALLOW_COMBAT) != 0
            })
    }

    fn has_resident_gift(&self, actor_id: u64) -> bool {
        self.default_resident_gift_candidate(actor_id).is_some()
    }

    fn default_resident_gift_candidate(
        &self,
        actor_id: u64,
    ) -> Option<ResidentPlayerGiftCandidate> {
        let actor = self.actor_by_id(actor_id)?;
        if actor.kind != CW_ACTOR_HUMAN || actor.status != CW_ACTOR_ACTIVE {
            return None;
        }

        let held_items = self.actor_held_items(actor_id);
        if held_items.is_empty() {
            return None;
        }

        let mut candidates = Vec::new();
        let mut targets = self.active_chat_targets(actor_id);
        targets.sort_by_key(|target| target.id);
        for target in targets {
            let Some(request) = self.resident_request_for_holder(target, actor_id) else {
                continue;
            };
            let Some(offered_item) = held_items
                .iter()
                .copied()
                .find(|item| item.id == request.item_id)
            else {
                continue;
            };
            if !self.resident_can_accept_player_gift(target, offered_item) {
                continue;
            }
            candidates.push(ResidentPlayerGiftCandidate {
                offered_item,
                target,
                request,
            });
        }
        candidates.sort_by_key(|candidate| {
            (
                std::cmp::Reverse(
                    self.resident_item_offer_score(candidate.target, candidate.offered_item),
                ),
                candidate.target.id,
                candidate.offered_item.id,
            )
        });
        candidates.into_iter().next()
    }

    fn resident_gift_is_willing(
        &self,
        actor_id: u64,
        target_actor_id: u64,
        item_id: u64,
    ) -> Result<(), String> {
        let actor = self
            .actor_by_id(actor_id)
            .ok_or_else(|| "That avatar is not here.".to_string())?;
        if actor.kind != CW_ACTOR_HUMAN || actor.status != CW_ACTOR_ACTIVE {
            return Err("Only an active player avatar can give items.".to_string());
        }
        let target = self
            .actor_by_id(target_actor_id)
            .ok_or_else(|| "That resident is not here.".to_string())?;
        if target.kind != CW_ACTOR_NPC
            || target.status != CW_ACTOR_ACTIVE
            || target.location_id != actor.location_id
        {
            return Err("That resident is not close enough to receive an item.".to_string());
        }
        let offered_item = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .find(|item| item.id == item_id)
            .ok_or_else(|| "That item is not here.".to_string())?;
        if offered_item.holder_actor_id != actor_id {
            return Err("You are not holding that item.".to_string());
        }
        let Some(request) = self.resident_request_for_holder(target, actor_id) else {
            let target_name = self
                .actor_name(target.id)
                .unwrap_or_else(|| format!("Resident {}", target.id));
            return Err(format!(
                "{target_name} is not asking for that item right now."
            ));
        };
        if request.item_id != item_id {
            let target_name = self
                .actor_name(target.id)
                .unwrap_or_else(|| format!("Resident {}", target.id));
            let item_name = self
                .item_name(offered_item.id)
                .unwrap_or_else(|| format!("Item {}", offered_item.id));
            return Err(format!(
                "{target_name} is not seeking {item_name} right now."
            ));
        }
        if !self.resident_can_accept_player_gift(target, offered_item) {
            let target_name = self
                .actor_name(target.id)
                .unwrap_or_else(|| format!("Resident {}", target.id));
            return Err(format!(
                "{target_name} has no free paw and cannot part with what they carry."
            ));
        }
        Ok(())
    }

    fn default_item_trade(&self, actor_id: u64) -> Option<(CwItem, CwActor, CwItem)> {
        self.default_item_trade_candidate(actor_id)
            .map(|candidate| {
                (
                    candidate.offered_item,
                    candidate.target,
                    candidate.target_item,
                )
            })
    }

    fn default_item_trade_candidate(&self, actor_id: u64) -> Option<ResidentTradeCandidate> {
        self.accepted_item_trade_candidates(actor_id)
            .into_iter()
            .next()
    }

    fn default_item_trade_stance_candidate_for_target(
        &self,
        actor_id: u64,
        target_actor_id: u64,
    ) -> Option<ResidentTradeCandidate> {
        self.item_trade_candidates(actor_id)
            .into_iter()
            .find(|candidate| candidate.target.id == target_actor_id)
    }

    fn accepted_item_trade_candidates(&self, actor_id: u64) -> Vec<ResidentTradeCandidate> {
        self.item_trade_candidates(actor_id)
            .into_iter()
            .filter(|candidate| candidate.preference.accepted)
            .collect()
    }

    fn item_trade_candidates(&self, actor_id: u64) -> Vec<ResidentTradeCandidate> {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return Vec::new();
        };
        if actor.kind != CW_ACTOR_HUMAN || actor.status != CW_ACTOR_ACTIVE {
            return Vec::new();
        }
        let offered_items = self.actor_held_items(actor_id);
        if offered_items.is_empty() {
            return Vec::new();
        }

        let mut targets = self.active_chat_targets(actor_id);
        targets.sort_by_key(|target| target.id);
        let mut candidates = Vec::new();
        for target in targets {
            for target_item in self.actor_held_items(target.id) {
                for offered_item in &offered_items {
                    let preference =
                        self.resident_trade_preference(target.id, *offered_item, target_item);
                    candidates.push(ResidentTradeCandidate {
                        offered_item: *offered_item,
                        target,
                        target_item,
                        preference,
                    });
                }
            }
        }
        candidates.sort_by(|left, right| {
            right
                .preference
                .accepted
                .cmp(&left.preference.accepted)
                .then_with(|| right.preference.score.cmp(&left.preference.score))
                .then_with(|| left.target.id.cmp(&right.target.id))
                .then_with(|| left.target_item.id.cmp(&right.target_item.id))
                .then_with(|| left.offered_item.id.cmp(&right.offered_item.id))
        });
        candidates
    }

    fn resident_mutual_trade_candidate(
        &self,
        actor: CwActor,
    ) -> Option<ResidentMutualTradeCandidate> {
        if actor.kind != CW_ACTOR_NPC || actor.status != CW_ACTOR_ACTIVE {
            return None;
        }
        let actor_items = self.actor_held_items(actor.id);
        if actor_items.is_empty() {
            return None;
        }

        let mut targets: Vec<_> = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|target| {
                target.id != actor.id
                    && target.kind == CW_ACTOR_NPC
                    && target.status == CW_ACTOR_ACTIVE
                    && target.location_id == actor.location_id
                    && self.resident_remembers_actor_at(actor.id, target.id, actor.location_id)
            })
            .collect();
        targets.sort_by_key(|target| target.id);

        let mut candidates = Vec::new();
        for target in targets {
            for actor_item in &actor_items {
                for target_item in self.actor_held_items(target.id) {
                    if !self.resident_remembers_actor_holding_item_at(
                        actor.id,
                        target.id,
                        target_item.id,
                        actor.location_id,
                    ) {
                        continue;
                    }
                    let Some(target_desire_memory) =
                        self.resident_actor_wants_item_memory(actor.id, target.id, actor_item.id)
                    else {
                        continue;
                    };
                    let target_preference =
                        self.resident_trade_preference(target.id, *actor_item, target_item);
                    let actor_preference =
                        self.resident_trade_preference(actor.id, target_item, *actor_item);
                    if target_preference.accepted && actor_preference.accepted {
                        candidates.push(ResidentMutualTradeCandidate {
                            actor_item: *actor_item,
                            target,
                            target_item,
                            actor_preference,
                            target_preference,
                            target_desire_confidence: target_desire_memory.confidence,
                            target_desire_salience: target_desire_memory.salience,
                            target_desire_observed_tick: target_desire_memory.observed_tick,
                        });
                    }
                }
            }
        }
        candidates.sort_by(|left, right| {
            let left_score = left
                .actor_preference
                .score
                .saturating_add(left.target_preference.score);
            let right_score = right
                .actor_preference
                .score
                .saturating_add(right.target_preference.score);
            right_score
                .cmp(&left_score)
                .then_with(|| {
                    right
                        .target_desire_salience
                        .cmp(&left.target_desire_salience)
                })
                .then_with(|| {
                    right
                        .target_desire_confidence
                        .cmp(&left.target_desire_confidence)
                })
                .then_with(|| {
                    right
                        .target_desire_observed_tick
                        .cmp(&left.target_desire_observed_tick)
                })
                .then_with(|| left.target.id.cmp(&right.target.id))
                .then_with(|| left.target_item.id.cmp(&right.target_item.id))
                .then_with(|| left.actor_item.id.cmp(&right.actor_item.id))
        });
        candidates.into_iter().next()
    }

    fn resident_gift_candidate(&self, actor: CwActor) -> Option<ResidentGiftCandidate> {
        if actor.kind != CW_ACTOR_NPC || actor.status != CW_ACTOR_ACTIVE {
            return None;
        }
        let actor_items = self.actor_held_items(actor.id);
        if actor_items.is_empty() {
            return None;
        }

        let mut targets: Vec<_> = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|target| {
                target.id != actor.id
                    && target.kind == CW_ACTOR_NPC
                    && target.status == CW_ACTOR_ACTIVE
                    && target.location_id == actor.location_id
                    && self.resident_remembers_actor_at(actor.id, target.id, actor.location_id)
            })
            .collect();
        targets.sort_by_key(|target| target.id);

        let mut candidates = Vec::new();
        for actor_item in actor_items {
            if self.resident_item_is_attached(actor.id, actor_item) {
                continue;
            }
            for target in &targets {
                if !self.actor_can_receive_item(*target, actor_item.id) {
                    continue;
                }
                if let Some(desire_memory) =
                    self.resident_actor_wants_item_memory(actor.id, target.id, actor_item.id)
                {
                    candidates.push(ResidentGiftCandidate {
                        actor_item,
                        target: *target,
                        desire_confidence: desire_memory.confidence,
                        desire_salience: desire_memory.salience,
                        desire_observed_tick: desire_memory.observed_tick,
                    });
                }
            }
        }
        candidates.sort_by_key(|candidate| {
            (
                std::cmp::Reverse(candidate.desire_salience),
                std::cmp::Reverse(candidate.desire_confidence),
                std::cmp::Reverse(candidate.desire_observed_tick),
                self.resident_item_keep_score(actor, candidate.actor_item),
                candidate.target.id,
                candidate.actor_item.id,
            )
        });
        candidates.into_iter().next()
    }

    fn resident_delivery_candidate(&self, actor: CwActor) -> Option<ResidentDeliveryCandidate> {
        if actor.kind != CW_ACTOR_NPC || actor.status != CW_ACTOR_ACTIVE {
            return None;
        }
        let actor_items = self.actor_held_items(actor.id);
        if actor_items.is_empty() {
            return None;
        }

        let mut candidates = Vec::new();
        for actor_item in actor_items {
            if self.resident_item_is_attached(actor.id, actor_item) {
                continue;
            }
            let target_memories: Vec<_> = self
                .resident_memories
                .values()
                .filter(|memory| {
                    memory.carrier_actor_id == actor.id
                        && memory.kind == RESIDENT_MEMORY_KIND_ACTOR_LOCATION
                        && memory.subject_id != actor.id
                        && memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
                })
                .cloned()
                .collect();
            for memory in target_memories {
                let Some(target) = self.actor_by_id(memory.subject_id) else {
                    continue;
                };
                if target.kind != CW_ACTOR_NPC || target.status != CW_ACTOR_ACTIVE {
                    continue;
                }
                let Some(desire_memory) =
                    self.resident_actor_wants_item_memory(actor.id, target.id, actor_item.id)
                else {
                    continue;
                };
                if memory.location_id == actor.location_id
                    || self
                        .next_unlocked_step_toward(actor.location_id, memory.location_id)
                        .is_none()
                {
                    continue;
                }
                candidates.push(ResidentDeliveryCandidate {
                    actor_item,
                    target,
                    target_location_id: memory.location_id,
                    confidence: memory.confidence,
                    salience: memory.salience,
                    observed_tick: memory.observed_tick,
                    desire_confidence: desire_memory.confidence,
                    desire_salience: desire_memory.salience,
                    desire_observed_tick: desire_memory.observed_tick,
                });
            }
        }
        candidates.sort_by_key(|candidate| {
            (
                std::cmp::Reverse(candidate.desire_salience),
                std::cmp::Reverse(candidate.desire_confidence),
                std::cmp::Reverse(candidate.desire_observed_tick),
                self.resident_item_keep_score(actor, candidate.actor_item),
                std::cmp::Reverse(candidate.salience),
                std::cmp::Reverse(candidate.confidence),
                std::cmp::Reverse(candidate.observed_tick),
                candidate.target_location_id,
                candidate.target.id,
                candidate.actor_item.id,
            )
        });
        candidates.into_iter().next()
    }

    fn resident_trade_is_willing(
        &self,
        actor_id: u64,
        target_actor_id: u64,
        item_id: u64,
        target_item_id: u64,
    ) -> Result<(), String> {
        let actor = self
            .actor_by_id(actor_id)
            .ok_or_else(|| "That avatar is not here.".to_string())?;
        if actor.kind != CW_ACTOR_HUMAN || actor.status != CW_ACTOR_ACTIVE {
            return Err("Only an active player avatar can trade.".to_string());
        }
        let target = self
            .actor_by_id(target_actor_id)
            .ok_or_else(|| "That resident is not here.".to_string())?;
        if target.kind != CW_ACTOR_NPC
            || target.status != CW_ACTOR_ACTIVE
            || target.location_id != actor.location_id
        {
            return Err("That resident is not close enough to trade.".to_string());
        }
        let offered_item = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .find(|item| item.id == item_id)
            .ok_or_else(|| "That item is not here.".to_string())?;
        let requested_item = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .find(|item| item.id == target_item_id)
            .ok_or_else(|| "That trade item is not here.".to_string())?;
        if offered_item.holder_actor_id != actor_id || requested_item.holder_actor_id != target.id {
            return Err("Those items are not held by the trading partners.".to_string());
        }
        let preference = self.resident_trade_preference(target.id, offered_item, requested_item);
        if preference.accepted {
            Ok(())
        } else {
            Err(preference.reason)
        }
    }

    fn has_useful_usable_item(&self, actor_id: u64) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        let has_charged_potion = self.world.items[..self.world.item_count]
            .iter()
            .any(|item| {
                item.holder_actor_id == actor_id && item.kind == CW_ITEM_POTION && item.charges > 0
            });
        has_charged_potion
            && self.world.actors[..self.world.actor_count]
                .iter()
                .any(|target| self.healing_target_is_offerable(&actor, target))
    }

    fn healing_target_is_offerable(&self, actor: &CwActor, target: &CwActor) -> bool {
        if target.location_id != actor.location_id {
            return false;
        }
        let needs_healing = target.status == CW_ACTOR_KNOCKED_OUT
            || (target.status == CW_ACTOR_ACTIVE && target.damage > 0);
        if !needs_healing {
            return false;
        }
        if target.id == actor.id {
            return true;
        }
        !(target.kind == CW_ACTOR_NPC && self.location_has_unresolved_combat(actor.location_id))
    }

    fn apply_wallet_overlap_placements(&mut self, ownership: &OwnershipIndex, day_index: u64) {
        let _ = self.apply_wallet_overlap_placements_inner(ownership, day_index, false);
    }

    fn apply_wallet_overlap_placements_with_events(
        &mut self,
        ownership: &OwnershipIndex,
        day_index: u64,
    ) -> Vec<EventView> {
        self.apply_wallet_overlap_placements_inner(ownership, day_index, true)
    }

    fn apply_wallet_overlap_placements_inner(
        &mut self,
        ownership: &OwnershipIndex,
        day_index: u64,
        emit_events: bool,
    ) -> Vec<EventView> {
        let mut events = Vec::new();
        for (actor_id, actor_card_id) in [
            (1001, "rati"),
            (1002, "cosy-whiskerwind"),
            (1003, "cosy-skull"),
        ] {
            let location_id =
                actor_location_from_overlap(actor_card_id, ownership, day_index).unwrap_or(1);
            if let Some(event) = self.place_actor_location(actor_id, location_id, emit_events) {
                events.push(event);
            }
        }
        events
    }

    #[cfg(test)]
    fn force_actor_location(&mut self, actor_id: u64, location_id: u64) {
        let _ = self.place_actor_location(actor_id, location_id, false);
    }

    fn place_actor_location(
        &mut self,
        actor_id: u64,
        location_id: u64,
        emit_event: bool,
    ) -> Option<EventView> {
        if self.location_name(location_id).is_none() {
            return None;
        }
        let mut from_location_id = None;
        if let Some(actor) = self.world.actors[..self.world.actor_count]
            .iter_mut()
            .find(|actor| actor.id == actor_id)
        {
            if actor.location_id == location_id {
                return None;
            }
            from_location_id = Some(actor.location_id);
            actor.location_id = location_id;
        }
        if emit_event {
            from_location_id.map(|from| self.append_actor_moved_event(actor_id, from, location_id))
        } else {
            None
        }
    }

    #[cfg(test)]
    fn dialogue_branch_for(&self, actor_id: u64, target_actor_id: u64) -> Option<DialogueBranch> {
        let actor = self.actor_by_id(actor_id)?;
        let target = self.actor_by_id(target_actor_id)?;
        if actor.kind != CW_ACTOR_HUMAN
            || target.kind != CW_ACTOR_NPC
            || actor.location_id != target.location_id
        {
            return None;
        }

        let evolved = target.stats.level >= 2;
        let missing_need = (!evolved)
            .then(|| self.first_missing_evolution_item_name(target_actor_id))
            .flatten();

        let (prompt, options) = match target_actor_id {
            1001 => {
                let prompt = if let Some(item_name) = missing_need.as_deref() {
                    format!(
                        "Rati holds up the blue scarf. \"It wants one more thing: {item_name}. Shall I tell you why?\""
                    )
                } else {
                    "Rati folds the blue scarf over one paw. \"Which thread should we tug first?\""
                        .to_string()
                };
                (
                    prompt,
                    vec![
                        DialogueOption {
                            id: "need".to_string(),
                            label: if evolved { "ask story" } else { "ask need" }.to_string(),
                            content: if let Some(item_name) = missing_need.as_deref() {
                                format!("Rati, why does the scarf need {item_name}?")
                            } else {
                                "Rati, could you tell me a story about the cottage?".to_string()
                            },
                        },
                        DialogueOption {
                            id: "detail".to_string(),
                            label: "offer detail".to_string(),
                            content: "I noticed the rain-soft windows and the kettle song."
                                .to_string(),
                        },
                    ],
                )
            }
            1002 => {
                let prompt = if missing_need.is_some() {
                    "🌧️🧵✨🫧".to_string()
                } else {
                    "🌧️🫖✨".to_string()
                };
                (
                    prompt,
                    vec![
                        DialogueOption {
                            id: "need".to_string(),
                            label: if evolved { "ask weather" } else { "ask need" }.to_string(),
                            content: if let Some(item_name) = missing_need.as_deref() {
                                format!("Gust, do you need {item_name}?")
                            } else {
                                "Gust, how does the weather feel?".to_string()
                            },
                        },
                        DialogueOption {
                            id: "tea".to_string(),
                            label: "offer tea".to_string(),
                            content: "Gust, would tea help the rain?".to_string(),
                        },
                    ],
                )
            }
            1003 => {
                let prompt = if let Some(item_name) = missing_need.as_deref() {
                    format!("*Skull touches the floor near the doorway, then looks toward {item_name}.*")
                } else {
                    "*Skull lowers his head toward the low doorway.*".to_string()
                };
                (
                    prompt,
                    vec![
                        DialogueOption {
                            id: "need".to_string(),
                            label: if evolved { "listen" } else { "ask need" }.to_string(),
                            content: if let Some(item_name) = missing_need.as_deref() {
                                format!("Skull, do you need {item_name} for your watch?")
                            } else {
                                "Skull, what do you hear beyond the door?".to_string()
                            },
                        },
                        DialogueOption {
                            id: "thanks".to_string(),
                            label: "thank him".to_string(),
                            content: "Skull, thank you for watching the hearth.".to_string(),
                        },
                    ],
                )
            }
            _ => (
                "They wait for your choice.".to_string(),
                vec![DialogueOption {
                    id: "greet".to_string(),
                    label: "greet".to_string(),
                    content: format!(
                        "Hello, {}.",
                        self.actor_name(target_actor_id)
                            .unwrap_or_else(|| "friend".to_string())
                    ),
                }],
            ),
        };

        Some(DialogueBranch {
            id: actor_id
                .saturating_mul(10_000)
                .saturating_add(target_actor_id),
            actor_id,
            target_actor_id,
            expires_at_tick: self.world.tick.saturating_add(DIALOGUE_BRANCH_TTL_TICKS),
            prompt: prompt.to_string(),
            options,
        })
    }

    fn first_missing_evolution_item_name(&self, actor_id: u64) -> Option<String> {
        let track = seed_content()
            .evolution_tracks
            .iter()
            .find(|track| track.actor_id == actor_id)?;
        for requirement in &track.requirements {
            if !self.evolution_requirement_satisfied(requirement) {
                return self.item_name(requirement.item_id);
            }
        }
        None
    }

    fn evolution_requirement_satisfied(
        &self,
        requirement: &SeedEvolutionRequirementContent,
    ) -> bool {
        let Some(item) = self.item_by_id(requirement.item_id) else {
            return false;
        };
        match placement_target_kind_from_str(&requirement.target_kind) {
            Some(CW_PLACEMENT_ACTOR_HAND) => {
                item.holder_actor_id == requirement.target_id && item.location_id == 0
            }
            Some(CW_PLACEMENT_LOCATION_FLOOR) => {
                item.holder_actor_id == 0 && item.location_id == requirement.target_id
            }
            _ => false,
        }
    }

    fn room_cast_names(&self, location_id: u64) -> Vec<String> {
        self.world.actors[..self.world.actor_count]
            .iter()
            .filter(|actor| actor.location_id == location_id && actor.status == CW_ACTOR_ACTIVE)
            .filter_map(|actor| self.actor_name(actor.id))
            .collect()
    }

    fn has_active_resident_at(&self, location_id: u64) -> bool {
        self.world.actors[..self.world.actor_count]
            .iter()
            .any(|actor| {
                actor.kind == CW_ACTOR_NPC
                    && actor.status == CW_ACTOR_ACTIVE
                    && actor.location_id == location_id
            })
    }

    fn welcome_host_for(&self, location_id: u64) -> Option<CwActor> {
        if let Some(rati) = self
            .actor_by_id(RATI_ACTOR_ID)
            .filter(|actor| actor.kind == CW_ACTOR_NPC && actor.status == CW_ACTOR_ACTIVE)
        {
            if rati.location_id != location_id {
                return Some(rati);
            }
            return None;
        }
        if self.has_active_resident_at(location_id) {
            return None;
        }
        self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| actor.kind == CW_ACTOR_NPC && actor.status == CW_ACTOR_ACTIVE)
            .min_by_key(|actor| actor.id)
    }

    fn recent_room_lines(&self, location_id: u64, limit: usize) -> Vec<String> {
        let mut recent_lines: Vec<String> = self
            .event_log
            .iter()
            .rev()
            .filter(|event| {
                event.location_id == Some(location_id)
                    && event.type_name == "message.created"
                    && event.content.is_some()
            })
            .take(limit)
            .map(|event| {
                format!(
                    "{}: {}",
                    event
                        .actor_name
                        .clone()
                        .unwrap_or_else(|| "Someone".to_string()),
                    event.content.clone().unwrap_or_default()
                )
            })
            .collect();
        recent_lines.reverse();
        recent_lines
    }

    fn narrative_goal_lines(&self, actor_id: Option<u64>, location_id: u64) -> Vec<String> {
        let mut goals = Vec::new();
        if let Some(job) = self.active_job_for_location(location_id) {
            let progress = self
                .clocks
                .get(&job.progress_clock_id)
                .map(|clock| format!("progress {}/{}", clock.filled, clock.segments));
            let danger = self
                .clocks
                .get(&job.danger_clock_id)
                .map(|clock| format!("danger {}/{}", clock.filled, clock.segments));
            let clocks = [progress, danger].into_iter().flatten().collect::<Vec<_>>();
            let clock_note = if clocks.is_empty() {
                String::new()
            } else {
                format!(" ({})", clocks.join(", "))
            };
            goals.push(format!(
                "Project goal: {} Stakes: {}{}",
                job.premise, job.stakes, clock_note
            ));
            if let Some(question) = seed_content()
                .fronts
                .iter()
                .find(|front| {
                    front.job_ids.iter().any(|id| id == &job.id)
                        || front.location_ids.contains(&location_id)
                })
                .and_then(|front| front.stakes_questions.first())
            {
                goals.push(format!("Open story question: {question}"));
            }
        } else if let Some(front) = seed_content()
            .fronts
            .iter()
            .find(|front| front.status == "active" && front.location_ids.contains(&location_id))
        {
            goals.push(format!(
                "Local tension: {}; looming outcome: {}",
                front.premise, front.impending_outcome
            ));
        }

        if let Some(actor_id) = actor_id {
            let ledger = self.visit_ledger_view(actor_id);
            if ledger.unbanked_count > 0 {
                goals.push("Growth goal: keep what this visit taught you.".to_string());
            } else if ledger.advancement_points > 0 {
                goals.push(
                    "Growth goal: use your growth on a knack, a friendship, or what calls you."
                        .to_string(),
                );
            }
            if self.tired_tag_active(actor_id) {
                goals.push(
                    "Pacing goal: the avatar is tired and should recover before more exertion."
                        .to_string(),
                );
            }
        }

        goals.truncate(4);
        goals
    }

    fn avatar_chat_plan_for(&self, actor_id: u64, target_actor_id: u64) -> Option<AvatarChatPlan> {
        let actor = self.actor_by_id(actor_id)?;
        let target = self.actor_by_id(target_actor_id)?;
        if actor.kind != CW_ACTOR_HUMAN
            || actor.status != CW_ACTOR_ACTIVE
            || target.kind != CW_ACTOR_NPC
            || target.status != CW_ACTOR_ACTIVE
            || actor.location_id != target.location_id
        {
            return None;
        }
        let actor_meta = self.actors.get(&actor_id);
        let target_meta = self.actors.get(&target_actor_id);
        let missing_need = (target.stats.level < 2)
            .then(|| self.first_missing_evolution_item_name(target_actor_id))
            .flatten();
        let target_actor_name = self
            .actor_name(target_actor_id)
            .unwrap_or_else(|| format!("Actor {target_actor_id}"));
        let location_meta = self.location_meta_for(actor.location_id);
        let target_economy_note = self.resident_economy_prompt_note(target, Some(actor_id));
        let recent_lines = self.recent_room_lines(actor.location_id, 8);
        let fresh_subject = recent_lines
            .iter()
            .rev()
            .take(2)
            .find_map(|line| self.conversation_subject(line, target_actor_id));

        Some(AvatarChatPlan {
            location_id: actor.location_id,
            actor_name: self
                .actor_name(actor_id)
                .unwrap_or_else(|| format!("Actor {actor_id}")),
            actor_title: actor_meta
                .map(|meta| meta.title.clone())
                .filter(|title| !title.trim().is_empty())
                .unwrap_or_else(|| "traveler".to_string()),
            actor_description: actor_meta
                .map(|meta| meta.description.clone())
                .filter(|description| !description.trim().is_empty())
                .unwrap_or_else(|| "A quiet visitor in CosyWorld.".to_string()),
            target_actor_name,
            target_title: target_meta
                .map(|meta| meta.title.clone())
                .filter(|title| !title.trim().is_empty())
                .unwrap_or_else(|| "resident".to_string()),
            target_continuity: self.resident_continuity_for(target),
            target_economy_note,
            goals: self.narrative_goal_lines(Some(actor_id), actor.location_id),
            location_name: self
                .location_name(actor.location_id)
                .unwrap_or_else(|| "Unknown Location".to_string()),
            location_title: location_meta.title,
            location_description: location_meta.description,
            location_persona: location_meta.persona,
            location_memory: location_meta.memory,
            cast: self.room_cast_names(actor.location_id),
            recent_lines,
            fresh_subject,
            missing_need,
        })
    }

    fn resident_reply_plan_for_target(
        &self,
        speaker_actor_id: u64,
        target_actor_id: u64,
        text: &str,
    ) -> Option<ResidentReplyPlan> {
        self.resident_reply_plan_for_target_with_context(speaker_actor_id, target_actor_id, text)
    }

    fn conversation_subject(&self, text: &str, npc_actor_id: u64) -> Option<String> {
        let lowered = text.to_lowercase();
        let longest_match = |values: Vec<String>| {
            values
                .into_iter()
                .filter(|value| {
                    let candidate = value.trim();
                    candidate.chars().count() >= 3 && lowered.contains(&candidate.to_lowercase())
                })
                .max_by_key(|value| value.chars().count())
        };

        longest_match(self.items.values().map(|item| item.name.clone()).collect())
            .or_else(|| longest_match(self.locations.values().cloned().collect()))
            .or_else(|| {
                longest_match(
                    self.actors
                        .iter()
                        .filter(|(actor_id, _)| **actor_id != npc_actor_id)
                        .map(|(_, actor)| actor.name.clone())
                        .collect(),
                )
            })
    }

    fn card_reaction_event<'a>(
        &self,
        speaker_actor_id: u64,
        events: &'a [EventView],
    ) -> Option<&'a EventView> {
        let belongs_to_player =
            |event: &&EventView| event.success && event.actor_id == Some(speaker_actor_id);
        events
            .iter()
            .filter(belongs_to_player)
            .find(|event| {
                matches!(
                    event.type_name.as_str(),
                    "actor.created"
                        | "actor.moved"
                        | "ability_check.rolled"
                        | "location.searched"
                        | "feature.searched"
                        | "exit.discovered"
                        | "avatar.discovered"
                        | "item.picked_up"
                        | "item.dropped"
                        | "item.used"
                        | "item.given"
                        | "item.traded"
                        | "combat.attack.attempt"
                        | "combat.attack.hit"
                        | "combat.attack.miss"
                        | "combat.defend"
                        | "combat.flee.success"
                        | "clock.updated"
                        | "job.updated"
                        | "ledger.banked"
                        | "calling.set"
                        | "calling.revised"
                        | "skill.stepped"
                ) || (matches!(event.type_name.as_str(), "tag.applied" | "tag.cleared")
                    && matches!(event.tag_label.as_deref(), Some("prepared") | Some("tired")))
            })
            .or_else(|| events.iter().find(belongs_to_player))
    }

    fn card_reaction_subject(&self, event: &EventView) -> Option<String> {
        let named = |value: Option<&str>| {
            value
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(ToString::to_string)
        };
        match event.type_name.as_str() {
            "actor.created" | "actor.moved" | "combat.flee.success" => named(
                event
                    .destination_location_name
                    .as_deref()
                    .or(event.location_name.as_deref()),
            ),
            "ability_check.rolled" | "location.searched" => named(event.location_name.as_deref()),
            "feature.searched" => event
                .content
                .as_deref()
                .and_then(|content| content.split(':').next())
                .and_then(|feature| named(Some(feature))),
            "exit.discovered" => named(event.destination_location_name.as_deref()),
            "avatar.discovered" => named(event.target_actor_name.as_deref()),
            "item.picked_up" | "item.dropped" | "item.used" | "item.given" => {
                named(event.item_name.as_deref())
            }
            "item.traded" => {
                let offered = named(event.item_name.as_deref());
                let received = named(event.target_item_name.as_deref());
                match (offered, received) {
                    (Some(offered), Some(received)) => Some(format!("{offered} and {received}")),
                    (offered, received) => offered.or(received),
                }
            }
            "combat.attack.attempt" | "combat.attack.hit" | "combat.attack.miss" => {
                named(event.target_actor_name.as_deref())
            }
            "clock.updated" => named(event.clock_label.as_deref()),
            "job.updated" => Some("the room's shared work".to_string()),
            "ledger.banked" => Some("what you learned".to_string()),
            "calling.set" | "calling.revised" => Some("your new purpose".to_string()),
            "skill.stepped" => event
                .content
                .as_deref()
                .and_then(|content| content.split(':').next())
                .and_then(skill_label)
                .map(|label| format!("your {label} practice")),
            "tag.applied" if event.tag_label.as_deref() == Some("prepared") => {
                Some("your careful plan".to_string())
            }
            "tag.cleared" if event.tag_label.as_deref() == Some("tired") => {
                Some("that proper breath".to_string())
            }
            _ => None,
        }
    }

    fn card_reaction_action_text(&self, actor_name: &str, event: &EventView) -> String {
        let subject = self.card_reaction_subject(event);
        match event.type_name.as_str() {
            "actor.created" | "actor.moved" => format!(
                "{actor_name} just arrived in {}.",
                subject.as_deref().unwrap_or("the room")
            ),
            "ability_check.rolled" => format!(
                "{actor_name} listened carefully to {} and caught a clue.",
                subject.as_deref().unwrap_or("the room")
            ),
            "feature.searched" => {
                let detail = event
                    .content
                    .as_deref()
                    .and_then(|content| content.splitn(3, ':').nth(1))
                    .map(str::trim)
                    .filter(|detail| !detail.is_empty());
                match detail {
                    Some(detail) => format!(
                        "{actor_name} searched {} and noticed: {detail}",
                        subject.as_deref().unwrap_or("a room feature")
                    ),
                    None => format!(
                        "{actor_name} searched {} and found a clue.",
                        subject.as_deref().unwrap_or("the room")
                    ),
                }
            }
            "location.searched" => format!(
                "{actor_name} searched {} and brought a clue to light.",
                subject.as_deref().unwrap_or("the room")
            ),
            "exit.discovered" => format!(
                "{actor_name} found a new path to {}.",
                subject.as_deref().unwrap_or("somewhere new")
            ),
            "avatar.discovered" => format!(
                "{actor_name} noticed {} hiding nearby.",
                subject.as_deref().unwrap_or("someone")
            ),
            "item.picked_up" => format!(
                "{actor_name} picked up {}.",
                subject.as_deref().unwrap_or("a keepsake")
            ),
            "item.dropped" => format!(
                "{actor_name} set {} down for the room to find.",
                subject.as_deref().unwrap_or("a keepsake")
            ),
            "item.used" => format!(
                "{actor_name} used {}.",
                subject.as_deref().unwrap_or("a keepsake")
            ),
            "item.given" => format!(
                "{actor_name} gave {} to {}.",
                subject.as_deref().unwrap_or("a keepsake"),
                event.target_actor_name.as_deref().unwrap_or("a neighbour")
            ),
            "item.traded" => format!(
                "{actor_name} traded {} with {}.",
                subject.as_deref().unwrap_or("two keepsakes"),
                event.target_actor_name.as_deref().unwrap_or("a neighbour")
            ),
            "combat.attack.attempt" | "combat.attack.hit" | "combat.attack.miss" => format!(
                "{actor_name} faced {} in the scuffle.",
                subject.as_deref().unwrap_or("the danger")
            ),
            "combat.defend" => format!("{actor_name} stood their ground."),
            "combat.flee.success" => format!(
                "{actor_name} hurried safely into {}.",
                subject.as_deref().unwrap_or("the next room")
            ),
            "clock.updated" => format!(
                "{actor_name} helped {} along.",
                subject.as_deref().unwrap_or("the room's shared work")
            ),
            "job.updated" => {
                format!("{actor_name} brought the room's shared work to a turning point.")
            }
            "ledger.banked" => format!("{actor_name} grew from what the visit taught them."),
            "calling.set" | "calling.revised" => {
                format!("{actor_name} chose a new purpose to follow.")
            }
            "skill.stepped" => format!(
                "{actor_name} practiced {}.",
                subject.as_deref().unwrap_or("a new knack")
            ),
            "tag.applied" if event.tag_label.as_deref() == Some("prepared") => {
                format!("{actor_name} made the next try count.")
            }
            "tag.cleared" if event.tag_label.as_deref() == Some("tired") => {
                format!("{actor_name} took a proper breath.")
            }
            _ => format!("{actor_name} played a card and changed the room a little."),
        }
    }

    fn next_resident_card_reaction_plan(
        &self,
        speaker_actor_id: u64,
        events: &[EventView],
    ) -> Option<ResidentReplyPlan> {
        if events.iter().any(|event| {
            matches!(
                event.type_name.as_str(),
                "bond.created" | "bond.revised" | "bond.resolved"
            )
        }) {
            return None;
        }
        let speaker = self.actor_by_id(speaker_actor_id)?;
        if speaker.kind != CW_ACTOR_HUMAN || speaker.status != CW_ACTOR_ACTIVE {
            return None;
        }
        let actor_name = self
            .actor_name(speaker_actor_id)
            .unwrap_or_else(|| "The visitor".to_string());
        let reaction_event = self.card_reaction_event(speaker_actor_id, events)?;
        let action_text = self.card_reaction_action_text(&actor_name, reaction_event);
        let mut residents = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| {
                actor.kind == CW_ACTOR_NPC
                    && actor.status == CW_ACTOR_ACTIVE
                    && actor.location_id == speaker.location_id
            })
            .collect::<Vec<_>>();
        residents.sort_by_key(|actor| {
            let dex = seed_content()
                .cards
                .iter()
                .position(|card| card.subject_kind == "actor" && card.subject_id == actor.id)
                .unwrap_or(usize::MAX);
            (dex, actor.id)
        });
        if residents.is_empty() {
            return None;
        }
        let latest_resident_speaker = self.event_log.iter().rev().find_map(|event| {
            if event.type_name != "message.created"
                || event.location_id != Some(speaker.location_id)
            {
                return None;
            }
            event.actor_id.filter(|actor_id| {
                self.actor_by_id(*actor_id)
                    .is_some_and(|actor| actor.kind == CW_ACTOR_NPC)
            })
        });
        let target = latest_resident_speaker
            .and_then(|actor_id| residents.iter().position(|actor| actor.id == actor_id))
            .map(|index| residents[(index + 1) % residents.len()])
            .unwrap_or(residents[0]);
        self.resident_reply_plan_for_target_with_context(speaker_actor_id, target.id, &action_text)
    }

    fn resident_reply_plan_for_target_with_context(
        &self,
        speaker_actor_id: u64,
        target_actor_id: u64,
        text: &str,
    ) -> Option<ResidentReplyPlan> {
        let speaker = self.actor_by_id(speaker_actor_id)?;
        let npc = self.actor_by_id(target_actor_id)?;
        if speaker.kind != CW_ACTOR_HUMAN
            || speaker.status != CW_ACTOR_ACTIVE
            || npc.kind != CW_ACTOR_NPC
            || npc.status != CW_ACTOR_ACTIVE
            || speaker.location_id != npc.location_id
        {
            return None;
        }
        let npc_meta = self.actors.get(&target_actor_id);
        let location_meta = self.location_meta_for(npc.location_id);
        let economy_note = self.resident_economy_prompt_note(npc, Some(speaker_actor_id));
        Some(ResidentReplyPlan {
            npc_actor_id: target_actor_id,
            npc_name: self
                .actor_name(target_actor_id)
                .unwrap_or_else(|| format!("Actor {target_actor_id}")),
            speech_mode: npc_meta
                .map(|meta| meta.speech_mode.clone())
                .unwrap_or_else(|| "prose".to_string()),
            resident_continuity: self.resident_continuity_for(npc),
            economy_note,
            goals: self.narrative_goal_lines(Some(speaker_actor_id), npc.location_id),
            location_name: self
                .location_name(npc.location_id)
                .unwrap_or_else(|| "Unknown Location".to_string()),
            location_title: location_meta.title,
            location_description: location_meta.description,
            location_persona: location_meta.persona,
            location_memory: location_meta.memory,
            cast: self.room_cast_names(npc.location_id),
            recent_lines: self.recent_room_lines(npc.location_id, 8),
            user_text: text.to_string(),
            caused_by_event_seq: None,
            source_world_tick: None,
            observed_through_seq: None,
            source_location_id: None,
        })
    }

    fn ripple_context_for_player_turn(
        &self,
        source_actor_id: u64,
        source_action_kind: u8,
        events: &[EventView],
    ) -> Option<RippleContext> {
        let source_actor = self.actor_by_id(source_actor_id)?;
        if source_actor.kind != CW_ACTOR_HUMAN || source_actor.status != CW_ACTOR_ACTIVE {
            return None;
        }

        let source_event_seqs = events
            .iter()
            .filter(|event| event.success && event.actor_id == Some(source_actor_id))
            .map(|event| event.seq)
            .collect::<Vec<_>>();
        if source_event_seqs.is_empty() {
            return None;
        }

        let mut affected_location_ids = BTreeSet::new();
        for event in events.iter().filter(|event| event.success) {
            if event.actor_id != Some(source_actor_id)
                && event.target_actor_id != Some(source_actor_id)
                && !matches!(
                    event.type_name.as_str(),
                    "clock.updated" | "tag.applied" | "tag.cleared" | "job.updated"
                )
            {
                continue;
            }
            if let Some(location_id) = event.location_id {
                affected_location_ids.insert(location_id);
            }
            if let Some(location_id) = event.destination_location_id {
                affected_location_ids.insert(location_id);
            }
            if event.clock_scope.as_deref() == Some("room") {
                if let Some(location_id) = event.clock_scope_id {
                    affected_location_ids.insert(location_id);
                }
            }
            if event.tag_scope.as_deref() == Some("room") {
                if let Some(location_id) = event.tag_scope_id {
                    affected_location_ids.insert(location_id);
                }
            }
        }
        affected_location_ids.insert(source_actor.location_id);
        if affected_location_ids.is_empty() {
            return None;
        }

        let source_location_id = events
            .iter()
            .find(|event| event.success && event.actor_id == Some(source_actor_id))
            .and_then(|event| event.location_id)
            .or_else(|| affected_location_ids.iter().next().copied());
        let zone = if affected_location_ids
            .iter()
            .any(|location_id| self.location_is_frontier(*location_id))
        {
            ZONE_FRONTIER.to_string()
        } else {
            ZONE_SANCTUARY.to_string()
        };
        let budget = RippleBudget::for_zone_and_action(&zone, source_action_kind);

        Some(RippleContext {
            source_actor_id,
            source_action_kind,
            source_event_seqs,
            source_location_id,
            affected_location_ids,
            zone,
            budget,
        })
    }

    fn resident_ripple_actor(&self, context: &RippleContext) -> Option<CwActor> {
        let candidates: Vec<CwActor> = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| {
                actor.kind == CW_ACTOR_NPC
                    && actor.status == CW_ACTOR_ACTIVE
                    && context.affected_location_ids.contains(&actor.location_id)
            })
            .collect();
        if candidates.is_empty() {
            return None;
        }

        Some(candidates[(self.world.tick as usize) % candidates.len()])
    }

    #[cfg(test)]
    fn ambient_actor(&self) -> Option<CwActor> {
        let human_locations: BTreeSet<u64> = self.world.actors[..self.world.actor_count]
            .iter()
            .filter(|actor| actor.kind == CW_ACTOR_HUMAN && actor.status == CW_ACTOR_ACTIVE)
            .map(|actor| actor.location_id)
            .collect();
        if human_locations.is_empty() {
            return None;
        }

        let candidates: Vec<CwActor> = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| {
                actor.kind == CW_ACTOR_NPC
                    && actor.status == CW_ACTOR_ACTIVE
                    && seed_actor_allows_ambient_autonomy(actor.id)
                    && human_locations.contains(&actor.location_id)
            })
            .collect();
        if candidates.is_empty() {
            return None;
        }

        Some(candidates[(self.world.tick as usize) % candidates.len()])
    }

