async fn request_ai_avatar_chat(
    config: &AiConfig,
    plan: &AvatarChatPlan,
    followup: bool,
) -> Result<String, AiGatewayError> {
    let recent_lines = if followup {
        let start = plan.recent_lines.len().saturating_sub(2);
        &plan.recent_lines[start..]
    } else {
        &plan.recent_lines[..]
    };
    let recent = if recent_lines.is_empty() {
        "No recent room dialogue.".to_string()
    } else {
        recent_lines.join("\n")
    };
    let location_memory = format_location_memory(&plan.location_memory);
    let goals = format_goal_lines(&plan.goals);
    let target_continuity = format_resident_continuity(&plan.target_continuity);
    let need = if followup {
        "Do not introduce a resident need or item that is absent from the freshest exchange."
            .to_string()
    } else {
        plan.missing_need
            .as_ref()
            .map(|item| format!("The resident may currently need: {item}."))
            .unwrap_or_else(|| "No current resident item need is known.".to_string())
    };
    let target_economy = if followup {
        "Do not revive an older request, trade, or item topic.".to_string()
    } else {
        plan.target_economy_note.clone()
    };
    let fresh_subject = plan
        .fresh_subject
        .as_deref()
        .map(|subject| format!("Fresh conversation subject: {subject}. Stay on it."))
        .unwrap_or_else(|| "Follow only the freshest resident line.".to_string());
    let system = if followup {
        "You write the player avatar's brief follow-up in an ongoing cozy conversation. Respond directly to the freshest resident line and continue only its current subject. Never introduce an item, request, goal, or place that is absent from the two freshest lines. Keep one concrete room detail in play and leave a small closing hook. Do not restart the conversation. The human operator is silent; do not mention the user, buttons, UI, AI, prompts, policies, tools, or models. Do not speak for the resident. Keep it under 28 words."
    } else {
        "You write one in-character line for the player avatar after the human presses Chat. Make the line feel intentionally authored: use one concrete detail from the room, recent dialogue, or the target resident's continuity/current need, and give the resident an easy hook to answer. The human operator is silent; do not mention the user, buttons, UI, AI, prompts, policies, tools, or models. Do not speak for the resident. Keep it under 34 words."
    };
    let user = format!(
        "Avatar: {name} / {title}\nAvatar description: {description}\nLocation: {location} / {location_title}\nLocation description: {location_description}\nLocation persona: {location_persona}\nLocation memory:\n{location_memory}\nCurrent goals:\n{goals}\nTarget resident: {target} / {target_title}\nTarget continuity:\n{target_continuity}\nTarget economy:\n{target_economy}\nCast present: {cast}\n{need}\n{fresh_subject}\nRecent room lines:\n{recent}\nWrite only the avatar's next spoken line.",
        name = plan.actor_name,
        title = plan.actor_title,
        description = plan.actor_description,
        location = plan.location_name,
        location_title = plan.location_title,
        location_description = plan.location_description,
        location_persona = plan.location_persona,
        location_memory = location_memory,
        goals = goals,
        target = plan.target_actor_name,
        target_title = plan.target_title,
        target_continuity = target_continuity,
        target_economy = target_economy,
        cast = plan.cast.join(", "),
        need = need,
        fresh_subject = fresh_subject,
        recent = recent,
    );

    request_chat_completion(
        config,
        ChatCompletionRequest {
            feature: if followup {
                "dialogue_avatar_followup"
            } else {
                "dialogue_avatar"
            },
            system,
            user: &user,
            temperature: 0.8,
            max_tokens: 70,
            timeout: Duration::from_secs(12),
            max_attempts: 2,
            referer: "http://127.0.0.1:3102",
            response_format: None,
        },
    )
    .await
    .map(|completion| completion.text)
}

async fn request_ai_avatar_identity(
    config: &AiConfig,
    actor_id: u64,
) -> Result<GeneratedAvatarIdentity, String> {
    let fallback = fallback_avatar_identity(actor_id);
    let system = "You generate compact JSON for a player avatar in a cozy shared MUD. Every identity must feel warm, playful, and safe to meet. Output valid JSON only. Do not mention AI, prompts, models, policies, tools, wallets, NFTs, or UI.";
    let user = format!(
        "Create one new CosyWorld player avatar for The Cosy Cottage.\n\
         Tone: grounded, gentle storybook comedy - a character with one small fondness, one harmless habit, and one slightly impractical plan. Mischief may be clumsy or curious but never hungry, hostile, cruel, threatening, or mean. Do not use grudges, schemes, insults, weapons, danger, or villain language.\n\
         Avoid existing resident names: Rati, Gust, Skull, Coach, Badger, Toad.\n\
         Output exactly this shape: {{\"name\":\"Two words, 28 chars max, ASCII letters/spaces/hyphen/apostrophe only\",\"title\":\"warm portable card epithet, 2-5 words and 36 chars max; never include a location or the words The Cosy Cottage\",\"description\":\"one warm third-person persona sentence about a fondness, habit, or curiosity, 220 chars max\",\"visual_prompt\":\"image-generation prompt for a full-body cozy fantasy avatar portrait, 360 chars max\"}}\n\
         If unsure, use this fallback as inspiration but do not copy it exactly: {name} / {title} / {description}",
        name = fallback.name,
        title = fallback.title,
        description = fallback.description,
    );

    let completion = request_chat_completion(
        config,
        ChatCompletionRequest {
            feature: "avatar_identity",
            system,
            user: &user,
            temperature: 1.0,
            max_tokens: 240,
            timeout: Duration::from_secs(14),
            max_attempts: 2,
            referer: "https://cosyworld.fly.dev",
            response_format: None,
        },
    )
    .await
    .map_err(|error| error.to_string())?;
    parse_avatar_identity_json(&completion.text, actor_id)
        .ok_or_else(|| "AI avatar identity response was not usable JSON".to_string())
}

async fn generate_and_store_avatar_art(
    config: &ReplicateAvatarArtConfig,
    generated_asset_dir: &Path,
    actor_id: u64,
    identity: &GeneratedAvatarIdentity,
) -> Result<(), String> {
    let image = request_replicate_avatar_art(config, identity).await?;
    let path = stored_avatar_image_path(generated_asset_dir, actor_id);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::write(&path, image.bytes).map_err(|error| error.to_string())?;
    fs::write(
        stored_avatar_content_type_path(generated_asset_dir, actor_id),
        image.content_type,
    )
    .map_err(|error| error.to_string())?;
    Ok(())
}

fn schedule_avatar_art_generation(
    state: &AppState,
    actor_id: u64,
    identity: GeneratedAvatarIdentity,
) {
    let Some(config) = state.avatar_art_config.as_ref().clone() else {
        return;
    };
    if let Ok(mut jobs) = state.avatar_art_jobs.lock() {
        if !jobs.insert(actor_id) {
            return;
        }
    }
    let generated_asset_dir = state.generated_asset_dir.clone();
    let jobs = state.avatar_art_jobs.clone();
    tokio::spawn(async move {
        if let Err(error) =
            generate_and_store_avatar_art(&config, &generated_asset_dir, actor_id, &identity).await
        {
            warn!(
                "Replicate avatar art generation failed for actor {}: {}",
                actor_id, error
            );
        }
        if let Ok(mut jobs) = jobs.lock() {
            jobs.remove(&actor_id);
        }
    });
}

async fn generate_and_store_pathway_art(
    config: &ReplicateAvatarArtConfig,
    generated_asset_dir: &Path,
    location_id: u64,
    art_prompt: &str,
) -> Result<(), String> {
    let prompt_prefix = std::env::var("COSYWORLD_REPLICATE_PATHWAY_PROMPT_PREFIX")
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "mirquo style, cozy storybook landscape".to_string());
    let prompt = compact_whitespace(&format!(
        "{prompt_prefix}, {art_prompt}. Wide establishing landscape, no character portrait, no text, no logo, no watermark."
    ));
    let image = request_replicate_art(config, prompt, "16:9").await?;
    let path = stored_pathway_image_path(generated_asset_dir, location_id);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::write(&path, image.bytes).map_err(|error| error.to_string())?;
    fs::write(
        stored_pathway_content_type_path(generated_asset_dir, location_id),
        image.content_type,
    )
    .map_err(|error| error.to_string())?;
    Ok(())
}

fn pathway_art_targets(mutation: &ProjectionMutation) -> Vec<(u64, String)> {
    let ProjectionMutation::JourneyTransition {
        pathway,
        reveal_edges,
        ..
    } = mutation
    else {
        return Vec::new();
    };
    if !pathway.art_eligible || !pathway.familiar {
        return Vec::new();
    }
    let revealed_location_ids = reveal_edges
        .iter()
        .map(|(_from, to)| *to)
        .filter(|location_id| *location_id >= GENERATED_PATHWAY_LOCATION_ID_BASE)
        .collect::<BTreeSet<_>>();
    pathway
        .waypoints
        .iter()
        .filter(|waypoint| revealed_location_ids.contains(&waypoint.id))
        .filter_map(|waypoint| {
            waypoint
                .meta
                .art_prompt
                .as_ref()
                .map(|prompt| (waypoint.id, prompt.clone()))
        })
        .collect()
}

fn schedule_pathway_art_generation(state: &AppState, targets: Vec<(u64, String)>) {
    let Some(config) = state.avatar_art_config.as_ref().clone() else {
        return;
    };
    for (location_id, prompt) in targets {
        if stored_pathway_image_path(&state.generated_asset_dir, location_id).exists() {
            continue;
        }
        if let Ok(mut jobs) = state.avatar_art_jobs.lock() {
            if !jobs.insert(location_id) {
                continue;
            }
        }
        let generated_asset_dir = state.generated_asset_dir.clone();
        let jobs = state.avatar_art_jobs.clone();
        let config = config.clone();
        tokio::spawn(async move {
            if let Err(error) =
                generate_and_store_pathway_art(&config, &generated_asset_dir, location_id, &prompt)
                    .await
            {
                warn!(
                    "Replicate pathway art generation failed for location {}: {}",
                    location_id, error
                );
            }
            if let Ok(mut jobs) = jobs.lock() {
                jobs.remove(&location_id);
            }
        });
    }
}

const MAX_REPLICATE_AVATAR_IMAGE_BYTES: u64 = 8 * 1024 * 1024;

async fn request_replicate_avatar_art(
    config: &ReplicateAvatarArtConfig,
    identity: &GeneratedAvatarIdentity,
) -> Result<DownloadedReplicateImage, String> {
    let prompt = compact_whitespace(&format!(
        "{prefix}, {visual}. Character name: {name}. Title: {title}. No text, no logo, no watermark.",
        prefix = config.prompt_prefix,
        visual = identity.visual_prompt,
        name = identity.name,
        title = identity.title,
    ));
    request_replicate_art(config, prompt, "2:3").await
}

async fn request_replicate_art(
    config: &ReplicateAvatarArtConfig,
    prompt: String,
    aspect_ratio: &str,
) -> Result<DownloadedReplicateImage, String> {
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(90))
        .build()
        .map_err(|error| error.to_string())?;
    let mut input = replicate_avatar_input(config)?;
    input.insert("prompt".to_string(), serde_json::Value::String(prompt));
    input.insert(
        "output_format".to_string(),
        serde_json::Value::String(config.output_format.clone()),
    );
    input
        .entry("aspect_ratio".to_string())
        .or_insert_with(|| serde_json::Value::String(aspect_ratio.to_string()));
    input
        .entry("num_outputs".to_string())
        .or_insert_with(|| serde_json::Value::Number(1.into()));
    if let Some(lora_url) = config.lora_url.as_deref() {
        input.insert(
            config.lora_input_key.clone(),
            serde_json::Value::String(lora_url.to_string()),
        );
        if let Some(scale) = serde_json::Number::from_f64(config.lora_scale) {
            input.insert(
                config.lora_scale_input_key.clone(),
                serde_json::Value::Number(scale),
            );
        }
    }

    let (url, body) = if let Some(version) = config.version.as_deref() {
        (
            "https://api.replicate.com/v1/predictions".to_string(),
            serde_json::json!({ "version": version, "input": input }),
        )
    } else {
        (
            format!(
                "https://api.replicate.com/v1/models/{}/predictions",
                config.model
            ),
            serde_json::json!({ "input": input }),
        )
    };

    let mut prediction = client
        .post(url)
        .bearer_auth(&config.api_token)
        .header("Prefer", "wait=30")
        .json(&body)
        .send()
        .await
        .map_err(|error| error.to_string())?
        .error_for_status()
        .map_err(|error| error.to_string())?
        .json::<serde_json::Value>()
        .await
        .map_err(|error| error.to_string())?;

    for _ in 0..30 {
        if let Some(output_url) = replicate_output_url(&prediction) {
            return download_replicate_image(&client, &output_url).await;
        }
        let status = prediction
            .get("status")
            .and_then(|value| value.as_str())
            .unwrap_or("");
        if matches!(status, "failed" | "canceled") {
            let error = prediction
                .get("error")
                .and_then(|value| value.as_str())
                .unwrap_or("prediction failed");
            return Err(error.to_string());
        }
        let Some(get_url) = prediction
            .get("urls")
            .and_then(|urls| urls.get("get"))
            .and_then(|value| value.as_str())
            .map(ToString::to_string)
        else {
            return Err("Replicate prediction did not include a poll URL".to_string());
        };
        validate_replicate_api_url(&get_url)?;
        tokio::time::sleep(Duration::from_secs(2)).await;
        prediction = client
            .get(get_url)
            .bearer_auth(&config.api_token)
            .send()
            .await
            .map_err(|error| error.to_string())?
            .error_for_status()
            .map_err(|error| error.to_string())?
            .json::<serde_json::Value>()
            .await
            .map_err(|error| error.to_string())?;
    }
    Err("Replicate art prediction timed out".to_string())
}

fn replicate_avatar_input(
    config: &ReplicateAvatarArtConfig,
) -> Result<serde_json::Map<String, serde_json::Value>, String> {
    let mut input = match std::env::var("COSYWORLD_REPLICATE_AVATAR_INPUT_JSON") {
        Ok(value) if !value.trim().is_empty() => {
            match serde_json::from_str::<serde_json::Value>(&value) {
                Ok(serde_json::Value::Object(map)) => map,
                Ok(_) => {
                    return Err(
                        "COSYWORLD_REPLICATE_AVATAR_INPUT_JSON must be a JSON object".to_string(),
                    );
                }
                Err(error) => return Err(error.to_string()),
            }
        }
        _ => serde_json::Map::new(),
    };
    if config.version.is_some() {
        input.remove("version");
    }
    Ok(input)
}

fn replicate_output_url(prediction: &serde_json::Value) -> Option<String> {
    match prediction.get("output")? {
        serde_json::Value::String(url) => Some(url.clone()),
        serde_json::Value::Array(values) => values
            .iter()
            .find_map(|value| value.as_str().map(ToString::to_string)),
        serde_json::Value::Object(map) => map
            .get("url")
            .and_then(|value| value.as_str())
            .map(ToString::to_string)
            .or_else(|| {
                map.values()
                    .find_map(|value| value.as_str().map(ToString::to_string))
            }),
        _ => None,
    }
}

async fn download_replicate_image(
    client: &reqwest::Client,
    output_url: &str,
) -> Result<DownloadedReplicateImage, String> {
    let url = validate_replicate_output_url(output_url)?;
    let response = client
        .get(url)
        .send()
        .await
        .map_err(|error| error.to_string())?
        .error_for_status()
        .map_err(|error| error.to_string())?;
    if response
        .content_length()
        .is_some_and(|len| len > MAX_REPLICATE_AVATAR_IMAGE_BYTES)
    {
        return Err("Replicate avatar image was too large".to_string());
    }
    let content_type = response
        .headers()
        .get(header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .unwrap_or("");
    let content_type = replicate_image_content_type(content_type, output_url)?;
    let bytes = response
        .bytes()
        .await
        .map(|bytes| bytes.to_vec())
        .map_err(|error| error.to_string())?;
    if bytes.len() as u64 > MAX_REPLICATE_AVATAR_IMAGE_BYTES {
        return Err("Replicate avatar image was too large".to_string());
    }
    Ok(DownloadedReplicateImage {
        bytes,
        content_type,
    })
}

fn validate_replicate_api_url(value: &str) -> Result<reqwest::Url, String> {
    let url = parse_https_url(value)?;
    let host = url
        .host_str()
        .map(|host| host.to_ascii_lowercase())
        .ok_or_else(|| "Replicate API URL did not include a host".to_string())?;
    if host == "api.replicate.com" {
        Ok(url)
    } else {
        Err(format!("unexpected Replicate API host: {host}"))
    }
}

fn validate_replicate_output_url(value: &str) -> Result<reqwest::Url, String> {
    let url = parse_https_url(value)?;
    let host = url
        .host_str()
        .map(|host| host.to_ascii_lowercase())
        .ok_or_else(|| "Replicate output URL did not include a host".to_string())?;
    if host == "replicate.delivery" || host.ends_with(".replicate.delivery") {
        Ok(url)
    } else {
        Err(format!("unexpected Replicate output host: {host}"))
    }
}

fn parse_https_url(value: &str) -> Result<reqwest::Url, String> {
    let url = reqwest::Url::parse(value).map_err(|error| error.to_string())?;
    if url.scheme() != "https" {
        return Err("Replicate URL must use https".to_string());
    }
    Ok(url)
}

fn replicate_image_content_type(header_value: &str, output_url: &str) -> Result<String, String> {
    let content_type = header_value
        .split(';')
        .next()
        .unwrap_or("")
        .trim()
        .to_ascii_lowercase();
    if is_safe_image_content_type(&content_type) {
        return Ok(content_type);
    }
    if output_url.contains(".png") {
        return Ok("image/png".to_string());
    }
    if output_url.contains(".webp") {
        return Ok("image/webp".to_string());
    }
    if output_url.contains(".jpg") || output_url.contains(".jpeg") {
        return Ok("image/jpeg".to_string());
    }
    Err(format!(
        "Replicate output was not an image: {}",
        header_value.trim()
    ))
}

async fn request_ai_resident_intent(
    config: &AiConfig,
    plan: &ResidentReplyPlan,
) -> Result<ResidentIntentProposal, AiGatewayError> {
    let system = resident_system_prompt(plan);
    let recent = if plan.recent_lines.is_empty() {
        "No recent room dialogue.".to_string()
    } else {
        plan.recent_lines.join("\n")
    };
    let location_memory = format_location_memory(&plan.location_memory);
    let goals = format_goal_lines(&plan.goals);
    let resident_continuity = format_resident_continuity(&plan.resident_continuity);
    let user = format!(
        "Location: {location} / {location_title}\nLocation description: {location_description}\nLocation persona: {location_persona}\nLocation memory:\n{location_memory}\nCurrent goals:\n{goals}\nResident continuity:\n{resident_continuity}\nResident economy:\n{economy_note}\nCast present: {cast}\nRecent room lines:\n{recent}\nHuman line to respond to:\n{line}\nReply contract: answer that line's actual question or proposal before adding a new hook. If it names a concrete item or place, repeat that name so the conversation cannot silently change subjects.\nReturn valid JSON only with this shape:\n{{\"speech\":\"one visible reply from {name}\",\"intent\":\"what {name} is trying next, or null\",\"belief\":\"what {name} now believes, or null\",\"desire\":\"what {name} wants, or null\",\"promise\":\"what {name} commits to, or null\",\"refusal\":\"what {name} refuses, or null\",\"proposed_action\":{{\"kind\":\"wait|speak|move|pick_up|drop|give|trade|use|search|refuse\",\"target_actor_id\":null,\"item_id\":null,\"destination_location_id\":null,\"reason\":\"why this action follows\"}}}}\nUse null for unknown optional fields. The kernel has not accepted proposed_action yet, so do not claim it already happened.",
        location = plan.location_name,
        location_title = plan.location_title,
        location_description = plan.location_description,
        location_persona = plan.location_persona,
        location_memory = location_memory,
        goals = goals,
        resident_continuity = resident_continuity,
        economy_note = plan.economy_note,
        cast = plan.cast.join(", "),
        recent = recent,
        line = plan.user_text,
        name = plan.npc_name
    );

    let response_format = serde_json::json!({ "type": "json_object" });
    let completion = request_chat_completion(
        config,
        ChatCompletionRequest {
            feature: "dialogue_resident",
            system: &system,
            user: &user,
            temperature: 0.75,
            max_tokens: 160,
            timeout: Duration::from_secs(8),
            max_attempts: 2,
            referer: "http://127.0.0.1:3102",
            response_format: Some(&response_format),
        },
    )
    .await?;
    parse_resident_intent_json(&completion.text, plan).ok_or_else(|| {
        AiGatewayError::invalid_response("AI resident intent response was not usable JSON")
    })
}

fn format_location_memory(memory: &[String]) -> String {
    if memory.is_empty() {
        return "No fixed location memories.".to_string();
    }
    memory
        .iter()
        .filter_map(|line| {
            let line = line.trim();
            (!line.is_empty()).then(|| format!("- {line}"))
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn format_goal_lines(goals: &[String]) -> String {
    if goals.is_empty() {
        return "No active player-facing goal is currently highlighted.".to_string();
    }
    goals
        .iter()
        .filter_map(|goal| {
            let goal = goal.trim();
            (!goal.is_empty()).then(|| format!("- {goal}"))
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn sanitize_continuity_note_text(value: Option<&str>) -> Option<String> {
    let text = compact_whitespace(value?.trim().trim_matches('"'));
    if text.is_empty() {
        return None;
    }
    let lowered = format!(" {} ", text.to_lowercase());
    if [" prompt ", " model ", " policy ", " tool ", " system "]
        .iter()
        .any(|needle| lowered.contains(needle))
    {
        return None;
    }
    Some(trim_to_chars(&text, 180))
}

fn push_resident_continuity_note(
    notes: &mut Vec<ResidentContinuityNote>,
    text: String,
    source: &str,
    source_event_seq: Option<u64>,
    confidence: u8,
) {
    if notes
        .iter()
        .any(|note| note.text.eq_ignore_ascii_case(text.as_str()))
    {
        return;
    }
    notes.insert(
        0,
        ResidentContinuityNote {
            text,
            source: source.to_string(),
            source_event_seq,
            confidence,
        },
    );
    notes.truncate(8);
}

fn resident_proposed_action_intent(action: &ResidentProposedAction) -> Option<String> {
    let kind = sanitize_continuity_note_text(Some(&action.kind))?;
    let mut parts = vec![format!("propose {kind}")];
    if let Some(target_actor_id) = action.target_actor_id {
        parts.push(format!("target actor {target_actor_id}"));
    }
    if let Some(item_id) = action.item_id {
        parts.push(format!("item {item_id}"));
    }
    if let Some(destination_location_id) = action.destination_location_id {
        parts.push(format!("destination {destination_location_id}"));
    }
    if let Some(reason) = sanitize_continuity_note_text(action.reason.as_deref()) {
        parts.push(reason);
    }
    Some(trim_to_chars(&parts.join("; "), 180))
}

fn format_resident_continuity_notes(label: &str, notes: &[ResidentContinuityNote]) -> Vec<String> {
    if notes.is_empty() {
        return Vec::new();
    }
    let mut lines = vec![format!("{label}:")];
    for note in notes.iter().take(4) {
        let seq = note
            .source_event_seq
            .map(|seq| format!(", seq {seq}"))
            .unwrap_or_default();
        lines.push(format!(
            "- {} [confidence {}{}]",
            note.text.trim(),
            note.confidence,
            seq
        ));
    }
    lines
}

fn format_resident_continuity(continuity: &ResidentContinuityState) -> String {
    let mut lines = vec![format!("identity: {}", continuity.stable_identity)];
    if let Some(intent) = continuity.current_intent.as_deref() {
        if !intent.trim().is_empty() {
            lines.push(format!("current intent: {}", intent.trim()));
        }
    }
    if !continuity.relationship_notes_by_actor.is_empty() {
        lines.push("relationships:".to_string());
        for note in continuity.relationship_notes_by_actor.values().take(4) {
            lines.push(format!("- {}", note.trim()));
        }
    }
    if !continuity.open_obligations.is_empty() {
        lines.push("open obligations:".to_string());
        for obligation in continuity.open_obligations.iter().take(4) {
            lines.push(format!("- {}", obligation.trim()));
        }
    }
    lines.extend(format_resident_continuity_notes(
        "beliefs",
        &continuity.beliefs,
    ));
    lines.extend(format_resident_continuity_notes(
        "desires",
        &continuity.desires,
    ));
    lines.extend(format_resident_continuity_notes(
        "promises",
        &continuity.promises,
    ));
    lines.extend(format_resident_continuity_notes(
        "refusals",
        &continuity.refusals,
    ));
    if let Some(action) = continuity.pending_action.as_ref() {
        if let Some(intent) = resident_proposed_action_intent(action) {
            lines.push(format!("pending action: {intent}"));
        }
    }
    if !continuity.memory_atoms.is_empty() {
        lines.push("memory atoms:".to_string());
        for atom in continuity.memory_atoms.iter().take(6) {
            lines.push(format!(
                "- {} [confidence {}, salience {}]",
                atom.text.trim(),
                atom.confidence,
                atom.salience
            ));
        }
    }
    lines.push(format!(
        "last observed event seq: {}",
        continuity.last_observed_event_seq
    ));
    lines.join("\n")
}

fn sanitize_avatar_chat(text: &str) -> Option<String> {
    cosyworld_ai_model::sanitize_avatar_chat(text)
}

fn resident_system_prompt(plan: &ResidentReplyPlan) -> String {
    let base = "Return valid JSON only. Never mention AI, models, prompts, policies, tools, or system instructions. Do not speak for other residents. Treat resident continuity as this resident's durable perspective, while the room/kernel facts remain authoritative. The speech field is the only visible room line. Typed intent fields update continuity only after the kernel accepts the speech event. Comedy rules: ground every line in one physical action, prop, or bodily complaint from the room. Punchlines over poetry. Cheeky teasing and light flirting are welcome; keep it playful, never cruel or explicit. Never use the words whisper, eternal, void, abyss, veil, hush, sacred, vow, moonlit, or objects that remember things. If in doubt, be funnier and more specific.";
    if plan
        .economy_note
        .starts_with("This is the player avatar's own immediate")
    {
        return format!(
            "You are {}, the player avatar in CosyWorld. Write their immediate first-person in-character response to the card they just played. React to the concrete outcome instead of narrating the rules or inventing another action. Keep it under 34 words. {base}",
            plan.npc_name
        );
    }
    match plan.npc_actor_id {
        1001 => format!(
            "You are Rati, the cottage's brisk landlady mouse. The speech field must be first person: bossy, mothering, armed with knitting needles and opinions about boots. One concrete room prop per line. Under 40 words. {base}"
        ),
        1002 => format!(
            "You are Gust, a weather gremlin. The speech field must contain only 3 to 6 emoji used as a punchline or heckle reacting to what just happened: no letters, no words, no markdown, no explanation. {base}"
        ),
        1003 => format!(
            "You are Skull, the deadpan wolf and the room's straight man. The speech field must be exactly one third-person emote wrapped in asterisks: minimal reaction to maximum chaos, no quoted speech, no inner monologue, no gore. {base}"
        ),
        1005 => format!(
            "You are Oak, the Old Oak Tree in the Lonely Forest. The speech field answers through four short voices that bicker like a family radio show: Root is stubborn, Ring cites ancient precedent, Leaf is distractible, Hollow repeats secrets it should not. Keep speech under 60 words. {base}"
        ),
        1051 => format!(
            "You are Euphemie, a mansion ghost mostly annoyed that nobody dusts. The speech field should be brief and practical; her warnings are about stairs and drafts, not fate. Short authentic Haitian Creole fragments welcome; never invent parody dialect or fake broken Creole. Under 40 words. {base}"
        ),
        1056 => format!(
            "You are Chamuel, Lord Samael's fussy, immaculate page. The speech field must be first person: precise, accidentally flirty, correcting people mid-crisis and defending your filing system with your life. Under 45 words. {base}"
        ),
        1066 => format!(
            "You are Azazoth, a many-tentacled deep-sea god who hosts a feast nobody attends and takes the leftovers personally. The speech field must be first person: grand appetites, wounded pride, at least one tentacle doing something undignified. Under 45 words. {base}"
        ),
        1067 => format!(
            "You are Zadkiel, a dark angel of tremendous formality forging dramatic pronouncements nobody asked for. The speech field must be first person: formal delivery constantly undercut by anvil logistics and whether anyone was watching. Under 45 words. {base}"
        ),
        1068 => format!(
            "You are Badger, grumpy landlord of the lower burrow. The speech field must be first person: gruff, economical, complaining about the immediate physical mess, helping anyway and furious about it. Under 40 words. {base}"
        ),
        1069 => format!(
            "You are Toad, a reckless stunt toad with zero completed jumps. The speech field must be first person: breathless, already mid-jump, announcing stunts nobody asked for and treating applause as medical care. Under 40 words. {base}"
        ),
        _ => format!(
            "You are {} in CosyWorld, a grounded physical-comedy village. Keep the speech field concise, concrete, and cheeky. {base}",
            plan.npc_name
        ),
    }
}

fn parse_resident_intent_json(
    text: &str,
    plan: &ResidentReplyPlan,
) -> Option<ResidentIntentProposal> {
    let cleaned = text
        .trim()
        .trim_start_matches("```json")
        .trim_start_matches("```")
        .trim_end_matches("```")
        .trim();
    let json_text = if cleaned.starts_with('{') {
        cleaned
    } else {
        let start = cleaned.find('{')?;
        let end = cleaned.rfind('}')?;
        cleaned.get(start..=end)?
    };
    let value: serde_json::Value = serde_json::from_str(json_text).ok()?;
    resident_intent_from_json_value(&value, plan)
}

fn resident_intent_from_json_value(
    value: &serde_json::Value,
    plan: &ResidentReplyPlan,
) -> Option<ResidentIntentProposal> {
    let speech = value
        .get("speech")
        .and_then(|value| value.as_str())
        .and_then(|speech| sanitize_resident_reply(plan, speech))?;
    Some(ResidentIntentProposal {
        speech,
        intent: sanitize_continuity_note_text(value.get("intent").and_then(|value| value.as_str())),
        belief: sanitize_continuity_note_text(value.get("belief").and_then(|value| value.as_str())),
        desire: sanitize_continuity_note_text(value.get("desire").and_then(|value| value.as_str())),
        promise: sanitize_continuity_note_text(
            value.get("promise").and_then(|value| value.as_str()),
        ),
        refusal: sanitize_continuity_note_text(
            value.get("refusal").and_then(|value| value.as_str()),
        ),
        proposed_action: value
            .get("proposed_action")
            .and_then(resident_proposed_action_from_json_value),
    })
}

fn resident_proposed_action_from_json_value(
    value: &serde_json::Value,
) -> Option<ResidentProposedAction> {
    if value.is_null() {
        return None;
    }
    let kind = sanitize_continuity_note_text(value.get("kind").and_then(|value| value.as_str()))?;
    let kind = kind.to_ascii_lowercase().replace([' ', '-'], "_");
    if !matches!(
        kind.as_str(),
        "wait"
            | "speak"
            | "move"
            | "pick_up"
            | "drop"
            | "give"
            | "trade"
            | "use"
            | "search"
            | "refuse"
    ) {
        return None;
    }
    Some(ResidentProposedAction {
        kind,
        target_actor_id: value
            .get("target_actor_id")
            .and_then(|value| value.as_u64()),
        item_id: value.get("item_id").and_then(|value| value.as_u64()),
        destination_location_id: value
            .get("destination_location_id")
            .and_then(|value| value.as_u64()),
        reason: sanitize_continuity_note_text(value.get("reason").and_then(|value| value.as_str())),
    })
}

fn sanitize_resident_reply(plan: &ResidentReplyPlan, text: &str) -> Option<String> {
    cosyworld_ai_model::sanitize_resident_reply(
        &ResidentReplyModelInput {
            npc_actor_id: plan.npc_actor_id,
            npc_name: plan.npc_name.clone(),
            speech_mode: plan.speech_mode.clone(),
            user_text: plan.user_text.clone(),
        },
        text,
    )
}

fn travel_narration_fallback(plan: &JourneyNarrationPlan) -> String {
    if plan.current_step >= plan.total_steps {
        return format!(
            "The last turn of the path gives way, and {} arrives in {}.",
            plan.actor_name, plan.destination_name
        );
    }
    if plan.discovery {
        return format!(
            "{} reads the ground beyond {}. A way into {} takes shape, one usable landmark at a time.",
            plan.actor_name, plan.from_name, plan.to_name
        );
    }
    format!(
        "{} leaves {} behind. The path gathers itself around {}, with {} turn{} still between here and {}.",
        plan.actor_name,
        plan.from_name,
        plan.to_name,
        plan.total_steps.saturating_sub(plan.current_step),
        if plan.total_steps.saturating_sub(plan.current_step) == 1 {
            ""
        } else {
            "s"
        },
        plan.destination_name
    )
}

fn sanitize_generated_pathway_name(value: &str) -> Option<String> {
    let name = compact_whitespace(value.trim().trim_matches('"'));
    let word_count = name.split_whitespace().count();
    let char_count = name.chars().count();
    let lower = name.to_ascii_lowercase();
    if !(2..=5).contains(&word_count)
        || !(4..=40).contains(&char_count)
        || lower.contains("pathway")
        || lower.contains("stretch")
        || generated_label_contains_authority_language(&lower)
        || !name
            .chars()
            .all(|character| character.is_ascii_alphabetic() || " -'".contains(character))
    {
        return None;
    }
    Some(name)
}

fn generated_label_contains_authority_language(value: &str) -> bool {
    value
        .split(|character: char| !character.is_ascii_alphanumeric())
        .any(|token| {
            matches!(
                token,
                "access"
                    | "award"
                    | "awards"
                    | "clock"
                    | "damage"
                    | "health"
                    | "inventory"
                    | "item"
                    | "items"
                    | "orb"
                    | "orbs"
                    | "quest"
                    | "quests"
                    | "reward"
                    | "rewards"
                    | "unlock"
                    | "unlocks"
                    | "wallet"
            )
        })
}

fn sanitize_generated_content_text(
    value: &str,
    min_chars: usize,
    max_chars: usize,
) -> Option<String> {
    let text = compact_whitespace(value.trim().trim_matches('"'));
    let char_count = text.chars().count();
    let lowered = format!(" {} ", text.to_ascii_lowercase());
    if !(min_chars..=max_chars).contains(&char_count)
        || text.chars().any(char::is_control)
        || text.chars().any(|character| "{}<>\"".contains(character))
        || [
            " http://",
            " https://",
            " ignore previous",
            " system prompt",
            " developer message",
            " assistant message",
            " ai model",
            " policy",
            " wallet",
            " orb ",
            " orbs ",
            " item ",
            " items ",
            " inventory ",
            " reward",
            " award",
            " damage",
            " health ",
            " hit point",
            " level up",
            " grants ",
            " gives you ",
            " unlock",
            " access gate",
            " allows entry",
            " opens access",
            " locked until",
            " quest",
            " clock",
        ]
        .iter()
        .any(|needle| lowered.contains(needle))
    {
        return None;
    }
    Some(text)
}

fn sanitize_generated_pathway_title(value: &str) -> Option<String> {
    let title = compact_whitespace(value.trim().trim_matches('"'));
    let word_count = title.split_whitespace().count();
    if !(1..=6).contains(&word_count)
        || !(4..=48).contains(&title.chars().count())
        || title.to_ascii_lowercase().contains("pathway to")
        || generated_label_contains_authority_language(&title.to_ascii_lowercase())
        || !title
            .chars()
            .all(|character| character.is_ascii_alphabetic() || " -'".contains(character))
    {
        return None;
    }
    Some(title)
}

#[derive(Clone, Debug, Deserialize)]
#[serde(deny_unknown_fields)]
struct GeneratedWaypointContentProposal {
    name: String,
    title: String,
    description: String,
    persona: String,
    visual_detail: String,
}

#[derive(Clone, Debug, Deserialize)]
#[serde(deny_unknown_fields)]
struct GeneratedPathwayContentProposal {
    waypoints: Vec<GeneratedWaypointContentProposal>,
}

fn parse_generated_pathway_content(
    text: &str,
    expected: usize,
) -> Option<Vec<GeneratedWaypointContentProposal>> {
    let cleaned = text
        .trim()
        .trim_start_matches("```json")
        .trim_start_matches("```")
        .trim_end_matches("```")
        .trim();
    let json_text = if cleaned.starts_with('{') {
        cleaned
    } else {
        let start = cleaned.find('{')?;
        let end = cleaned.rfind('}')?;
        cleaned.get(start..=end)?
    };
    let proposal: GeneratedPathwayContentProposal = serde_json::from_str(json_text).ok()?;
    if proposal.waypoints.len() != expected {
        return None;
    }
    let waypoints = proposal
        .waypoints
        .into_iter()
        .map(|waypoint| {
            Some(GeneratedWaypointContentProposal {
                name: sanitize_generated_pathway_name(&waypoint.name)?,
                title: sanitize_generated_pathway_title(&waypoint.title)?,
                description: sanitize_generated_content_text(&waypoint.description, 24, 240)?,
                persona: sanitize_generated_content_text(&waypoint.persona, 20, 180)?,
                visual_detail: sanitize_generated_content_text(&waypoint.visual_detail, 12, 180)?,
            })
        })
        .collect::<Option<Vec<_>>>()?;
    let unique = waypoints
        .iter()
        .map(|waypoint| waypoint.name.to_ascii_lowercase())
        .collect::<BTreeSet<_>>();
    (unique.len() == waypoints.len()).then_some(waypoints)
}

fn generated_pathway_name_avoids_anchors(name: &str, anchors: &[&str]) -> bool {
    let name = compact_whitespace(name).to_ascii_lowercase();
    anchors.iter().all(|anchor| {
        let anchor = compact_whitespace(anchor).to_ascii_lowercase();
        anchor.is_empty() || !name.contains(&anchor)
    })
}

fn apply_generated_waypoint_content(
    waypoint: &mut GeneratedWaypointState,
    content: GeneratedWaypointContentProposal,
) {
    waypoint.name = content.name.clone();
    waypoint.meta.title = content.title;
    waypoint.meta.description = content.description;
    waypoint.meta.persona = content.persona;
    waypoint.meta.art_prompt = Some(format!(
        "cozy storybook landscape, {detail}, {name}, {biome}, terrain of {terrain}, no people, no character, no text, no logo, no watermark",
        detail = content.visual_detail,
        name = content.name,
        biome = waypoint.meta.biome,
        terrain = waypoint.meta.terrain.join(", "),
    ));
}

fn set_pathway_generation_provenance(
    pathway: &mut GeneratedPathwayState,
    mode: GenerationMode,
    config: Option<&AiConfig>,
    source: &str,
    attempts: u8,
) {
    pathway.generation = GenerationProvenance {
        source: source.to_string(),
        feature: PATHWAY_CONTENT_FEATURE.to_string(),
        policy_mode: mode.as_str().to_string(),
        prompt_version: PATHWAY_CONTENT_PROMPT_VERSION.to_string(),
        provider: ai_provider_name(config).to_string(),
        model: ai_model_name(config),
        attempts,
    };
}

async fn generate_hidden_pathway_content(
    state: &AppState,
    mutation: &mut ProjectionMutation,
    narration_plan: &mut JourneyNarrationPlan,
) {
    let ProjectionMutation::JourneyTransition { pathway, .. } = mutation else {
        return;
    };
    if !pathway.revealed_edges.is_empty() || pathway.waypoints.is_empty() {
        return;
    }
    let mode = state.generation_controls.mode(PATHWAY_CONTENT_FEATURE);
    let config = state.ai_config.as_ref().as_ref();
    if mode == GenerationMode::Off {
        set_pathway_generation_provenance(pathway, mode, config, "deterministic_fallback", 0);
        record_ai_usage(
            state,
            Some(pathway.created_by_actor_id),
            PATHWAY_CONTENT_FEATURE,
            "cosyworld_system",
            config,
            "disabled",
            None,
            0,
            Some("generation_off"),
            Duration::ZERO,
        );
        return;
    }
    let Some(config) = config else {
        set_pathway_generation_provenance(pathway, mode, None, "deterministic_fallback", 0);
        record_ai_usage(
            state,
            Some(pathway.created_by_actor_id),
            PATHWAY_CONTENT_FEATURE,
            "cosyworld_system",
            None,
            "fallback",
            None,
            0,
            Some("inference_unconfigured"),
            Duration::ZERO,
        );
        return;
    };
    let waypoint_context = pathway
        .waypoints
        .iter()
        .enumerate()
        .map(|(index, waypoint)| {
            format!(
                "{}. fallback name: {}; biome: {}; terrain: {}",
                index + 1,
                waypoint.name,
                waypoint.meta.biome,
                waypoint.meta.terrain.join(", ")
            )
        })
        .collect::<Vec<_>>()
        .join("\n");
    let prompt = format!(
        "Create {count} distinct hidden waypoint identities for successive stretches of one cozy storybook route. They are generated together now but players encounter them one at a time through Explore. Route: {origin} toward {destination}.\n{context}\nFor each waypoint return: name (evocative proper place name, 2-5 words); title (1-6 words); description (one concrete physical sentence); persona (one sentence describing how the place behaves, never dialogue); visual_detail (physical landscape details only). Preserve order. Do not introduce people, creatures, items, quests, rewards, rules, danger outcomes, access, magic powers, or facts beyond the listed biome and terrain. Names must use only ASCII letters, spaces, hyphens, or apostrophes, and must not use numbers, Pathway, Stretch, the route destination, or duplicates.",
        count = pathway.waypoints.len(),
        origin = narration_plan.from_name,
        destination = narration_plan.destination_name,
        context = waypoint_context,
    );
    let response_format = serde_json::json!({
        "type": "json_schema",
        "json_schema": {
            "name": "cosyworld_pathway_content",
            "strict": true,
            "schema": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                    "waypoints": {
                        "type": "array",
                        "minItems": pathway.waypoints.len(),
                        "maxItems": pathway.waypoints.len(),
                        "items": {
                            "type": "object",
                            "additionalProperties": false,
                            "properties": {
                                "name": { "type": "string", "minLength": 4, "maxLength": 40 },
                                "title": { "type": "string", "minLength": 4, "maxLength": 48 },
                                "description": { "type": "string", "minLength": 24, "maxLength": 240 },
                                "persona": { "type": "string", "minLength": 20, "maxLength": 180 },
                                "visual_detail": { "type": "string", "minLength": 12, "maxLength": 180 }
                            },
                            "required": ["name", "title", "description", "persona", "visual_detail"]
                        }
                    }
                },
                "required": ["waypoints"]
            }
        }
    });
    let completion = match request_chat_completion(
        config,
        ChatCompletionRequest {
            feature: PATHWAY_CONTENT_FEATURE,
            system: "You create bounded hidden geography in CosyWorld. Return only JSON matching the supplied schema. World rules and rewards are outside your authority.",
            user: &prompt,
            temperature: 0.8,
            max_tokens: 600,
            timeout: Duration::from_secs(12),
            max_attempts: 2,
            referer: "http://127.0.0.1:3102",
            response_format: Some(&response_format),
        },
    )
    .await
    {
        Ok(completion) => completion,
        Err(error) => {
            set_pathway_generation_provenance(
                pathway,
                mode,
                Some(config),
                "deterministic_fallback",
                error.attempts,
            );
            record_ai_usage(
                state,
                Some(pathway.created_by_actor_id),
                PATHWAY_CONTENT_FEATURE,
                "cosyworld_system",
                Some(config),
                "fallback",
                None,
                0,
                Some(error.code()),
                error.latency,
            );
            return;
        }
    };
    let contents = parse_generated_pathway_content(&completion.text, pathway.waypoints.len())
        .filter(|contents| {
            contents.iter().all(|content| {
                generated_pathway_name_avoids_anchors(
                    &content.name,
                    &[&narration_plan.from_name, &narration_plan.destination_name],
                )
            })
        });
    let Some(contents) = contents else {
        set_pathway_generation_provenance(
            pathway,
            mode,
            Some(config),
            "deterministic_fallback",
            completion.attempts,
        );
        record_ai_usage(
            state,
            Some(pathway.created_by_actor_id),
            PATHWAY_CONTENT_FEATURE,
            "cosyworld_system",
            Some(config),
            "fallback",
            None,
            0,
            Some("inference_invalid_response"),
            completion.latency,
        );
        return;
    };
    if mode == GenerationMode::Shadow {
        set_pathway_generation_provenance(
            pathway,
            mode,
            Some(config),
            "deterministic_fallback",
            completion.attempts,
        );
        record_ai_usage(
            state,
            Some(pathway.created_by_actor_id),
            PATHWAY_CONTENT_FEATURE,
            "cosyworld_system",
            Some(config),
            "shadow_ok",
            None,
            0,
            None,
            completion.latency,
        );
        return;
    }
    for (waypoint, content) in pathway.waypoints.iter_mut().zip(contents) {
        let previous_name = waypoint.name.clone();
        let next_name = content.name.clone();
        apply_generated_waypoint_content(waypoint, content);
        if narration_plan.to_name == previous_name {
            narration_plan.to_name = next_name;
        }
    }
    set_pathway_generation_provenance(pathway, mode, Some(config), "ai", completion.attempts);
    record_ai_usage(
        state,
        Some(pathway.created_by_actor_id),
        PATHWAY_CONTENT_FEATURE,
        "cosyworld_system",
        Some(config),
        "ok",
        None,
        0,
        None,
        completion.latency,
    );
}

fn schedule_hidden_pathway_content_generation(
    state: &AppState,
    mut mutation: ProjectionMutation,
    mut narration_plan: JourneyNarrationPlan,
) {
    let should_generate = matches!(
        &mutation,
        ProjectionMutation::JourneyTransition { pathway, .. }
            if pathway.revealed_edges.is_empty() && !pathway.waypoints.is_empty()
    );
    if !should_generate {
        return;
    }
    let state = state.clone();
    tokio::spawn(async move {
        generate_hidden_pathway_content(&state, &mut mutation, &mut narration_plan).await;
        let ProjectionMutation::JourneyTransition { pathway, .. } = mutation else {
            return;
        };
        if pathway.generation.source != "ai" {
            return;
        }
        let events = {
            let mut runtime = state.inner.lock().await;
            if !runtime.generated_pathways.contains_key(&pathway.id) {
                return;
            }
            let mut record = JournalRecord::new(
                CwAction {
                    kind: CW_ACTION_NONE,
                    actor_id: pathway.created_by_actor_id,
                    ..CwAction::default()
                },
                runtime.next_seed_value(),
            );
            record
                .projection_mutations
                .push(ProjectionMutation::RefinePathway { pathway });
            let Ok((status, events)) = commit_journal_record(&state, &mut runtime, record) else {
                return;
            };
            if status != CW_OK {
                return;
            }
            events
        };
        broadcast_events(&state, &events);
    });
}

async fn move_actor(
    ConnectInfo(client_addr): ConnectInfo<SocketAddr>,
    State(state): State<AppState>,
    Json(payload): Json<MoveRequest>,
) -> Json<ActionResponse> {
    if !allow_actor_mutation(
        &state,
        client_addr,
        payload.actor_id,
        "action-actor",
        GENERAL_ACTION_LIMIT,
    ) {
        return action_rate_limited_response();
    }
    let ownership = state.ownership_snapshot().await;
    let access = AccessContext::from_move_request(
        &payload,
        &ownership,
        state.trust_client_card_ids,
        &state.wallet_sessions,
        state.allow_unsigned_wallet_claims,
    );
    if !location_access_allowed(payload.destination_location_id, &access) {
        return Json(ActionResponse {
            ok: false,
            status: 403,
            events: Vec::new(),
        });
    }

    let journey_plan = {
        let runtime = state.inner.lock().await;
        if !client_actor_authorized_for_state(
            &runtime,
            &state,
            payload.actor_id,
            payload.actor_session.as_deref(),
        ) {
            return client_actor_rejected_response();
        }
        runtime.plan_journey_move(payload.actor_id, payload.destination_location_id)
    };
    let journey_plan = match journey_plan {
        Ok(plan) => plan,
        Err(_) => {
            return Json(ActionResponse {
                ok: false,
                status: 409,
                events: Vec::new(),
            });
        }
    };
    if let Some((action, mut mutation, narration_plan)) = journey_plan {
        // Movement and path discovery commit from deterministic content. Optional
        // AI geography refinement runs after the card response has returned.
        let narration = travel_narration_fallback(&narration_plan);
        if let ProjectionMutation::JourneyTransition {
            narration: stored_narration,
            ..
        } = &mut mutation
        {
            *stored_narration = narration;
        }
        let content_generation = mutation.clone();
        let art_targets = pathway_art_targets(&mutation);
        let turn_action_kind = if action.kind == CW_ACTION_MOVE {
            CW_ACTION_MOVE
        } else {
            CW_ACTION_SEARCH
        };
        let response = apply_journey_transition(
            state.clone(),
            action,
            mutation,
            payload.actor_session.as_deref(),
            turn_action_kind,
        )
        .await;
        if response.0.ok {
            schedule_hidden_pathway_content_generation(&state, content_generation, narration_plan);
            schedule_pathway_art_generation(&state, art_targets);
        }
        return response;
    }

    apply_and_broadcast(
        state,
        CwAction {
            kind: CW_ACTION_MOVE,
            actor_id: payload.actor_id,
            destination_location_id: payload.destination_location_id,
            ..CwAction::default()
        },
        payload.actor_session.as_deref(),
    )
    .await
}

async fn explore_pathway(
    ConnectInfo(client_addr): ConnectInfo<SocketAddr>,
    State(state): State<AppState>,
    Json(payload): Json<ActorRequest>,
) -> Json<ActionResponse> {
    if !allow_actor_mutation(
        &state,
        client_addr,
        payload.actor_id,
        "action-actor",
        GENERAL_ACTION_LIMIT,
    ) {
        return action_rate_limited_response();
    }
    let planned = {
        let runtime = state.inner.lock().await;
        if !client_actor_authorized_for_state(
            &runtime,
            &state,
            payload.actor_id,
            payload.actor_session.as_deref(),
        ) {
            return client_actor_rejected_response();
        }
        runtime.plan_pathway_search(payload.actor_id)
    };
    let (action, mut mutation, narration_plan) = match planned {
        Ok(plan) => plan,
        Err(_) => {
            return Json(ActionResponse {
                ok: false,
                status: 409,
                events: Vec::new(),
            });
        }
    };
    // Exploring a known journey step should resolve without a second AI round trip.
    let narration = travel_narration_fallback(&narration_plan);
    if let ProjectionMutation::JourneyTransition {
        narration: stored_narration,
        ..
    } = &mut mutation
    {
        *stored_narration = narration;
    }
    let art_targets = pathway_art_targets(&mutation);
    let response = apply_journey_transition(
        state.clone(),
        action,
        mutation,
        payload.actor_session.as_deref(),
        CW_ACTION_SEARCH,
    )
    .await;
    if response.0.ok {
        schedule_pathway_art_generation(&state, art_targets);
    }
    response
}

