async fn work(
    ConnectInfo(client_addr): ConnectInfo<SocketAddr>,
    State(state): State<AppState>,
    Json(payload): Json<ActorRequest>,
) -> Json<ActionResponse> {
    if !allow_actor_mutation(
        &state,
        client_addr,
        payload.actor_id,
        "action-actor",
        GENERAL_ACTION_LIMIT,
    ) {
        return action_rate_limited_response();
    }

    let mut runtime = state.inner.lock().await;
    if !client_actor_authorized_for_state(
        &runtime,
        &state,
        payload.actor_id,
        payload.actor_session.as_deref(),
    ) {
        return client_actor_rejected_response();
    }
    let turn_location_id = runtime
        .actor_by_id(payload.actor_id)
        .map(|actor| actor.location_id);
    if let Some(response) = actor_turn_rejection(&state, &runtime, payload.actor_id) {
        return response;
    }
    if !runtime.work_available(payload.actor_id) {
        return Json(ActionResponse {
            ok: false,
            status: 409,
            events: Vec::new(),
        });
    }
    let Some(actor) = runtime.actor_by_id(payload.actor_id) else {
        return Json(ActionResponse {
            ok: false,
            status: 404,
            events: Vec::new(),
        });
    };
    let location_id = actor.location_id;
    let Some(clock_id) = runtime.active_progress_clock_id_for_location(location_id) else {
        return Json(ActionResponse {
            ok: false,
            status: 409,
            events: Vec::new(),
        });
    };
    let prepared = runtime.prepared_tag_active(payload.actor_id, location_id);
    let progress_amount = runtime.work_project_progress_amount(payload.actor_id, location_id);
    let progress_reason = if prepared && progress_amount > 2 {
        "informed_work"
    } else if prepared {
        "prepared_work"
    } else {
        "work"
    };
    let pathway_upgrade_id = runtime.generated_pathway_id_for_progress_clock(&clock_id);
    let mut record = JournalRecord::new(
        CwAction {
            kind: CW_ACTION_NONE,
            actor_id: payload.actor_id,
            ..CwAction::default()
        },
        runtime.next_seed_value(),
    )
    .into_player_card();
    record
        .projection_mutations
        .push(ProjectionMutation::AdvanceClock {
            clock_id: clock_id.clone(),
            amount: progress_amount,
            reason: progress_reason.to_string(),
        });
    if let Some(pathway_id) = &pathway_upgrade_id {
        record
            .projection_mutations
            .push(ProjectionMutation::UpgradePathwayIfReady {
                pathway_id: pathway_id.clone(),
                progress_clock_id: clock_id.clone(),
            });
    }
    if prepared {
        record
            .projection_mutations
            .push(ProjectionMutation::ClearTag {
                tag_id: prepared_tag_id(payload.actor_id, location_id),
                reason: progress_reason.to_string(),
            });
        record
            .projection_mutations
            .push(ProjectionMutation::SetTag {
                tag: RpgTagState {
                    id: project_preparation_spent_tag_id(payload.actor_id, location_id, &clock_id),
                    scope: "actor".to_string(),
                    scope_id: payload.actor_id,
                    label: "spent preparation".to_string(),
                    kind: "memory".to_string(),
                    active: true,
                    source_event_seq: None,
                    expires: Some("when_job_resolves".to_string()),
                },
                reason: progress_reason.to_string(),
            });
    } else {
        record
            .projection_mutations
            .push(ProjectionMutation::SetTag {
                tag: RpgTagState {
                    id: tired_tag_id(payload.actor_id),
                    scope: "actor".to_string(),
                    scope_id: payload.actor_id,
                    label: "tired".to_string(),
                    kind: "condition".to_string(),
                    active: true,
                    source_event_seq: None,
                    expires: Some("after_rest".to_string()),
                },
                reason: "work".to_string(),
            });
    }

    let Ok((status, mut events)) = commit_journal_record(&state, &mut runtime, record) else {
        return Json(ActionResponse {
            ok: false,
            status: 500,
            events: Vec::new(),
        });
    };
    let pathway_upgraded = events
        .iter()
        .any(|event| event.type_name == "pathway.familiarized");
    let pathway_art_targets = pathway_upgrade_id
        .as_deref()
        .filter(|_| pathway_upgraded)
        .map(|pathway_id| runtime.generated_pathway_art_targets(pathway_id))
        .unwrap_or_default();
    let ripple_reply_plan = advance_turn_and_capture_player_tick_observation(
        &state,
        &mut runtime,
        turn_location_id,
        payload.actor_id,
        status,
        &mut events,
    );
    drop(runtime);

    broadcast_events(&state, &events);
    if pathway_upgraded {
        schedule_pathway_art_generation(&state, pathway_art_targets);
    }
    if let Some(plan) = ripple_reply_plan {
        schedule_player_tick_observation(&state, plan);
    }
    Json(ActionResponse {
        ok: status == CW_OK,
        status,
        events,
    })
}

