async fn apply_and_broadcast(
    state: AppState,
    action: CwAction,
    actor_session: Option<&str>,
) -> Json<ActionResponse> {
    apply_and_broadcast_with_resident_reply(state, action, actor_session).await
}

async fn apply_journey_transition(
    state: AppState,
    action: CwAction,
    mutation: ProjectionMutation,
    actor_session: Option<&str>,
    turn_action_kind: u8,
) -> Json<ActionResponse> {
    let actor_id = action.actor_id;
    let was_active = actor_session
        .and_then(|token| actor_session_active_for_actor(&state.actor_sessions, actor_id, token))
        .unwrap_or(false);
    let mut runtime = state.inner.lock().await;
    if !client_actor_authorized_for_state(&runtime, &state, actor_id, actor_session) {
        return client_actor_rejected_response();
    }
    let released_events = release_inactive_human_inventory_locked(&state, &mut runtime);
    let turn_location_id = runtime.actor_by_id(actor_id).map(|actor| actor.location_id);
    let turn_action = CwAction {
        kind: turn_action_kind,
        actor_id,
        destination_location_id: action.destination_location_id,
        ..CwAction::default()
    };
    if let Some(response) = actor_action_turn_rejection(&state, &runtime, &turn_action) {
        drop(runtime);
        if !released_events.is_empty() {
            broadcast_events(&state, &released_events);
        }
        return response;
    }
    let mut record = JournalRecord::new(action, runtime.next_seed_value());
    record.projection_mutations.push(mutation);
    let Ok((status, mut events)) = commit_journal_record(&state, &mut runtime, record) else {
        drop(runtime);
        return Json(ActionResponse {
            ok: false,
            status: 500,
            events: Vec::new(),
        });
    };
    let reply_plan = advance_turn_and_capture_player_tick_observation(
        &state,
        &mut runtime,
        turn_location_id,
        actor_id,
        status,
        &mut events,
    );
    drop(runtime);
    if !released_events.is_empty() {
        broadcast_events(&state, &released_events);
    }
    broadcast_events(&state, &events);
    if let Some(plan) = reply_plan {
        schedule_player_tick_observation(&state, plan);
    }
    let mut response_events = events;
    if !was_active {
        response_events.extend(commit_presence_event(&state, actor_id, true).await);
    }
    Json(ActionResponse {
        ok: status == CW_OK && !response_events.is_empty(),
        status,
        events: response_events,
    })
}

async fn apply_and_broadcast_with_resident_reply(
    state: AppState,
    action: CwAction,
    actor_session: Option<&str>,
) -> Json<ActionResponse> {
    let actor_id = action.actor_id;
    let was_active = actor_session
        .and_then(|token| actor_session_active_for_actor(&state.actor_sessions, actor_id, token))
        .unwrap_or(false);
    let mut runtime = state.inner.lock().await;
    if !client_actor_authorized_for_state(&runtime, &state, actor_id, actor_session) {
        return client_actor_rejected_response();
    }
    let released_events = release_inactive_human_inventory_locked(&state, &mut runtime);
    let turn_location_id = runtime.actor_by_id(actor_id).map(|actor| actor.location_id);
    if let Some(response) = actor_action_turn_rejection(&state, &runtime, &action) {
        drop(runtime);
        if !released_events.is_empty() {
            broadcast_events(&state, &released_events);
        }
        return response;
    }
    let listen_cost = if action_is_listen_check(&action) {
        runtime.listen_cost_orbs(actor_id)
    } else {
        0
    };
    if listen_cost > 0 && runtime.orb_balance(actor_id) < listen_cost {
        drop(runtime);
        if !released_events.is_empty() {
            broadcast_events(&state, &released_events);
        }
        let events = if was_active {
            Vec::new()
        } else {
            commit_presence_event(&state, actor_id, true).await
        };
        return Json(ActionResponse {
            ok: false,
            status: 402,
            events,
        });
    }
    let mut record = JournalRecord::new(action, runtime.next_seed_value());
    if listen_cost > 0 {
        record.orb_deltas.push(OrbDelta {
            actor_id,
            delta: -listen_cost,
            reason: "listen".to_string(),
        });
    }
    let Ok((status, mut events)) = commit_journal_record(&state, &mut runtime, record) else {
        drop(runtime);
        if !released_events.is_empty() {
            broadcast_events(&state, &released_events);
        }
        return Json(ActionResponse {
            ok: false,
            status: 500,
            events: Vec::new(),
        });
    };
    let actor_observation = advance_turn_and_capture_player_tick_observation(
        &state,
        &mut runtime,
        turn_location_id,
        actor_id,
        status,
        &mut events,
    );
    drop(runtime);

    if !released_events.is_empty() {
        broadcast_events(&state, &released_events);
    }
    broadcast_events(&state, &events);
    if let Some(observation) = actor_observation {
        schedule_player_tick_observation(&state, observation);
    }
    let mut response_events = events;
    if !was_active {
        response_events.extend(commit_presence_event(&state, actor_id, true).await);
    }
    Json(ActionResponse {
        ok: status == CW_OK,
        status,
        events: response_events,
    })
}

fn client_actor_rejected_response() -> Json<ActionResponse> {
    Json(ActionResponse {
        ok: false,
        status: 403,
        events: Vec::new(),
    })
}

async fn stream(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<EventsQuery>,
) -> Sse<impl tokio_stream::Stream<Item = Result<Event, Infallible>>> {
    let ownership = state.ownership_snapshot().await;
    let access = AccessContext::from_events_query(
        &query,
        &ownership,
        state.trust_client_card_ids,
        &state.wallet_sessions,
        state.allow_unsigned_wallet_claims,
    );
    let visible_locations = {
        let runtime = state.inner.lock().await;
        let actor_id = query.actor_id.filter(|id| {
            client_actor_read_authorized_for_state(
                &runtime,
                &state,
                *id,
                query.actor_session.as_deref(),
                &access,
            )
        });
        runtime.visible_event_locations(actor_id, &access)
    };
    let replay_after = stream_replay_after(&headers, query.after);
    let replay_limit = event_replay_limit(query.limit);
    let rx = state.tx.subscribe();
    let replay_events =
        stream_replay_events(&state, replay_after, replay_limit, &visible_locations).await;
    let replay_stream = tokio_stream::iter(replay_events.into_iter().filter_map(sse_world_event));
    let live_stream = BroadcastStream::new(rx).filter_map(move |event| match event {
        Ok(view) if event_visible_to_locations(&view, &visible_locations) => sse_world_event(view),
        Ok(_) => None,
        Err(_) => None,
    });
    let stream = replay_stream.chain(live_stream);

    Sse::new(stream).keep_alive(KeepAlive::default())
}

fn stream_replay_after(headers: &HeaderMap, query_after: Option<u64>) -> Option<u64> {
    let header_after = headers
        .get("last-event-id")
        .and_then(|value| value.to_str().ok())
        .and_then(|value| value.trim().parse::<u64>().ok());
    query_after.into_iter().chain(header_after).max()
}

async fn stream_replay_events(
    state: &AppState,
    after: Option<u64>,
    replay_limit: usize,
    visible_locations: &BTreeSet<u64>,
) -> Vec<EventView> {
    if after.is_none() || replay_limit == 0 {
        return Vec::new();
    }
    let events = if let Some(path) = state.event_store_path.as_deref() {
        match read_event_store(path, after, event_store_scan_limit(after, replay_limit)) {
            Ok(events) => events,
            Err(error) => {
                warn!(
                    "failed to read CosyWorld v2 stream replay store {}: {}",
                    path.display(),
                    error
                );
                Vec::new()
            }
        }
    } else {
        let runtime = state.inner.lock().await;
        runtime
            .event_log
            .iter()
            .filter(|event| after.map(|seq| event.seq > seq).unwrap_or(true))
            .cloned()
            .collect()
    };
    tail_event_replay(
        events
            .into_iter()
            .filter(|event| event_visible_to_locations(event, visible_locations))
            .collect(),
        replay_limit,
    )
}

fn sse_world_event(view: EventView) -> Option<Result<Event, Infallible>> {
    Event::default()
        .event("world")
        .id(view.seq.to_string())
        .json_data(view)
        .ok()
        .map(Ok)
}

fn broadcast_events(state: &AppState, events: &[EventView]) {
    for event in events
        .iter()
        .filter(|event| event.type_name != "action.receipt")
    {
        let _ = state.tx.send(event.clone());
    }
}

fn index_etag() -> &'static str {
    static ETAG: OnceLock<String> = OnceLock::new();
    ETAG.get_or_init(|| format!("\"{}\"", stable_hash_hex(&[INDEX_HTML])))
}

async fn index(headers: HeaderMap) -> Response {
    let etag = index_etag();
    let cache_headers = [
        (header::CACHE_CONTROL, "public, max-age=0, must-revalidate"),
        (header::ETAG, etag),
    ];
    if headers
        .get(header::IF_NONE_MATCH)
        .and_then(|value| value.to_str().ok())
        .is_some_and(|value| value == etag)
    {
        return (StatusCode::NOT_MODIFIED, cache_headers).into_response();
    }
    (StatusCode::OK, cache_headers, Html(INDEX_HTML)).into_response()
}

async fn moderation_console() -> impl IntoResponse {
    (no_store_headers(), Html(MODERATION_HTML))
}

fn event_visible_to_locations(event: &EventView, location_ids: &BTreeSet<u64>) -> bool {
    event
        .location_id
        .map(|location_id| location_ids.contains(&location_id))
        .unwrap_or(false)
        || event
            .destination_location_id
            .map(|location_id| location_ids.contains(&location_id))
            .unwrap_or(false)
}

