async fn generated_seed_card_asset(AxumPath(card_file): AxumPath<String>) -> impl IntoResponse {
    if let Some((card_id, content_type)) = generated_seed_card_bitmap_request(&card_file) {
        let path = seed_pack_asset_path("cosyworld.core", "generated/cards", &card_file);
        return match path.and_then(|path| fs::read(path).ok()) {
            Some(bytes) => (
                StatusCode::OK,
                [
                    (header::CONTENT_TYPE, content_type),
                    (header::CACHE_CONTROL, "public, max-age=86400"),
                ],
                bytes,
            )
                .into_response(),
            None => (
                StatusCode::NOT_FOUND,
                format!("missing generated seed card asset {card_id}"),
            )
                .into_response(),
        };
    }

    let Some(card_id) = card_file.strip_suffix(".svg") else {
        return (StatusCode::NOT_FOUND, "unknown seed card").into_response();
    };
    let Some(spec) = seed_card_art_spec(card_id) else {
        return (StatusCode::NOT_FOUND, "unknown seed card").into_response();
    };
    (
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, "image/svg+xml; charset=utf-8"),
            (header::CACHE_CONTROL, "public, max-age=86400"),
        ],
        generated_seed_card_svg(&spec),
    )
        .into_response()
}

async fn worldpack_asset(
    AxumPath((pack_id, asset_path)): AxumPath<(String, String)>,
) -> impl IntoResponse {
    let Some(mount) = seed_asset_mounts()
        .iter()
        .filter(|mount| {
            mount.pack_id == pack_id
                && asset_path
                    .strip_prefix(&mount.mount)
                    .is_some_and(|suffix| suffix.starts_with('/'))
        })
        .max_by_key(|mount| mount.mount.len())
    else {
        return (StatusCode::NOT_FOUND, "unknown worldpack asset mount").into_response();
    };
    let relative_path = asset_path
        .strip_prefix(&mount.mount)
        .unwrap_or_default()
        .trim_start_matches('/');
    let Some(path) = seed_pack_asset_path(&pack_id, &mount.mount, relative_path) else {
        return (StatusCode::BAD_REQUEST, "invalid worldpack asset path").into_response();
    };
    match fs::read(path) {
        Ok(bytes) => (
            StatusCode::OK,
            [
                (header::CONTENT_TYPE, asset_content_type(relative_path)),
                (header::CACHE_CONTROL, "public, max-age=86400"),
            ],
            bytes,
        )
            .into_response(),
        Err(_) if mount.optional => {
            let fallback = mount.fallback.as_deref().unwrap_or("none");
            (
                StatusCode::NOT_FOUND,
                format!("optional worldpack asset missing; fallback={fallback}"),
            )
                .into_response()
        }
        Err(_) => (
            StatusCode::NOT_FOUND,
            format!(
                "missing required worldpack asset under {}",
                mount.public_prefix
            ),
        )
            .into_response(),
    }
}

async fn generated_pathway_asset(
    State(state): State<AppState>,
    AxumPath(asset_file): AxumPath<String>,
) -> impl IntoResponse {
    let Some(location_id) = asset_file
        .strip_suffix(".svg")
        .and_then(|value| value.parse::<u64>().ok())
    else {
        return (StatusCode::NOT_FOUND, "unknown pathway").into_response();
    };
    if location_id < GENERATED_PATHWAY_LOCATION_ID_BASE {
        return (StatusCode::NOT_FOUND, "unknown pathway").into_response();
    }
    if let Ok(bytes) = fs::read(stored_pathway_image_path(
        &state.generated_asset_dir,
        location_id,
    )) {
        let content_type = stored_pathway_content_type(&state.generated_asset_dir, location_id);
        return (
            StatusCode::OK,
            [
                (header::CONTENT_TYPE, content_type),
                (header::CACHE_CONTROL, "public, max-age=86400".to_string()),
            ],
            bytes,
        )
            .into_response();
    }
    let waypoint = {
        let runtime = state.inner.lock().await;
        runtime
            .generated_pathways
            .values()
            .flat_map(|pathway| pathway.waypoints.iter())
            .find(|waypoint| waypoint.id == location_id)
            .cloned()
    };
    let Some(waypoint) = waypoint else {
        return (StatusCode::NOT_FOUND, "unknown pathway").into_response();
    };
    let hash = stable_pathway_hash(&format!("{}:{}", waypoint.name, waypoint.meta.biome));
    let palettes = [
        ("#102419", "#315b3e", "#9faf88", "#d7c47a"),
        ("#111d2a", "#284761", "#91b4c8", "#d2d7ad"),
        ("#241c2c", "#4a3658", "#a585b5", "#d9b66f"),
        ("#242117", "#5d5131", "#b4a36c", "#cad7a2"),
    ];
    let (sky, ground, path, accent) = palettes[(hash as usize) % palettes.len()];
    let svg = format!(
        "<svg xmlns='http://www.w3.org/2000/svg' width='1536' height='864' viewBox='0 0 1536 864' role='img' aria-label='Generated pathway landscape'><defs><linearGradient id='sky' x1='0' y1='0' x2='0' y2='1'><stop offset='0' stop-color='{sky}'/><stop offset='1' stop-color='{ground}'/></linearGradient><filter id='soft'><feGaussianBlur stdDeviation='9'/></filter></defs><rect width='1536' height='864' fill='url(#sky)'/><circle cx='1180' cy='150' r='78' fill='{accent}' opacity='.42' filter='url(#soft)'/><path d='M0 510 Q260 390 510 520 T1010 470 T1536 505 V864 H0Z' fill='{ground}' opacity='.92'/><path d='M610 864 C630 700 720 640 770 560 C820 480 790 390 910 300' fill='none' stroke='{path}' stroke-width='120' stroke-linecap='round' opacity='.82'/><path d='M0 630 Q190 520 380 620 M1080 590 Q1310 450 1536 610' fill='none' stroke='{accent}' stroke-width='20' opacity='.34'/><g fill='{path}' opacity='.72'><circle cx='220' cy='480' r='22'/><circle cx='310' cy='450' r='14'/><circle cx='1210' cy='420' r='18'/><circle cx='1320' cy='470' r='26'/></g></svg>"
    );
    (
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, "image/svg+xml; charset=utf-8"),
            (header::CACHE_CONTROL, "public, max-age=86400"),
        ],
        svg,
    )
        .into_response()
}

fn generated_seed_card_bitmap_request(card_file: &str) -> Option<(&str, &'static str)> {
    let (card_id, content_type) = if let Some(card_id) = card_file.strip_suffix(".webp") {
        (card_id, "image/webp")
    } else if let Some(card_id) = card_file.strip_suffix(".png") {
        (card_id, "image/png")
    } else {
        return None;
    };
    if card_id.is_empty()
        || card_id.len() > 128
        || !card_id
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_'))
    {
        return None;
    }
    if !seed_content()
        .cards
        .iter()
        .any(|card| card.card_id == card_id)
    {
        return None;
    }
    Some((card_id, content_type))
}

