fn canonical_pathway_anchors(left: u64, right: u64) -> (u64, u64) {
    if left <= right {
        (left, right)
    } else {
        (right, left)
    }
}

fn generated_pathway_id(left: u64, right: u64) -> String {
    let (origin, destination) = canonical_pathway_anchors(left, right);
    format!("pathway:{origin}:{destination}")
}

