fn effect_descriptor_reason(effect: &EffectDescriptor) -> Option<&str> {
    match effect {
        EffectDescriptor::AdvanceClock { reason, .. }
        | EffectDescriptor::SetTag { reason, .. }
        | EffectDescriptor::ClearTag { reason, .. }
        | EffectDescriptor::SetJobStatus { reason, .. } => reason.as_deref(),
    }
}

fn summarize_effects(effects: &[EffectDescriptor]) -> Option<String> {
    let parts: Vec<_> = effects.iter().map(summarize_effect).collect();
    (!parts.is_empty()).then(|| parts.join("; "))
}

fn summarize_effect(effect: &EffectDescriptor) -> String {
    let summary = match effect {
        EffectDescriptor::AdvanceClock {
            clock_id, amount, ..
        } => format!("advances {clock_id} by {amount}"),
        EffectDescriptor::SetTag {
            scope,
            scope_id,
            label,
            ..
        } => format!("sets {scope} tag {label} on {scope_id}"),
        EffectDescriptor::ClearTag { tag_id, .. } => format!("clears tag {tag_id}"),
        EffectDescriptor::SetJobStatus { job_id, status, .. } => {
            let status = normalize_job_status(status).unwrap_or(status);
            format!("sets job {job_id} to {status}")
        }
    };
    if let Some(reason) = effect_descriptor_reason(effect)
        .map(str::trim)
        .filter(|reason| !reason.is_empty())
    {
        format!("{summary} ({reason})")
    } else {
        summary
    }
}

fn committed_orb_deltas(
    record: &JournalRecord,
    events: &[EventView],
    pre_orb_reward_claims: &BTreeSet<String>,
) -> Vec<OrbDelta> {
    let mut deltas = automatic_orb_rewards_for_action(&record.action, events)
        .into_iter()
        .filter(|reward| !pre_orb_reward_claims.contains(&reward.claim_key))
        .map(|reward| reward.delta)
        .collect::<Vec<_>>();
    deltas.extend(record.orb_deltas.iter().cloned());
    deltas
        .into_iter()
        .filter(|delta| delta.actor_id != 0 && delta.delta != 0)
        .collect()
}

fn source_event_for_orb_delta<'a>(
    record: &JournalRecord,
    delta: &OrbDelta,
    events: &'a [EventView],
) -> Option<&'a EventView> {
    let preferred_type = match delta.reason.as_str() {
        "avatar_created" => Some("actor.created"),
        "ability_check_success" => Some("ability_check.rolled"),
        "combat_knockout" => Some("combat.knockout"),
        "combat_hit" => Some("combat.attack.hit"),
        "combat_outcome" => Some("combat.encounter.resolved"),
        "combat_flee" => Some("combat.flee.success"),
        "job_completed" => Some("job.updated"),
        "chat" => Some("chat.queued"),
        "chat_refund" => Some("chat.failed"),
        "listen" => Some("ability_check.rolled"),
        _ => None,
    };
    events
        .iter()
        .find(|event| {
            (event.success || delta.reason == "chat_refund")
                && event.actor_id == Some(delta.actor_id)
                && preferred_type
                    .map(|type_name| event.type_name == type_name)
                    .unwrap_or(true)
                && (delta.reason != "chat"
                    || record.action.content_id == 0
                    || event.content_id == Some(record.action.content_id))
        })
        .or_else(|| {
            events.iter().find(|event| {
                (event.success || delta.reason == "chat_refund")
                    && event.actor_id == Some(delta.actor_id)
            })
        })
        .or_else(|| {
            events
                .iter()
                .find(|event| event.success || delta.reason == "chat_refund")
        })
}

fn orb_ledger_entries_for_record(
    record: &JournalRecord,
    events: &[EventView],
    pre_orb_balances: &BTreeMap<u64, i32>,
    pre_orb_reward_claims: &BTreeSet<String>,
) -> Vec<OrbLedgerEntry> {
    let deltas = committed_orb_deltas(record, events, pre_orb_reward_claims);
    let mut balances = BTreeMap::new();
    for delta in &deltas {
        balances
            .entry(delta.actor_id)
            .or_insert_with(|| pre_orb_balances.get(&delta.actor_id).copied().unwrap_or(0));
    }

    deltas
        .into_iter()
        .enumerate()
        .map(|(index, delta)| {
            let current = balances.get(&delta.actor_id).copied().unwrap_or(0);
            let balance_after = current.saturating_add(delta.delta).max(0);
            balances.insert(delta.actor_id, balance_after);
            let source_event = source_event_for_orb_delta(record, &delta, events);
            let source_event_id = source_event.map(|event| event.seq);
            let idempotency_key = source_event_id
                .map(|seq| format!("orb:{seq}:{}:{}:{index}", delta.actor_id, delta.reason))
                .unwrap_or_else(|| {
                    format!(
                        "orb:seed:{}:{}:{}:{}:{index}",
                        record.seed, record.action.kind, delta.actor_id, delta.reason
                    )
                });
            let metadata_json = serde_json::json!({
                "action_kind": record.action.kind,
                "seed": record.seed,
                "source_event_type": source_event.map(|event| event.type_name.as_str()),
            })
            .to_string();
            OrbLedgerEntry {
                idempotency_key,
                actor_id: delta.actor_id,
                delta: delta.delta,
                reason: delta.reason,
                source_event_id,
                balance_after,
                metadata_json,
            }
        })
        .collect()
}

fn source_event_id_for_chat(events: &[EventView], actor_id: u64, content_id: u64) -> Option<u64> {
    events
        .iter()
        .find(|event| {
            event.type_name == "message.created"
                && event.success
                && event.actor_id == Some(actor_id)
                && event.content_id == Some(content_id)
        })
        .map(|event| event.seq)
}

fn record_ai_usage(
    state: &AppState,
    actor_id: Option<u64>,
    feature: &str,
    payer_mode: &str,
    config: Option<&AiConfig>,
    status: &str,
    source_event_id: Option<u64>,
    orb_delta: i32,
    error_code: Option<&str>,
    latency: Duration,
) {
    let Some(path) = state.event_store_path.as_deref() else {
        return;
    };
    let idempotency_key = source_event_id
        .map(|seq| format!("ai:{feature}:{seq}"))
        .unwrap_or_else(|| format!("ai:{feature}:{}:{}", actor_id.unwrap_or(0), now_seed()));
    let record = AiUsageLedgerRecord {
        idempotency_key,
        actor_id,
        feature: feature.to_string(),
        payer_mode: payer_mode.to_string(),
        provider: ai_provider_name(config).to_string(),
        model: ai_model_name(config),
        status: status.to_string(),
        source_event_id,
        orb_delta,
        error_code: error_code.map(ToString::to_string),
        latency_ms: latency.as_millis() as u64,
    };
    if let Err(error) = append_ai_usage_ledger(path, &record) {
        warn!(
            "failed to append CosyWorld v2 AI usage ledger to {}: {}",
            path.display(),
            error
        );
    }
}

fn commit_journal_record(
    state: &AppState,
    runtime: &mut RuntimeWorld,
    record: JournalRecord,
) -> io::Result<(u32, Vec<EventView>)> {
    let pre_orb_balances = runtime.orb_balances.clone();
    let pre_orb_reward_claims = runtime.orb_reward_claims.clone();
    let (status, events, _actor_job_inserted) = if let Some(path) =
        state.event_store_path.as_deref()
    {
        init_event_store(path)?;
        let mut conn = open_event_store(path)?;
        let tx = conn.transaction().map_err(sqlite_error)?;
        let committed = (|| -> io::Result<(u32, Vec<EventView>, bool)> {
            insert_action_journal(&tx, &record)?;
            let (status, events) = runtime.apply_journal_record(&record);
            let ledger_entries = orb_ledger_entries_for_record(
                &record,
                &events,
                &pre_orb_balances,
                &pre_orb_reward_claims,
            );
            if status == CW_OK {
                insert_orb_ledger_entries(&tx, &ledger_entries)?;
            }
            insert_world_events(&tx, &events)?;
            let observation_job_inserted =
                if status == CW_OK && record.origin == JournalOrigin::PlayerCard {
                    player_tick_observation(runtime, None, record.action.actor_id, status, &events)
                        .map(|observation| insert_actor_job(&tx, &observation))
                        .transpose()?
                        .unwrap_or(false)
                } else {
                    false
                };
            let queued_job_inserted = if status == CW_OK {
                match record.queued_actor_job.as_ref() {
                    Some(ActorJobPayload::OrbChat(job)) => {
                        let queue_event_id = events
                            .iter()
                            .find(|event| event.type_name == "chat.queued" && event.success)
                            .map(|event| event.seq);
                        insert_orb_chat_job(&tx, job, runtime.world.tick, queue_event_id)?
                    }
                    Some(_) => {
                        return Err(io::Error::new(
                            io::ErrorKind::InvalidData,
                            "journal queued an unsupported actor job payload",
                        ));
                    }
                    None => false,
                }
            } else {
                false
            };
            Ok((
                status,
                events,
                observation_job_inserted || queued_job_inserted,
            ))
        })();
        let committed = match committed {
            Ok(committed) => committed,
            Err(error) => {
                let rollback_error = tx.rollback().map_err(sqlite_error).err();
                let restore_error = restore_runtime_from_durable_state(state, runtime, path).err();
                return Err(journal_commit_recovery_error(
                    error,
                    rollback_error,
                    restore_error,
                ));
            }
        };
        if let Err(error) = tx.commit().map_err(sqlite_error) {
            let restore_error = restore_runtime_from_durable_state(state, runtime, path).err();
            return Err(journal_commit_recovery_error(error, None, restore_error));
        }
        committed
    } else {
        let (status, events) = runtime.apply_journal_record(&record);
        (status, events, false)
    };
    if !events.is_empty() {
        state.mark_activity();
    }
    persist_runtime(state, runtime);
    Ok((status, events))
}

fn restore_runtime_from_durable_state(
    state: &AppState,
    runtime: &mut RuntimeWorld,
    event_store_path: &Path,
) -> io::Result<()> {
    let mut restored = RuntimeWorld::from_action_journal(event_store_path)?;
    if let Some(path) = state.resident_continuity_path.as_deref() {
        match restored.load_resident_continuity_snapshot(path) {
            Ok(_) => {}
            Err(error) if error.kind() == io::ErrorKind::NotFound => {}
            Err(error) => return Err(error),
        }
    }
    if let Ok(ownership) = state.ownership_index.try_read() {
        let placement_rotation = placement_rotation_index_for_runtime(&restored);
        restored.apply_wallet_overlap_placements(&ownership, placement_rotation);
    }
    *runtime = restored;
    Ok(())
}

fn journal_commit_recovery_error(
    commit_error: io::Error,
    rollback_error: Option<io::Error>,
    restore_error: Option<io::Error>,
) -> io::Error {
    let mut message = commit_error.to_string();
    if let Some(error) = rollback_error {
        message.push_str(&format!("; transaction rollback failed: {error}"));
    }
    if let Some(error) = restore_error {
        message.push_str(&format!("; runtime journal recovery failed: {error}"));
    }
    io::Error::new(commit_error.kind(), message)
}

fn persist_runtime(state: &AppState, runtime: &RuntimeWorld) {
    if state.event_store_path.is_none() {
        if let Some(path) = state.snapshot_path.as_deref() {
            if let Err(error) = runtime.save_snapshot(path) {
                warn!(
                    "failed to persist CosyWorld v2 snapshot {}: {}",
                    path.display(),
                    error
                );
            }
        }
    }
    if let Some(path) = state.resident_continuity_path.as_deref() {
        if let Err(error) = runtime.save_resident_continuity_snapshot(path) {
            warn!(
                "failed to persist CosyWorld resident continuity artifact {}: {}",
                path.display(),
                error
            );
        }
    }
}

fn persist_events(state: &AppState, events: &[EventView]) {
    let Some(path) = state.event_store_path.as_deref() else {
        return;
    };
    if let Err(error) = append_event_store(path, events) {
        warn!(
            "failed to append CosyWorld v2 events to {}: {}",
            path.display(),
            error
        );
    }
}

const INDEX_HTML: &str = include_str!("index.html");
const MODERATION_HTML: &str = include_str!("moderation.html");

fn snapshot_path_from_env() -> Option<PathBuf> {
    match std::env::var("COSYWORLD_V2_SNAPSHOT_PATH") {
        Ok(value) if value.trim().is_empty() => None,
        Ok(value) if value.eq_ignore_ascii_case("off") || value.eq_ignore_ascii_case("none") => {
            None
        }
        Ok(value) => Some(PathBuf::from(value)),
        Err(_) => Some(PathBuf::from(".runtime/cosyworld-v2-snapshot.json")),
    }
}

fn resident_continuity_path_from_env(snapshot_path: Option<&PathBuf>) -> Option<PathBuf> {
    match std::env::var("COSYWORLD_V2_RESIDENT_CONTINUITY_PATH") {
        Ok(value) if value.trim().is_empty() => None,
        Ok(value) if value.eq_ignore_ascii_case("off") || value.eq_ignore_ascii_case("none") => {
            None
        }
        Ok(value) => Some(PathBuf::from(value)),
        Err(_) => Some(default_resident_continuity_path(snapshot_path)),
    }
}

fn default_resident_continuity_path(snapshot_path: Option<&PathBuf>) -> PathBuf {
    let Some(snapshot_path) = snapshot_path else {
        return PathBuf::from(".runtime/cosyworld-v2-resident-continuity.json");
    };
    let stem = snapshot_path
        .file_stem()
        .and_then(|value| value.to_str())
        .filter(|value| !value.is_empty())
        .unwrap_or("cosyworld-v2");
    let base = stem.strip_suffix("-snapshot").unwrap_or(stem);
    snapshot_path.with_file_name(format!("{base}-resident-continuity.json"))
}

fn load_snapshot_or_seed(snapshot_path: Option<&PathBuf>) -> RuntimeWorld {
    match snapshot_path {
        Some(path) => match RuntimeWorld::load_snapshot(path) {
            Ok(runtime) => {
                info!("loaded CosyWorld v2 snapshot from {}", path.display());
                runtime
            }
            Err(error) => {
                warn!(
                    "starting fresh CosyWorld v2 world; failed to load snapshot {}: {}",
                    path.display(),
                    error
                );
                RuntimeWorld::seeded()
            }
        },
        None => RuntimeWorld::seeded(),
    }
}

fn event_store_path_from_env() -> Option<PathBuf> {
    match std::env::var("COSYWORLD_V2_EVENT_DB_PATH") {
        Ok(value) if value.trim().is_empty() => None,
        Ok(value) if value.eq_ignore_ascii_case("off") || value.eq_ignore_ascii_case("none") => {
            None
        }
        Ok(value) => Some(PathBuf::from(value)),
        Err(_) => Some(PathBuf::from(".runtime/cosyworld-v2-events.sqlite")),
    }
}

fn init_event_store(path: &Path) -> io::Result<()> {
    if let Some(parent) = path.parent() {
        if !parent.as_os_str().is_empty() {
            fs::create_dir_all(parent)?;
        }
    }
    let conn = open_event_store(path)?;
    conn.execute_batch(
        "CREATE TABLE IF NOT EXISTS world_events (
            seq INTEGER PRIMARY KEY,
            event_type TEXT NOT NULL,
            payload_json TEXT NOT NULL,
            created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_world_events_type ON world_events(event_type);
        CREATE TABLE IF NOT EXISTS room_memory_chapters (
            location_id INTEGER NOT NULL,
            day_index INTEGER NOT NULL,
            latest_seq INTEGER NOT NULL,
            summary TEXT NOT NULL,
            source TEXT NOT NULL,
            updated_at_ms INTEGER NOT NULL,
            PRIMARY KEY (location_id, day_index)
        );
        CREATE INDEX IF NOT EXISTS idx_room_memory_chapters_location_day
            ON room_memory_chapters(location_id, day_index);
        CREATE TABLE IF NOT EXISTS action_journal (
            journal_seq INTEGER PRIMARY KEY AUTOINCREMENT,
            action_kind INTEGER NOT NULL,
            seed INTEGER NOT NULL,
            record_json TEXT NOT NULL,
            created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_action_journal_kind ON action_journal(action_kind);
        CREATE TABLE IF NOT EXISTS actor_jobs (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            kind TEXT NOT NULL,
            actor_id INTEGER NOT NULL,
            cause_event_seq INTEGER,
            source_tick INTEGER NOT NULL,
            observed_through_seq INTEGER NOT NULL,
            location_id INTEGER,
            status TEXT NOT NULL DEFAULT 'pending',
            attempts INTEGER NOT NULL DEFAULT 0,
            lease_until_ms INTEGER,
            available_at_ms INTEGER NOT NULL DEFAULT 0,
            context_json TEXT NOT NULL,
            dedupe_key TEXT NOT NULL UNIQUE,
            last_error TEXT,
            created_at_ms INTEGER NOT NULL,
            updated_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_actor_jobs_ready
            ON actor_jobs(status, available_at_ms, lease_until_ms, id);
        CREATE INDEX IF NOT EXISTS idx_actor_jobs_actor
            ON actor_jobs(actor_id, status, id);
        CREATE TABLE IF NOT EXISTS actor_sessions (
            session_token TEXT PRIMARY KEY,
            actor_id INTEGER NOT NULL,
            expires_at_unix INTEGER NOT NULL,
            created_at_ms INTEGER NOT NULL,
            updated_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_actor_sessions_actor_id ON actor_sessions(actor_id);
        CREATE INDEX IF NOT EXISTS idx_actor_sessions_expires_at ON actor_sessions(expires_at_unix);
        CREATE TABLE IF NOT EXISTS wallet_avatar_links (
            wallet_address TEXT PRIMARY KEY,
            actor_id INTEGER NOT NULL,
            created_at_ms INTEGER NOT NULL,
            updated_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_wallet_avatar_links_actor_id ON wallet_avatar_links(actor_id);
        CREATE TABLE IF NOT EXISTS actor_suspensions (
            actor_id INTEGER PRIMARY KEY,
            reason TEXT NOT NULL,
            created_at_unix INTEGER NOT NULL,
            updated_at_ms INTEGER NOT NULL
        );
        CREATE TABLE IF NOT EXISTS moderation_reports (
            report_id INTEGER PRIMARY KEY AUTOINCREMENT,
            status TEXT NOT NULL DEFAULT 'open',
            reporter_actor_id INTEGER NOT NULL,
            reporter_actor_name TEXT NOT NULL,
            reporter_actor_kind TEXT NOT NULL DEFAULT 'human',
            target_actor_id INTEGER NOT NULL,
            target_actor_name TEXT NOT NULL,
            target_actor_kind TEXT NOT NULL DEFAULT 'unknown',
            location_id INTEGER NOT NULL,
            location_name TEXT NOT NULL,
            reason TEXT NOT NULL,
            created_at_ms INTEGER NOT NULL,
            resolved_at_ms INTEGER,
            resolved_by TEXT,
            resolution_note TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_moderation_reports_target ON moderation_reports(target_actor_id);
        CREATE INDEX IF NOT EXISTS idx_moderation_reports_created ON moderation_reports(created_at_ms);
        CREATE TABLE IF NOT EXISTS orb_ledger (
            idempotency_key TEXT PRIMARY KEY,
            actor_id INTEGER NOT NULL,
            delta INTEGER NOT NULL,
            reason TEXT NOT NULL,
            source_event_id INTEGER,
            balance_after INTEGER NOT NULL,
            metadata_json TEXT NOT NULL,
            created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_orb_ledger_actor_id ON orb_ledger(actor_id);
        CREATE INDEX IF NOT EXISTS idx_orb_ledger_source_event_id ON orb_ledger(source_event_id);
        CREATE TABLE IF NOT EXISTS ai_usage_ledger (
            idempotency_key TEXT PRIMARY KEY,
            actor_id INTEGER,
            feature TEXT NOT NULL,
            payer_mode TEXT NOT NULL,
            provider TEXT NOT NULL,
            model TEXT NOT NULL,
            status TEXT NOT NULL,
            source_event_id INTEGER,
            orb_delta INTEGER NOT NULL DEFAULT 0,
            error_code TEXT,
            latency_ms INTEGER NOT NULL DEFAULT 0,
            created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_ai_usage_ledger_actor_id ON ai_usage_ledger(actor_id);
        CREATE INDEX IF NOT EXISTS idx_ai_usage_ledger_source_event_id ON ai_usage_ledger(source_event_id);
        CREATE TABLE IF NOT EXISTS wooden_box_receipts (
            box_asset_address TEXT PRIMARY KEY,
            owner_wallet_address TEXT NOT NULL,
            status TEXT NOT NULL,
            burn_signature TEXT NOT NULL UNIQUE,
            verification_status TEXT NOT NULL,
            metadata_uri TEXT,
            pack_id TEXT NOT NULL UNIQUE,
            created_at_ms INTEGER NOT NULL,
            updated_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_wooden_box_receipts_owner ON wooden_box_receipts(owner_wallet_address);
        CREATE TABLE IF NOT EXISTS avatar_pack_openings (
            idempotency_key TEXT PRIMARY KEY,
            owner_wallet_address TEXT NOT NULL,
            box_asset_address TEXT,
            pack_id TEXT NOT NULL UNIQUE,
            reveal_seed TEXT NOT NULL,
            catalog_hash TEXT NOT NULL,
            card_ids_json TEXT NOT NULL,
            provenance_json TEXT NOT NULL,
            created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_avatar_pack_openings_owner ON avatar_pack_openings(owner_wallet_address);
        CREATE TABLE IF NOT EXISTS economy_reconciliation_runs (
            run_id INTEGER PRIMARY KEY AUTOINCREMENT,
            source TEXT NOT NULL,
            wallet_count INTEGER NOT NULL,
            active_box_count INTEGER NOT NULL,
            unopened_pack_count INTEGER NOT NULL,
            anomaly_count INTEGER NOT NULL,
            anomalies_json TEXT NOT NULL,
            status TEXT NOT NULL DEFAULT 'open',
            created_at_ms INTEGER NOT NULL,
            resolved_at_ms INTEGER,
            resolved_by TEXT,
            resolution_note TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_economy_reconciliation_runs_created
            ON economy_reconciliation_runs(created_at_ms);",
    )
    .map_err(sqlite_error)?;
    init_activation_store(&conn)?;
    ensure_sqlite_column(
        &conn,
        "moderation_reports",
        "reporter_actor_kind",
        "ALTER TABLE moderation_reports ADD COLUMN reporter_actor_kind TEXT NOT NULL DEFAULT 'human'",
    )?;
    ensure_sqlite_column(
        &conn,
        "moderation_reports",
        "target_actor_kind",
        "ALTER TABLE moderation_reports ADD COLUMN target_actor_kind TEXT NOT NULL DEFAULT 'unknown'",
    )?;
    ensure_sqlite_column(
        &conn,
        "moderation_reports",
        "status",
        "ALTER TABLE moderation_reports ADD COLUMN status TEXT NOT NULL DEFAULT 'open'",
    )?;
    ensure_sqlite_column(
        &conn,
        "moderation_reports",
        "resolved_at_ms",
        "ALTER TABLE moderation_reports ADD COLUMN resolved_at_ms INTEGER",
    )?;
    ensure_sqlite_column(
        &conn,
        "moderation_reports",
        "resolved_by",
        "ALTER TABLE moderation_reports ADD COLUMN resolved_by TEXT",
    )?;
    ensure_sqlite_column(
        &conn,
        "moderation_reports",
        "resolution_note",
        "ALTER TABLE moderation_reports ADD COLUMN resolution_note TEXT",
    )?;
    ensure_sqlite_column(
        &conn,
        "economy_reconciliation_runs",
        "status",
        "ALTER TABLE economy_reconciliation_runs ADD COLUMN status TEXT NOT NULL DEFAULT 'open'",
    )?;
    ensure_sqlite_column(
        &conn,
        "economy_reconciliation_runs",
        "resolved_at_ms",
        "ALTER TABLE economy_reconciliation_runs ADD COLUMN resolved_at_ms INTEGER",
    )?;
    ensure_sqlite_column(
        &conn,
        "economy_reconciliation_runs",
        "resolved_by",
        "ALTER TABLE economy_reconciliation_runs ADD COLUMN resolved_by TEXT",
    )?;
    ensure_sqlite_column(
        &conn,
        "economy_reconciliation_runs",
        "resolution_note",
        "ALTER TABLE economy_reconciliation_runs ADD COLUMN resolution_note TEXT",
    )?;
    conn.execute(
        "UPDATE economy_reconciliation_runs
         SET status = 'clear'
         WHERE anomaly_count = 0 AND status = 'open' AND resolved_at_ms IS NULL",
        [],
    )
    .map_err(sqlite_error)?;
    conn.execute(
        "CREATE INDEX IF NOT EXISTS idx_moderation_reports_status ON moderation_reports(status, report_id)",
        [],
    )
    .map_err(sqlite_error)?;
    Ok(())
}

fn ensure_sqlite_column(
    conn: &Connection,
    table: &str,
    column: &str,
    alter_sql: &str,
) -> io::Result<()> {
    let pragma = format!("PRAGMA table_info({table})");
    let mut stmt = conn.prepare(&pragma).map_err(sqlite_error)?;
    let rows = stmt
        .query_map([], |row| row.get::<_, String>(1))
        .map_err(sqlite_error)?;
    for row in rows {
        if row.map_err(sqlite_error)? == column {
            return Ok(());
        }
    }
    conn.execute(alter_sql, []).map_err(sqlite_error)?;
    Ok(())
}

fn action_journal_has_records(path: &Path) -> io::Result<bool> {
    let conn = open_event_store(path)?;
    let count: i64 = conn
        .query_row("SELECT COUNT(*) FROM action_journal", [], |row| row.get(0))
        .map_err(sqlite_error)?;
    Ok(count > 0)
}

#[cfg(test)]
fn append_action_journal(path: &Path, record: &JournalRecord) -> io::Result<()> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    insert_action_journal(&conn, record)
}

fn insert_action_journal(conn: &Connection, record: &JournalRecord) -> io::Result<()> {
    let payload = serde_json::to_string(record)
        .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
    conn.execute(
        "INSERT INTO action_journal (action_kind, seed, record_json, created_at_ms)
         VALUES (?1, ?2, ?3, ?4)",
        params![
            record.action.kind as i64,
            record.seed as i64,
            payload,
            now_millis() as i64
        ],
    )
    .map_err(sqlite_error)?;
    Ok(())
}

fn actor_job_dedupe_key(observation: &PlayerTickObservation) -> String {
    format!(
        "player-tick:{}:{}:{}",
        observation.source_world_tick,
        observation.caused_by_event_seq.unwrap_or(0),
        observation.source_actor_id
    )
}

fn insert_actor_job(conn: &Connection, observation: &PlayerTickObservation) -> io::Result<bool> {
    let payload = ActorJobPayload::PlayerTick(observation.clone());
    insert_actor_job_payload(
        conn,
        ACTOR_JOB_KIND_PLAYER_TICK,
        observation.source_actor_id,
        observation.caused_by_event_seq,
        observation.source_world_tick,
        observation.observed_through_seq,
        observation.source_location_id,
        &actor_job_dedupe_key(observation),
        &payload,
    )
}

fn insert_orb_chat_job(
    conn: &Connection,
    job: &OrbChatJob,
    source_tick: u64,
    queue_event_id: Option<u64>,
) -> io::Result<bool> {
    let mut job = job.clone();
    job.queue_event_id = queue_event_id.or(job.queue_event_id);
    job.source_world_tick = Some(source_tick);
    job.observed_through_seq = job.queue_event_id;
    let payload = ActorJobPayload::OrbChat(job.clone());
    let cause_event_seq = job.queue_event_id;
    insert_actor_job_payload(
        conn,
        ACTOR_JOB_KIND_ORB_CHAT,
        job.actor_id,
        cause_event_seq,
        source_tick,
        cause_event_seq.unwrap_or(0),
        Some(job.plan.location_id),
        &format!(
            "orb-chat:{}:{}:{}",
            job.actor_id,
            job.target_actor_id,
            cause_event_seq.unwrap_or(0)
        ),
        &payload,
    )
}

fn actor_has_active_job(path: &Path, actor_id: u64, kind: &str) -> io::Result<bool> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let count: i64 = conn
        .query_row(
            "SELECT COUNT(*) FROM actor_jobs
             WHERE actor_id = ?1 AND kind = ?2 AND status IN ('pending', 'running')",
            params![actor_id as i64, kind],
            |row| row.get(0),
        )
        .map_err(sqlite_error)?;
    Ok(count > 0)
}

#[allow(clippy::too_many_arguments)]
fn insert_actor_job_payload(
    conn: &Connection,
    kind: &str,
    actor_id: u64,
    cause_event_seq: Option<u64>,
    source_tick: u64,
    observed_through_seq: u64,
    location_id: Option<u64>,
    dedupe_key: &str,
    payload: &ActorJobPayload,
) -> io::Result<bool> {
    let context_json = serde_json::to_string(payload)
        .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
    let now = now_millis() as i64;
    let inserted = conn
        .execute(
            "INSERT OR IGNORE INTO actor_jobs
                (kind, actor_id, cause_event_seq, source_tick, observed_through_seq,
                 location_id, status, attempts, lease_until_ms, available_at_ms,
                 context_json, dedupe_key, created_at_ms, updated_at_ms)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, 'pending', 0, NULL, ?7, ?8, ?9, ?7, ?7)",
            params![
                kind,
                actor_id as i64,
                cause_event_seq.map(|seq| seq as i64),
                source_tick as i64,
                observed_through_seq as i64,
                location_id.map(|id| id as i64),
                now,
                context_json,
                dedupe_key,
            ],
        )
        .map_err(sqlite_error)?;
    Ok(inserted > 0)
}

