fn claim_next_actor_job(path: &Path) -> io::Result<Option<ActorJob>> {
    claim_next_actor_job_filtered(path, None)
}

fn claim_next_actor_job_of_kind(path: &Path, kind: &str) -> io::Result<Option<ActorJob>> {
    claim_next_actor_job_filtered(path, Some(kind))
}

fn claim_next_actor_job_filtered(
    path: &Path,
    claimed_kind: Option<&str>,
) -> io::Result<Option<ActorJob>> {
    init_event_store(path)?;
    let mut conn = open_event_store(path)?;
    let tx = conn.transaction().map_err(sqlite_error)?;
    let now = now_millis() as i64;
    let row = tx
        .query_row(
            "SELECT id, kind, actor_id, attempts, context_json
             FROM actor_jobs
             WHERE ((status = 'pending' AND available_at_ms <= ?1)
                OR (status = 'running' AND lease_until_ms IS NOT NULL AND lease_until_ms <= ?1))
               AND (?2 IS NULL OR actor_jobs.kind = ?2)
               AND NOT EXISTS (
                   SELECT 1 FROM actor_jobs AS active
                   WHERE active.actor_id = actor_jobs.actor_id
                     AND active.kind = actor_jobs.kind
                     AND active.id != actor_jobs.id
                     AND active.status = 'running'
                     AND active.lease_until_ms > ?1
               )
             ORDER BY source_tick ASC, id ASC
             LIMIT 1",
            params![now, claimed_kind],
            |row| {
                Ok((
                    row.get::<_, i64>(0)?,
                    row.get::<_, String>(1)?,
                    row.get::<_, i64>(2)?,
                    row.get::<_, i64>(3)?,
                    row.get::<_, String>(4)?,
                ))
            },
        )
        .optional()
        .map_err(sqlite_error)?;
    let Some((id, kind, actor_id, attempts, context_json)) = row else {
        tx.commit().map_err(sqlite_error)?;
        return Ok(None);
    };
    let next_attempt = attempts.max(0).saturating_add(1);
    let lease_until = now.saturating_add(ACTOR_JOB_LEASE_MS as i64);
    let claimed = tx
        .execute(
            "UPDATE actor_jobs
             SET status = 'running', attempts = ?2, lease_until_ms = ?3, updated_at_ms = ?4
             WHERE id = ?1
               AND ((status = 'pending' AND available_at_ms <= ?4)
                 OR (status = 'running' AND lease_until_ms IS NOT NULL AND lease_until_ms <= ?4))",
            params![id, next_attempt, lease_until, now],
        )
        .map_err(sqlite_error)?;
    if claimed == 0 {
        tx.commit().map_err(sqlite_error)?;
        return Ok(None);
    }
    tx.commit().map_err(sqlite_error)?;
    let payload = serde_json::from_str(&context_json)
        .or_else(|primary_error| {
            if kind == ACTOR_JOB_KIND_PLAYER_TICK {
                serde_json::from_str::<PlayerTickObservation>(&context_json)
                    .map(ActorJobPayload::PlayerTick)
            } else {
                Err(primary_error)
            }
        })
        .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
    Ok(Some(ActorJob {
        id,
        kind,
        actor_id: actor_id.max(0) as u64,
        attempts: next_attempt.max(0) as u32,
        payload,
    }))
}

fn complete_actor_job(path: &Path, job_id: i64) -> io::Result<()> {
    let conn = open_event_store(path)?;
    conn.execute(
        "UPDATE actor_jobs
         SET status = 'completed', lease_until_ms = NULL, last_error = NULL, updated_at_ms = ?2
         WHERE id = ?1",
        params![job_id, now_millis() as i64],
    )
    .map_err(sqlite_error)?;
    Ok(())
}

fn fail_or_retry_actor_job(path: &Path, job: &ActorJob, error: &str) -> io::Result<()> {
    let conn = open_event_store(path)?;
    let terminal = job.attempts >= ACTOR_JOB_MAX_ATTEMPTS;
    let backoff_ms = 250_u64.saturating_mul(1_u64 << job.attempts.saturating_sub(1).min(5));
    let now = now_millis();
    conn.execute(
        "UPDATE actor_jobs
         SET status = ?2, lease_until_ms = NULL, available_at_ms = ?3,
             last_error = ?4, updated_at_ms = ?5
         WHERE id = ?1",
        params![
            job.id,
            if terminal { "dead" } else { "pending" },
            now.saturating_add(backoff_ms) as i64,
            trim_to_chars(error, 500),
            now as i64,
        ],
    )
    .map_err(sqlite_error)?;
    Ok(())
}

fn read_action_journal(path: &Path) -> io::Result<Vec<JournalRecord>> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let mut stmt = conn
        .prepare("SELECT record_json FROM action_journal ORDER BY journal_seq ASC")
        .map_err(sqlite_error)?;
    let rows = stmt
        .query_map([], |row| row.get::<_, String>(0))
        .map_err(sqlite_error)?;
    let mut records = Vec::new();
    for row in rows {
        let payload = row.map_err(sqlite_error)?;
        let record = serde_json::from_str(&payload)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        records.push(record);
    }
    Ok(records)
}

fn load_actor_sessions(path: &Path) -> io::Result<ActorSessions> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let now_unix = now_unix_secs();
    conn.execute(
        "DELETE FROM actor_sessions WHERE expires_at_unix <= ?1",
        params![now_unix as i64],
    )
    .map_err(sqlite_error)?;
    let now = Instant::now();
    let mut stmt = conn
        .prepare(
            "SELECT session_token, actor_id, expires_at_unix
             FROM actor_sessions
             WHERE expires_at_unix > ?1
             ORDER BY updated_at_ms DESC",
        )
        .map_err(sqlite_error)?;
    let rows = stmt
        .query_map(params![now_unix as i64], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, i64>(1)?,
                row.get::<_, i64>(2)?,
            ))
        })
        .map_err(sqlite_error)?;

    let mut sessions = ActorSessions::default();
    let inactive_seen_at = inactive_presence_seen_at(now);
    for row in rows {
        let (token, actor_id, expires_at_unix) = row.map_err(sqlite_error)?;
        if token.trim().is_empty() || actor_id <= 0 || expires_at_unix <= now_unix as i64 {
            continue;
        }
        sessions.sessions.insert(
            token,
            ActorSession {
                actor_id: actor_id as u64,
                expires_at: now + Duration::from_secs((expires_at_unix as u64) - now_unix),
                expires_at_unix: expires_at_unix as u64,
                last_seen_at: inactive_seen_at,
                explicitly_inactive: true,
            },
        );
    }
    Ok(sessions)
}

fn persist_actor_session(path: &Path, token: &str, session: &ActorSession) -> io::Result<()> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let now_ms = now_millis() as i64;
    conn.execute(
        "INSERT INTO actor_sessions
            (session_token, actor_id, expires_at_unix, created_at_ms, updated_at_ms)
         VALUES (?1, ?2, ?3, ?4, ?4)
         ON CONFLICT(session_token) DO UPDATE SET
            actor_id = excluded.actor_id,
            expires_at_unix = excluded.expires_at_unix,
            updated_at_ms = excluded.updated_at_ms",
        params![
            token,
            session.actor_id as i64,
            session.expires_at_unix as i64,
            now_ms,
        ],
    )
    .map_err(sqlite_error)?;
    Ok(())
}

