fn append_event_store(path: &Path, events: &[EventView]) -> io::Result<()> {
    if events.is_empty() {
        return Ok(());
    }
    init_event_store(path)?;
    let mut conn = open_event_store(path)?;
    let tx = conn.transaction().map_err(sqlite_error)?;
    insert_world_events(&tx, events)?;
    tx.commit().map_err(sqlite_error)?;
    Ok(())
}

fn insert_world_events(conn: &Connection, events: &[EventView]) -> io::Result<()> {
    let mut stmt = conn
        .prepare(
            "INSERT OR IGNORE INTO world_events
             (seq, event_type, payload_json, created_at_ms)
             VALUES (?1, ?2, ?3, ?4)",
        )
        .map_err(sqlite_error)?;
    let now = now_millis();
    for event in events {
        let payload = serde_json::to_string(event)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        stmt.execute(params![
            event.seq as i64,
            event.type_name,
            payload,
            now as i64
        ])
        .map_err(sqlite_error)?;
    }
    Ok(())
}

