fn load_room_memory_prior_chapters(
    path: &Path,
    location_id: u64,
    before_day_index: u64,
    limit: usize,
) -> io::Result<Vec<RoomMemoryChapter>> {
    if limit == 0 || before_day_index == 0 {
        return Ok(Vec::new());
    }
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let mut stmt = conn
        .prepare(
            "SELECT location_id, day_index, latest_seq, summary, source
             FROM room_memory_chapters
             WHERE location_id = ?1 AND day_index < ?2
             ORDER BY day_index DESC
             LIMIT ?3",
        )
        .map_err(sqlite_error)?;
    let rows = stmt
        .query_map(
            params![
                location_id as i64,
                before_day_index as i64,
                limit.min(24) as i64
            ],
            |row| {
                Ok(RoomMemoryChapter {
                    location_id: row.get::<_, i64>(0)?.max(0) as u64,
                    day_index: row.get::<_, i64>(1)?.max(0) as u64,
                    latest_seq: row.get::<_, i64>(2)?.max(0) as u64,
                    summary: row.get(3)?,
                    source: row.get(4)?,
                })
            },
        )
        .map_err(sqlite_error)?;
    let mut chapters = Vec::new();
    for row in rows {
        chapters.push(row.map_err(sqlite_error)?);
    }
    chapters.reverse();
    Ok(chapters)
}

fn max_event_store_seq(path: &Path) -> io::Result<u64> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let max_seq: Option<i64> = conn
        .query_row("SELECT MAX(seq) FROM world_events", [], |row| row.get(0))
        .map_err(sqlite_error)?;
    Ok(max_seq.unwrap_or(0).max(0) as u64)
}

fn advance_runtime_next_event_seq_from_store(
    runtime: &mut RuntimeWorld,
    path: &Path,
) -> io::Result<()> {
    let max_seq = max_event_store_seq(path)?;
    if runtime.world.next_event_seq <= max_seq {
        runtime.world.next_event_seq = max_seq.saturating_add(1);
    }
    Ok(())
}

