    fn signed_narrative_move(
        signing_key: &ed25519_dalek::SigningKey,
        wallet_address: &str,
        session_id: &str,
        character_id: u64,
        command: &str,
        nonce: &str,
        issued_at_unix: u64,
    ) -> SignedNarrativeMove {
        use ed25519_dalek::Signer;

        let command = normalize_command_text(command);
        let message = narrative_move_signature_message(
            wallet_address,
            session_id,
            character_id,
            &command,
            nonce,
            issued_at_unix,
        );
        SignedNarrativeMove {
            wallet_address: wallet_address.to_string(),
            command,
            nonce: nonce.to_string(),
            issued_at_unix,
            signature: WalletSignatureInput::Bytes(
                signing_key.sign(message.as_bytes()).to_bytes().to_vec(),
            ),
            delegation: None,
        }
    }

    fn signed_narrative_move_delegation(
        owner_signing_key: &ed25519_dalek::SigningKey,
        wallet_address: &str,
        delegate_address: &str,
        session_id: &str,
        character_id: u64,
        issued_at_unix: u64,
        expires_at_unix: u64,
    ) -> NarrativeMoveDelegation {
        use ed25519_dalek::Signer;

        let message = narrative_move_delegation_message(
            wallet_address,
            delegate_address,
            session_id,
            character_id,
            issued_at_unix,
            expires_at_unix,
        );
        NarrativeMoveDelegation {
            delegate_address: delegate_address.to_string(),
            issued_at_unix,
            expires_at_unix,
            signature: WalletSignatureInput::Bytes(
                owner_signing_key
                    .sign(message.as_bytes())
                    .to_bytes()
                    .to_vec(),
            ),
        }
    }

    fn delegated_narrative_move(
        delegate_signing_key: &ed25519_dalek::SigningKey,
        wallet_address: &str,
        delegate_address: &str,
        session_id: &str,
        character_id: u64,
        command: &str,
        nonce: &str,
        issued_at_unix: u64,
        delegation: NarrativeMoveDelegation,
    ) -> SignedNarrativeMove {
        use ed25519_dalek::Signer;

        let command = normalize_command_text(command);
        let message = delegated_narrative_move_signature_message(
            wallet_address,
            delegate_address,
            session_id,
            character_id,
            &command,
            nonce,
            issued_at_unix,
        );
        SignedNarrativeMove {
            wallet_address: wallet_address.to_string(),
            command,
            nonce: nonce.to_string(),
            issued_at_unix,
            signature: WalletSignatureInput::Bytes(
                delegate_signing_key
                    .sign(message.as_bytes())
                    .to_bytes()
                    .to_vec(),
            ),
            delegation: Some(delegation),
        }
    }

    #[test]
    fn action_backed_command_failures_include_visible_output() {
        let resolved = ResolvedCommand {
            command: "attack Coach".to_string(),
            verb: "attack".to_string(),
            action: Some(command_action("attack", "Attack", "attack Coach")),
            dispatch: CommandDispatch::Attack {
                target_actor_id: 1004,
            },
        };
        let lost = command_action_failure_output(&resolved, 500);
        let reconnect = command_action_failure_output(&resolved, 403);
        let hurried = command_action_failure_output(&resolved, RATE_LIMITED_STATUS);

        let Json(response) = command_action_response_with_events(
            resolved,
            ActionResponse {
                ok: false,
                status: 409,
                events: Vec::new(),
            },
            Vec::new(),
        );

        assert!(!response.ok);
        assert_eq!(
            response.output.as_deref(),
            Some("There is no need to fight here now.")
        );
        assert_eq!(
            lost,
            "That choice got lost before the room could answer. Try once more."
        );
        assert_eq!(
            reconnect,
            "Your avatar slipped out of reach. Begin again or reconnect your account."
        );
        assert_eq!(hurried, "The room needs a breath. Try again in a moment.");
        assert!(![lost, reconnect, hurried].iter().any(|copy| {
            let lowered = copy.to_lowercase();
            lowered.contains("committed")
                || lowered.contains("session")
                || lowered.contains("status")
        }));
    }

