    #[test]
    fn search_found_items_return_to_hidden_pool_when_forgotten() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Pocket Finder",
        );
        for item in &mut runtime.world.items[..runtime.world.item_count] {
            if item.id == HEARTH_TONIC_ITEM_ID {
                item.location_id = 0;
                item.holder_actor_id = 5000;
            }
        }
        assert!(runtime.room_floor_empty(COSY_COTTAGE_LOCATION_ID));
        assert_eq!(
            runtime.hidden_search_item_for_location(COSY_COTTAGE_LOCATION_ID),
            Some(STORY_BUTTON_ITEM_ID)
        );

        let mut record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_SEARCH,
                actor_id: 5000,
                location_id: COSY_COTTAGE_LOCATION_ID,
                content_id: 91_003,
                item_id: STORY_BUTTON_ITEM_ID,
                ..CwAction::default()
            },
            91_003,
        );
        record.content_upserts.insert(
            91_003,
            "Scarf Basket: a warm wooden button turns up.".to_string(),
        );
        record
            .projection_mutations
            .push(ProjectionMutation::RememberSearchItem {
                item_id: STORY_BUTTON_ITEM_ID,
                location_id: COSY_COTTAGE_LOCATION_ID,
                reason: "search_feature".to_string(),
            });
        let (status, events) = runtime.apply_journal_record(&record);
        assert_eq!(status, CW_OK);
        assert!(events
            .iter()
            .any(|event| event.type_name == "item.found"
                && event.item_id == Some(STORY_BUTTON_ITEM_ID)));
        assert!(runtime.search_item_remembered(STORY_BUTTON_ITEM_ID));
        assert!(runtime
            .state_response(Some(5000), &AccessContext::default())
            .items
            .iter()
            .any(|item| item.id == STORY_BUTTON_ITEM_ID));

        runtime.world.tick = runtime
            .world
            .tick
            .saturating_add(SEARCH_MEMORY_TIME_DECAY_INTERVAL_TICKS * 64);
        runtime.decay_search_memories();

        assert!(!runtime.search_item_remembered(STORY_BUTTON_ITEM_ID));
        assert_eq!(
            runtime
                .item_by_id(STORY_BUTTON_ITEM_ID)
                .map(|item| item.location_id),
            Some(0)
        );
        assert_eq!(
            runtime.hidden_search_item_for_location(COSY_COTTAGE_LOCATION_ID),
            Some(STORY_BUTTON_ITEM_ID)
        );
        assert!(!runtime
            .state_response(Some(5000), &AccessContext::default())
            .items
            .iter()
            .any(|item| item.id == STORY_BUTTON_ITEM_ID));
    }

    #[tokio::test]
    async fn lonely_forest_source_characters_are_seeded_with_png_cards() {
        let content = parse_seed_content(SEED_CONTENT_JSON).expect("seed content parses");
        let runtime = RuntimeWorld::seeded();

        let placed_seed_actors: Vec<&SeedActorContent> = content
            .actors
            .iter()
            .filter(|actor| actor.location_id.is_some())
            .collect();
        assert_eq!(placed_seed_actors.len(), 55);
        for actor in placed_seed_actors {
            let world_actor = runtime.actor_by_id(actor.id).expect("placed seed actor");
            assert_eq!(world_actor.location_id, actor.location_id.unwrap());
            assert_eq!(world_actor.kind, CW_ACTOR_NPC);
            assert_eq!(world_actor.stats.hp_base, seed_actor_stats(actor).hp_base);
        }

        let lonely_forest_actor_cards: Vec<&SeedCardContent> = content
            .cards
            .iter()
            .filter(|card| {
                card.subject_kind == "actor"
                    && card
                        .image_url
                        .as_deref()
                        .is_some_and(|url| url.starts_with(LONELY_FOREST_CHARACTER_ASSET_PREFIX))
            })
            .collect();
        assert_eq!(lonely_forest_actor_cards.len(), 25);
        for card in lonely_forest_actor_cards {
            let image_url = card.image_url.as_deref().expect("Lonely Forest image URL");
            let asset_file = image_url
                .strip_prefix(LONELY_FOREST_CHARACTER_ASSET_PREFIX)
                .expect("Lonely Forest asset prefix");
            assert!(
                lonely_forest_character_asset_exists(asset_file),
                "missing manifest asset for {}",
                card.card_id
            );

            let projected = card_for_actor(card.subject_id, &card.display_name, &card.title, "", 1);
            assert_eq!(projected.image_url.as_deref(), Some(image_url));
            assert_eq!(projected.asset_status, "source_art");
        }

        let response = lonely_forest_character_asset(AxumPath("10-woodland-bear.png".to_string()))
            .await
            .into_response();
        assert_eq!(response.status(), StatusCode::OK);
        assert_eq!(
            response
                .headers()
                .get(header::CONTENT_TYPE)
                .and_then(|value| value.to_str().ok()),
            Some("image/png")
        );

        let missing =
            lonely_forest_character_asset(AxumPath("../10-woodland-bear.png".to_string()))
                .await
                .into_response();
        assert_eq!(missing.status(), StatusCode::NOT_FOUND);

        let generated = generated_seed_card_asset(AxumPath("cosy-whiskerwind.webp".to_string()))
            .await
            .into_response();
        assert_eq!(generated.status(), StatusCode::OK);
        assert_eq!(
            generated
                .headers()
                .get(header::CONTENT_TYPE)
                .and_then(|value| value.to_str().ok()),
            Some("image/webp")
        );

        let missing_generated =
            generated_seed_card_asset(AxumPath("../cosy-whiskerwind.webp".to_string()))
                .await
                .into_response();
        assert_eq!(missing_generated.status(), StatusCode::NOT_FOUND);
    }

    #[test]
    fn ranked_action_offers_and_inspector_explain_room_state() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;
        let mut record = JournalRecord::new(create, 7840);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Inspector Tester".to_string(),
                speech_mode: "prose".to_string(),
                title: "Room Auditor".to_string(),
                description: "A test avatar checking offer and inspector metadata.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);

        for (destination, seed) in [(2, 7841), (MOONLIT_TRAIL_LOCATION_ID, 7842)] {
            let mut move_action = CwAction::default();
            move_action.kind = CW_ACTION_MOVE;
            move_action.actor_id = 5000;
            move_action.destination_location_id = destination;
            assert_eq!(
                runtime
                    .apply_journal_record(&JournalRecord::new(move_action, seed))
                    .0,
                CW_OK
            );
        }

        discover_seed_exit_pair_for_test(&mut runtime, MOONLIT_TRAIL_LOCATION_ID, 2);
        let state = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(state.primary_action.kind, "pick_up");
        assert_eq!(state.primary_action.label, "Take");
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "check" && option.command == "listen"));
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "prepare" && option.command == "prepare"));
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "help" && option.command == "assist"));
        let listen_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "check")
            .expect("listen offer is exposed");
        assert_eq!(listen_offer.category, "discovery");
        assert_eq!(listen_offer.zone, ZONE_FRONTIER);
        assert!(listen_offer
            .effect
            .as_deref()
            .is_some_and(|effect| effect.contains("one useful clue")
                && effect.contains("shared work")
                && !effect.contains(MOONLIT_PROGRESS_CLOCK_ID)));
        assert_eq!(listen_offer.progress, Some(1));
        assert!(listen_offer
            .risk
            .as_deref()
            .is_some_and(|risk| risk.contains("out here may tire you")));
        assert!(state
            .action_offers
            .windows(2)
            .all(|pair| pair[0].rank <= pair[1].rank));
        let help_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "help")
            .expect("help offer is exposed");
        assert_eq!(help_offer.category, "social");
        assert_eq!(help_offer.command, "assist");
        assert!(help_offer.risk.is_none());
        assert!(help_offer
            .effect
            .as_deref()
            .is_some_and(|effect| effect.contains("first help brings you closer")));
        assert_eq!(help_offer.progress, Some(1));
        let work_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "work")
            .expect("work offer is exposed");
        assert_eq!(work_offer.category, "project");
        assert_eq!(work_offer.effect.as_deref(), Some("makes good headway"));
        assert_eq!(work_offer.progress, Some(2));
        assert!(work_offer
            .risk
            .as_deref()
            .is_some_and(|risk| risk.contains("rushing in may tire you")));
        let chat_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "chat")
            .expect("chat offer is exposed");
        assert_eq!(chat_offer.category, "social");
        assert_eq!(
            chat_offer.cost.as_ref().map(|cost| cost.orbs),
            Some(CHAT_ORB_COST)
        );
        assert!(chat_offer
            .effect
            .as_deref()
            .is_some_and(|effect| effect.contains("opens a small exchange")));
        assert!(chat_offer.claim_key.is_none());
        let move_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "move")
            .expect("move offer is exposed");
        assert_eq!(move_offer.category, "travel");
        assert!(
            move_offer.rank < chat_offer.rank,
            "chat should not outrank concrete room travel without a bond payoff"
        );
        let spent_chat_state = runtime.state_response(Some(5000), &AccessContext::default());
        let spent_chat_offer = spent_chat_state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "chat")
            .expect("chat remains available after first-chat payoffs are spent");
        let spent_move_offer = spent_chat_state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "move")
            .expect("move remains available after first-chat payoffs are spent");
        assert!(
            spent_move_offer.rank < spent_chat_offer.rank,
            "chat should stay behind travel without a bond payoff"
        );
        assert!(spent_chat_offer.effect.is_some());
        assert!(spent_chat_offer.claim_key.is_none());

        let inspector = state.inspector;
        assert_eq!(inspector.location_id, MOONLIT_TRAIL_LOCATION_ID);
        let suggested = inspector
            .suggested_action
            .as_ref()
            .expect("inspector exposes a suggested action");
        assert_eq!(suggested.kind, "pick_up");
        assert_eq!(suggested.category, "inventory");
        assert_eq!(suggested.zone, ZONE_FRONTIER);
        assert_eq!(suggested.source, "kernel_flags+rpg_projection");
        assert_eq!(suggested.rank, action_offer_rank("pick_up"));
        assert!(!suggested.disabled);
        assert!(state.action_offers.iter().any(|offer| {
            offer.kind == "prepare"
                && offer.progress == Some(2)
                && offer.effect.as_deref() == Some("makes the next try count")
        }));
        assert!(inspector
            .fronts
            .iter()
            .any(|front| front.id == "moonlit-trail:echo-front"
                && front
                    .stakes_questions
                    .iter()
                    .any(|question| question.contains("quiet again"))));
        assert!(inspector
            .room
            .listen_reason
            .as_deref()
            .is_some_and(|reason| reason.contains("one useful clue")
                && reason.contains("shared work")
                && !reason.contains(MOONLIT_PROGRESS_CLOCK_ID)));
        assert!(
            inspector
                .jobs
                .iter()
                .any(|job| job.id == MOONLIT_JOB_ID
                    && job.needs.iter().any(|need| need.contains("4")))
        );
        assert!(inspector.clocks.iter().any(|clock| {
            clock.id == MOONLIT_PROGRESS_CLOCK_ID
                && clock
                    .on_fill_effect
                    .as_deref()
                    .is_some_and(|effect| effect.contains("quieted moonlight"))
        }));
        assert!(inspector.lifecycle_hooks.iter().any(|hook| {
            hook.hook == "on_listen"
                && hook.target_kind == "room"
                && hook
                    .effect
                    .as_deref()
                    .is_some_and(|effect| effect.contains(MOONLIT_PROGRESS_CLOCK_ID))
        }));
    }

    #[test]
    fn ruby_high_first_bell_live_catalog_projects_card_metadata() {
        assert_eq!(ruby_high_first_bell_catalog().len(), 24);

        let ids: BTreeSet<&str> = ruby_high_first_bell_catalog()
            .iter()
            .map(|spec| spec.card_id.as_str())
            .collect();
        for card_id in [
            "lyra",
            "sami",
            "ravi",
            "indra",
            "mika",
            "noor",
            "ruby",
            "sally-science",
            "professor-edward",
            "eliza",
            "rati",
            "captain-null",
            "item-hall-pass",
            "item-flashcards",
            "item-library-card",
            "item-lab-flask",
            "item-lunch-tray",
            "item-notebook",
            "location-homeroom",
            "location-science-lab",
            "location-library",
            "location-cafeteria",
            "location-greenhouse",
            "location-courtyard",
        ] {
            assert!(ids.contains(card_id), "missing First Bell card {card_id}");
            let card = ruby_high_card_by_id(card_id).expect("card projects");
            assert_eq!(card.card_id, card_id);
            assert_eq!(card.source, "ruby_high_first_bell");
            assert_eq!(card.asset_status, "on_chain");
            assert!(card
                .set_number
                .as_deref()
                .is_some_and(|value| value.starts_with("FB-")));
            let expected_image_url = format!("/assets/cards/{card_id}.png");
            assert_eq!(card.image_url.as_deref(), Some(expected_image_url.as_str()));
            assert!(card
                .chain_image_uri
                .as_deref()
                .is_some_and(|value| value.starts_with("https://gateway.irys.xyz/")));
        }

        assert_eq!(
            ruby_high_card_by_id("item-lab-flask").unwrap().aspect,
            "square"
        );
        assert_eq!(
            ruby_high_card_by_id("location-library").unwrap().aspect,
            "wide"
        );
        assert_eq!(ruby_high_card_by_id("rati").unwrap().aspect, "tall");
    }

